    @app.route("/upload", methods=["POST"])
    def upload_image():
        # from flask import request, jsonify, url_for
        # from werkzeug.utils import secure_filename

        ALLOWED_EXTENSIONS = {"png", "jpg", "jpeg", "gif", "bmp", "webp"}

        # 简单的大小检查（使用 Content-Length）
        content_length = request.content_length
        if content_length is not None and content_length > app.config.get("MAX_CONTENT_LENGTH", MAX_UPLOAD_SIZE_BYTES):
            return jsonify(success=False, message=f"文件大小超过最大限制 {MAX_UPLOAD_SIZE_BYTES // (1024*1024)}MB"), 413

        # 支持两种常见字段名：'file' 和 editormd 的 'editormd-image-file'
        file = request.files.get("file") or request.files.get(
            "editormd-image-file")
        if not file or not getattr(file, 'filename', None):
            return jsonify(success=False, message="没有检测到上传文件"), 400

        filename = werkzeug.utils.secure_filename(file.filename)
        if "." not in filename:
            return jsonify(success=False, message="文件名不合法"), 400

        ext = filename.rsplit('.', 1)[1].lower()
        if ext.lower() not in [e.lower() for e in ALLOWED_EXTENSIONS]:
            return jsonify(success=False, message="不支持的文件类型"), 400

        timestamp = datetime.datetime.utcnow().strftime("%Y%m%d%H%M%S%f")
        save_name = f"{timestamp}_{filename}"
        save_path = os.path.join(UPLOADS_DIR, save_name)
        try:
            file.save(save_path)
        except Exception as e:
            logging.error(f"上传保存失败: {e}")
            return jsonify(success=False, message="文件保存失败"), 500

        # 二次检查实际保存的文件大小，超出则删除并返回错误
        try:
            actual_size = os.path.getsize(save_path)
            if actual_size > app.config.get("MAX_CONTENT_LENGTH", MAX_UPLOAD_SIZE_BYTES):
                try:
                    os.remove(save_path)
                except Exception:
                    pass
                return jsonify(success=False, message=f"文件大小超过最大限制 {MAX_UPLOAD_SIZE_BYTES // (1024*1024)}MB"), 413
        except Exception as e:
            logging.warning(f"无法获取文件大小: {e}")

        # 默认返回的文件URL（如果审核通过或未启用审核）
        file_url = url_for(
            'download_file', filename=save_name, _external=False)

        # === 内容审核（图片） ===
        try:
            config = _read_config_ini("config.ini")
            enable_review = False
            if config and config.has_section("Content_Review"):
                enable_review = config.get(
                    "Content_Review", "enable_message_review", fallback="false").lower() == "true"
        except Exception:
            enable_review = False

        if enable_review:
            try:
                # 读取百度云凭证并获取access_token
                baidu_api_key = config.get(
                    "baidu_cloud", "api_key", fallback="").strip()
                baidu_secret = config.get(
                    "baidu_cloud", "secret_key", fallback="").strip()
                token_res = get_baidu_access_token(baidu_api_key, baidu_secret)
                access_token = token_res.get(
                    "access_token") if token_res else None

                # 如果无法获取token，视为审核失败，移动到 refuse
                if not access_token:
                    raise Exception(token_res.get("error")
                                    if token_res else "获取access_token失败")

                # 读取文件并进行base64编码
                # import base64 as _base64, requests as _requests

                with open(save_path, "rb") as _f:
                    img_b64 = base64.b64encode(_f.read()).decode("utf-8")

                censor_url = f"https://aip.baidubce.com/rest/2.0/solution/v1/img_censor/v2/user_defined?access_token={access_token}"
                headers = {"content-type": "application/x-www-form-urlencoded"}
                data = {"image": img_b64}
                resp = requests.post(censor_url, data=data,
                                     headers=headers, timeout=10)
                resp.raise_for_status()
                result = resp.json()

                # API错误或返回中带 error_code，视为审核失败
                if isinstance(result, dict) and "error_code" in result:
                    raise Exception(result.get("error_msg", "百度云API返回错误"))

                conclusion_type = int(result.get("conclusionType", 4)) if isinstance(
                    result, dict) else 4

                # 只有 conclusionType == 1 视为通过，其他均视为不通过或疑似 -> 移动到 refuse
                if conclusion_type != 1:
                    # 将文件移动到 refuse 目录
                    try:
                        # import shutil as _shutil
                        dest = os.path.join(REFUSE_DIR, save_name)
                        # 如果目标已存在则先移除
                        if os.path.exists(dest):
                            try:
                                os.remove(dest)
                            except Exception:
                                pass
                        shutil.move(save_path, dest)
                    except Exception as mv_err:
                        logging.error(f"移动到 refuse 目录失败: {mv_err}")

                    # 尝试从返回结果中提取详细原因并返回给客户端
                    details = None
                    try:
                        if isinstance(result, dict):
                            details = result.get("data") or result
                    except Exception:
                        details = result

                    # 聚合 data 中的消息以生成更友好的提示
                    msgs = []
                    if isinstance(details, list):
                        for item in details:
                            if isinstance(item, dict):
                                m = item.get("msg") or item.get(
                                    "message") or item.get("conclusion")
                                if m:
                                    msgs.append(str(m))
                            else:
                                msgs.append(str(item))
                    else:
                        if isinstance(details, dict):
                            m = details.get("msg") or details.get(
                                "message") or details.get("conclusion")
                            if m:
                                msgs.append(str(m))
                        else:
                            msgs.append(str(details))

                    human_msg = "图片审核未通过，已拒绝显示"
                    if msgs:
                        # 限长，避免返回过长信息
                        joined = "; ".join(msgs)
                        if len(joined) > 800:
                            joined = joined[:800] + "..."
                        human_msg = f"图片审核未通过，已拒绝显示: {joined}"

                    return jsonify(success=False, message=human_msg, details=details or result), 403

            except Exception as e:
                # 审核过程出现异常也将图片视为被拒绝并移动（以保证安全）
                try:
                    # import shutil as _shutil
                    dest = os.path.join(REFUSE_DIR, save_name)
                    if os.path.exists(dest):
                        try:
                            os.remove(dest)
                        except Exception:
                            pass
                    shutil.move(save_path, dest)
                except Exception:
                    logging.exception("审核失败且移动到 refuse 时发生错误")

                return jsonify(success=False, message=f"图片审核失败: {str(e)}"), 500

        return jsonify(success=True, url=file_url, filename=save_name)

    @app.route("/download/<path:filename>", methods=["GET"])
    def download_file(filename: str):
        # from flask import send_from_directory, abort, request

        # 基本安全检查，拒绝路径穿越
        if ".." in filename or filename.startswith('/'):
            logging.warning(f"检测到非法文件路径请求: {filename}")
            abort(404)

        # 禁止访问 refuse 目录中的文件
        # 如果请求的第一级路径是 refuse，则拒绝访问
        first_segment = filename.replace('\\', '/').split('/')[0]
        if first_segment == 'refuse':
            logging.warning(f"尝试访问被拒绝的文件: {filename}")
            abort(404)

        file_path = os.path.join(UPLOADS_DIR, filename)
        if not os.path.exists(file_path):
            # 尝试返回 uploads/picture_refuse.png，如果不存在则返回内置1x1 PNG占位图
            try:
                # 优先查找项目内 uploads/picture_refuse.png
                refuse_static = 'picture_refuse.png'
                if os.path.exists(refuse_static):
                    logging.info(f"返回内置拒绝图片: {refuse_static}")
                    return send_from_directory('', 'picture_refuse.png')
                # 回退：返回内置透明1x1 PNG
                # from io import BytesIO
                # import base64 as _base64
                png_b64 = (
                    'iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR4nGNgYAAAAAMAASsJTYQAAAAASUVORK5CYII='
                )
                img_bytes = base64.b64decode(png_b64)
                logging.info("返回内置透明1x1 PNG占位图")
                return send_file(io.BytesIO(img_bytes), mimetype='image/png')
            except Exception:
                abort(404)

        return send_from_directory(UPLOADS_DIR, filename)

