    def _process_overdue_payment_async(overdue_accounts: list, auth_username: str, out_trade_no: str):
        logging.info(f"[overdue_count处理] 欠费账号列表: {overdue_accounts}")
        # 提取总欠费次数（订单创建时已计算好）
        total_count = 0
        for account in overdue_accounts:
            account_overdue_count = account.get("overdue_count", 0)
            total_count += account_overdue_count

        # 验证必要字段是否存在
        if overdue_accounts and total_count > 0:
            try:

                # 遍历所有欠费账号

                for account in overdue_accounts:
                    # 提取学校账号用户名
                    school_username = account.get(
                        "school_username", "")

                    # 验证学校账号用户名是否有效
                    if not school_username:
                        # 如果用户名为空，跳过该账号
                        continue

                    # 构造学校账号INI文件路径
                    # INI文件存储在SCHOOL_ACCOUNTS_DIR目录下，以{school_username}.ini命名
                    account_ini_path = os.path.join(
                        SCHOOL_ACCOUNTS_DIR, f"{school_username}.ini")

                    # 检查INI文件是否存在
                    if os.path.exists(account_ini_path):
                        try:
                            # 读取INI文件
                            # ConfigParser是Python标准库，用于读写INI格式的配置文件
                            account_config = configparser.ConfigParser(
                                strict=False)
                            account_config.read(
                                account_ini_path, encoding="utf-8")

                            # 读取当前的overdue_count值
                            # 从[stats]节中读取overdue_count字段
                            # 如果字段不存在，默认值为0
                            current_overdue_count = 0
                            if account_config.has_option("stats", "overdue_count"):
                                current_overdue_count = int(
                                    account_config.get("stats", "overdue_count", fallback="0"))

                            # 从订单的overdue_accounts中获取该账号的overdue_count
                            # 这个值表示该账号在此订单中的欠费次数
                            # 支付成功后，需要减去这个值，而不是固定减1
                            account_overdue_count = account.get(
                                "overdue_count", 0)

                            # 计算新的overdue_count值
                            # 使用max(0, ...)确保结果不会小于0
                            # 减去的值是订单中该账号对应的overdue_count，而不是固定减1
                            new_overdue_count = max(
                                0, current_overdue_count - account_overdue_count)

                            # 确保[stats]节存在
                            # 如果INI文件中没有[stats]节，则创建它
                            if not account_config.has_section("stats"):
                                account_config.add_section("stats")

                            # 设置新的overdue_count值
                            # 将计算好的新值写入配置对象
                            account_config.set(
                                "stats", "overdue_count", str(new_overdue_count))

                            # 将配置写回文件
                            # 这一步将内存中的配置对象持久化到磁盘
                            with open(account_ini_path, "w", encoding="utf-8") as f:
                                account_config.write(f)

                            # 记录日志：更新成功
                            # 日志中包含账号名、原值、减少值和新值，便于追踪和调试
                            logging.info(
                                f"[订单overdue处理] 账号 {school_username} 的overdue_count: "
                                f"{current_overdue_count} - {account_overdue_count} = {new_overdue_count}"
                            )

                        except Exception as e:
                            # 捕获处理单个账号时的异常
                            # 即使某个账号处理失败，也不影响其他账号的处理
                            logging.error(
                                f"[订单overdue处理] 处理账号 {school_username} 失败: {str(e)}"
                            )
                    else:
                        # INI文件不存在
                        # 这可能是因为账号已被删除，或者数据迁移时文件丢失
                        logging.warning(
                            f"[订单overdue处理] 账号文件不存在: {account_ini_path}"
                        )

                # ========== 步骤3：记录欠费支付成功日志 ==========

                # 记录总结日志
                logging.info(
                    f"[欠费支付-异步] 欠费补缴处理完成 - 学校账号: {overdue_accounts}, "
                    f"总欠费次数: {total_count}, 用户: {auth_username}, 订单: {out_trade_no}"
                )

            except Exception as e:
                # 捕获欠费处理过程中的异常
                # 即使处理失败，也不影响异步线程的执行
                # 但需要记录详细的错误日志，便于人工介入处理
                logging.error(
                    f"[欠费支付-异步] 处理欠费补缴异常 - 用户: {auth_username}, "
                    f"订单: {out_trade_no}, 错误: {str(e)}"
                )
                logging.error(traceback.format_exc())

                # 记录错误日志到支付操作日志
                _write_payment_log(
                    user_id=auth_username,
                    order_id=out_trade_no,
                    action="overdue_payment_error",
                    log_data={
                        "error": str(e),
                        "traceback": traceback.format_exc(),
                        "overdue_accounts": overdue_accounts
                    }
                )
        else:
            # 订单数据不完整（异常情况）
            logging.warning(
                f"[overdue_count处理] 订单数据不完整，无法处理欠费 - 订单: {out_trade_no}, "
                f"auth_username: {auth_username}, total_count: {total_count}"
            )

        logging.info(f"[overdue_count处理] 订单处理完成 - 订单号: {out_trade_no}")

    def parse_google_fonts_css(css_content):
        """
        解析Google Fonts CSS内容，提取所有字体文件URL

        参数:
            css_content: CSS文件内容

        返回:
            字体URL列表 [(url, font_name), ...]
        """
        # import re

        # 匹配 url(https://...) 格式的链接
        pattern = r"url\((https://fonts\.gstatic\.com/[^)]+)\)"
        urls = re.findall(pattern, css_content)

        # 为每个URL生成唯一的标识符（基于文件名）
        font_urls = []
        for url in urls:
            # 从URL提取文件名作为标识符
            # 例如: https://fonts.gstatic.com/s/notosanssc/v39/xxx.ttf -> notosanssc-xxx.ttf
            parts = url.split("/")
            if len(parts) >= 2:
                font_family = parts[-3] if len(parts) >= 3 else "font"
                font_file = parts[-1]
                font_key = f"{font_family}-{font_file}"
            else:
                font_key = url.split("/")[-1]
            font_urls.append((url, font_key))

        return font_urls

    def cache_google_fonts_with_ttf(css_content, key):
        """
        缓存Google Fonts CSS及其引用的所有TTF字体文件

        参数:
            css_content: CSS文件内容
            key: 缓存键名

        返回:
            处理后的CSS内容（URL已替换为本地API地址）
        """
        # import re

        # 解析CSS中的字体URL
        font_urls = parse_google_fonts_css(css_content)
        logging.info(f"[CDN缓存] 发现 {len(font_urls)} 个字体文件需要缓存")

        modified_css = css_content

        for original_url, font_key in font_urls:
            # 下载字体文件（二进制模式）
            logging.info(f"[CDN缓存] 正在下载字体: {font_key}")
            font_content = fetch_cdn_file(
                original_url, timeout=60, binary=True)

            if font_content:
                # 缓存字体文件（二进制）
                with font_cache_lock:
                    font_cache_storage[font_key] = font_content

                # 保存到本地文件
                font_filename = font_key
                save_cached_file(font_filename, font_content, binary=True)

                # 替换CSS中的URL为本地API地址
                local_url = f"/api/cdn/font/{font_key}"
                modified_css = modified_css.replace(original_url, local_url)
                logging.info(f"[CDN缓存] 字体已缓存: {font_key}")
            else:
                logging.warning(f"[CDN缓存] 字体下载失败: {font_key}")

        return modified_css

    def load_cached_fonts():
        """
        从本地缓存加载所有字体文件
        """
        try:
            fonts_dir = JS_CACHE_DIR
            if not os.path.exists(fonts_dir):
                return

            for filename in os.listdir(fonts_dir):
                if (
                    filename.endswith(".ttf")
                    or filename.endswith(".woff")
                    or filename.endswith(".woff2")
                ):
                    filepath = os.path.join(fonts_dir, filename)
                    try:
                        with open(filepath, "rb") as f:
                            content = f.read()
                        with font_cache_lock:
                            font_cache_storage[filename] = content
                        logging.info(f"[CDN缓存] 从本地加载字体: {filename}")
                    except Exception as e:
                        logging.warning(f"[CDN缓存] 加载字体文件失败 {filename}: {e}")
        except Exception as e:
            logging.warning(f"[CDN缓存] 扫描字体缓存目录失败: {e}")

    def get_latest_socketio_version():
        """
        获取socket.io的最新稳定版本号
        """
        try:
            # 从npm registry获取最新版本
            response = requests.get(
                "https://registry.npmjs.org/socket.io-client/latest", timeout=10
            )
            if response.status_code == 200:
                data = response.json()
                version = data.get("version", "4.8.1")
                logging.info(f"[CDN缓存] Socket.IO 最新版本: {version}")
                return version
        except Exception as e:
            logging.warning(f"[CDN缓存] 获取Socket.IO最新版本失败: {e}")
        return "4.8.1"  # 默认版本

    def fetch_cdn_file(url, timeout=30, binary=False):
        """
        从CDN获取文件内容

        参数:
            url: 文件URL
            timeout: 超时时间（秒）
            binary: 是否以二进制模式获取（用于字体文件等）
        """
        try:
            headers = {
                "User-Agent": "Mozilla/5.0 (Windows NT 10.0; Win64; x64) AppleWebKit/537.36"
            }
            response = requests.get(url, headers=headers, timeout=timeout)
            if response.status_code == 200:
                return response.content if binary else response.text
            else:
                logging.warning(
                    f"[CDN缓存] 获取文件失败，状态码: {response.status_code}, URL: {url}"
                )
                return None
        except Exception as e:
            logging.error(f"[CDN缓存] 获取文件异常: {e}, URL: {url}")
            return None

    def load_cached_file(filename, binary=False):
        """
        从本地缓存文件加载内容

        参数:
            filename: 文件名
            binary: 是否以二进制模式读取
        """
        cache_path = os.path.join(JS_CACHE_DIR, filename)
        if os.path.exists(cache_path):
            try:
                mode = "rb" if binary else "r"
                encoding = None if binary else "utf-8"
                with open(cache_path, mode, encoding=encoding) as f:
                    return f.read()
            except Exception as e:
                logging.error(f"[CDN缓存] 读取缓存文件失败: {e}, 文件: {filename}")
        return None

    def save_cached_file(filename, content, binary=False):
        """
        保存内容到本地缓存文件

        参数:
            filename: 文件名
            content: 文件内容
            binary: 是否以二进制模式写入
        """
        cache_path = os.path.join(JS_CACHE_DIR, filename)
        try:
            mode = "wb" if binary else "w"
            encoding = None if binary else "utf-8"
            with open(cache_path, mode, encoding=encoding) as f:
                f.write(content)
            logging.info(f"[CDN缓存] 已保存缓存文件: {filename}")
            return True
        except Exception as e:
            logging.error(f"[CDN缓存] 保存缓存文件失败: {e}, 文件: {filename}")
            return False

    def update_single_cdn_file(key, config):
        """
        更新单个CDN文件的缓存
        """
        url = config["url"]
        filename = config["filename"]

        # 如果是socket.io且标记需要检查最新版本，则动态获取最新版本URL
        if config.get("check_latest") and key == "socketio":
            latest_version = get_latest_socketio_version()
            url = f"https://cdn.socket.io/{latest_version}/socket.io.min.js"
            logging.info(f"[CDN缓存] Socket.IO 使用最新版本: {latest_version}")

        logging.info(f"[CDN缓存] 正在获取: {key} ({url})")
        content = fetch_cdn_file(url)

        if content:
            # 如果是 Google Fonts，需要特殊处理：解析并缓存TTF字体文件
            if key == "google-fonts":
                logging.info(f"[CDN缓存] 正在解析Google Fonts CSS并缓存字体文件...")
                content = cache_google_fonts_with_ttf(content, key)

            with js_cache_lock:
                js_cache_storage[key] = content
                js_cache_last_update[key] = time.time()
            save_cached_file(filename, content)
            logging.info(f"[CDN缓存] 成功更新: {key}")
            return True
        else:
            # 获取失败，尝试使用本地缓存
            cached = load_cached_file(filename)
            if cached:
                with js_cache_lock:
                    if key not in js_cache_storage:
                        js_cache_storage[key] = cached
                logging.warning(f"[CDN缓存] 获取失败，使用本地缓存: {key}")
                return False
            else:
                logging.error(f"[CDN缓存] 获取失败且无本地缓存: {key}")
                return False

    def update_all_cdn_files():
        """
        更新所有CDN文件的缓存
        """
        logging.info("[CDN缓存] 开始更新所有CDN文件...")
        success_count = 0
        fail_count = 0

        for key, config in CDN_FILES.items():
            if update_single_cdn_file(key, config):
                success_count += 1
            else:
                fail_count += 1

        logging.info(f"[CDN缓存] 更新完成: 成功 {success_count}, 失败 {fail_count}")
        return success_count, fail_count

    def init_cdn_cache():
        """
        初始化CDN缓存：先尝试加载本地缓存，如果没有则从CDN获取
        """
        logging.info("[CDN缓存] 正在初始化CDN文件缓存...")

        # 先加载缓存的字体文件
        load_cached_fonts()

        for key, config in CDN_FILES.items():
            filename = config["filename"]
            # 先尝试加载本地缓存
            cached = load_cached_file(filename)
            if cached:
                with js_cache_lock:
                    js_cache_storage[key] = cached
                    js_cache_last_update[key] = os.path.getmtime(
                        os.path.join(JS_CACHE_DIR, filename)
                    )
                logging.info(f"[CDN缓存] 从本地加载: {key}")
            else:
                # 本地没有缓存，从CDN获取
                update_single_cdn_file(key, config)

        logging.info(
            f"[CDN缓存] 初始化完成，已缓存 {len(js_cache_storage)} 个JS/CSS文件, {len(font_cache_storage)} 个字体文件"
        )

    def cdn_cache_update_worker():
        """
        CDN缓存定时更新工作线程（每小时检查一次）
        """
        current_thread = threading.current_thread()
        logging.info(f"[CDN Worker] 已在线程中启动: Thread[{current_thread.name}, id={current_thread.ident}]")
        logging.warning("[Eventlet 警告] CDN worker 运行在独立线程中 - 避免使用 eventlet 操作")
        UPDATE_INTERVAL = 3600  # 1小时

        while True:
            try:
                time.sleep(UPDATE_INTERVAL)
                logging.info("[CDN缓存] 定时更新任务开始...")
                update_all_cdn_files()
            except Exception as e:
                logging.error(f"[CDN缓存] 定时更新任务异常: {e}")

    # 初始化CDN缓存
    init_cdn_cache()

    # 启动CDN缓存定时更新线程
    cdn_update_thread = threading.Thread(
        target=cdn_cache_update_worker, daemon=True, name="CDN_Update_Worker")
    current_thread = threading.current_thread()
    logging.info(f"[线程创建] 正在从 Thread[{current_thread.name}, id={current_thread.ident}] 创建 CDN 更新线程")
    logging.warning("[Eventlet 警告] CDN 更新线程在 eventlet.monkey_patch 之后创建 - 可能导致 greenlet 冲突")
    cdn_update_thread.start()
    logging.info(f"[CDN缓存] 定时更新线程已启动: {cdn_update_thread.name} (id={cdn_update_thread.ident})（每小时检查一次）")

    # ===== 登录验证装饰器 =====
    def login_required(f):
        """
        一个装饰器，用于验证用户是否已登录。
        它检查 X-Session-ID，验证会话，并将用户信息存储在 g 对象中。
        """

        @functools.wraps(f)
        def decorated_function(*args, **kwargs):
            session_id = request.headers.get("X-Session-ID", "")
            api_instance = None
            is_authenticated = False
            auth_username = None
            if session_id:
                with web_sessions_lock:
                    if session_id in web_sessions:
                        api_instance = web_sessions[session_id]
                        is_authenticated = getattr(
                            api_instance, "is_authenticated", False
                        )
                        auth_username = getattr(
                            api_instance, "auth_username", None)
            if not is_authenticated or not api_instance or not auth_username:
                return jsonify({"success": False, "message": "未登录或会话无效"}), 401
            if getattr(api_instance, "is_guest", False):
                return jsonify({"success": False, "message": "游客无权访问此功能"}), 403
            g.user = auth_username
            g.api_instance = api_instance
            # 将 session_id 存储到 g 对象中，以便被装饰的函数可以访问它（用于审计日志等）
            g.session_id = session_id
            return f(*args, **kwargs)

        return decorated_function

    # ==================== [修正] 添加缺失的 admin_required 装饰器，并采用权限组判断 ====================
    def admin_required(f):
        """
        管理员权限验证装饰器 (基于权限组)
        要求用户已登录，且权限组为 'admin' 或 'super_admin'
        """

        @functools.wraps(f)
        def decorated_function(*args, **kwargs):
            session_id = request.headers.get("X-Session-ID", "")
            api_instance = None
            is_authenticated = False
            auth_username = None
            auth_group = "guest"  # 默认访客组

            # 1. 验证会话和登录状态
            if session_id:
                with web_sessions_lock:
                    if session_id in web_sessions:
                        api_instance = web_sessions[session_id]
                        is_authenticated = getattr(
                            api_instance, "is_authenticated", False
                        )
                        auth_username = getattr(
                            api_instance, "auth_username", None)
                        # 获取权限组（用于后续的组判断）
                        auth_group = getattr(
                            api_instance, "auth_group", "guest")

            if not is_authenticated or not api_instance or not auth_username:
                logging.warning(
                    f"Admin Required Failed: No valid session or not authenticated. Session ID: {session_id[:8]}..."
                )
                return jsonify({"success": False, "message": "未登录或会话无效"}), 401

            # 2. 验证管理员权限 (检查权限组)
            ADMIN_GROUPS = ["admin", "super_admin"]
            if auth_group not in ADMIN_GROUPS:
                logging.warning(
                    f"Admin Required Failed: User {auth_username} (Group: {auth_group}) attempted to access admin route."
                )
                return jsonify({"success": False, "message": "权限不足，仅管理员可访问"}), 403

            # 3. 设置上下文变量
            g.user = auth_username
            g.api_instance = api_instance
            # 将 session_id 存储到 g 对象中，以便被装饰的函数可以访问它（用于审计日志等）
            g.session_id = session_id
            return f(*args, **kwargs)

        return decorated_function
