    @app.route("/auth/get_user_school_accounts", methods=["GET"])
    @login_required  # 只需要登录即可，权限过滤在数据层通过get_initial_data实现
    def auth_get_user_school_accounts():
        """
        获取指定认证用户的所有 school_account（基于get_initial_data权限过滤）

        功能说明：
        - 该接口用于获取认证用户（auth user）关联的学校账号（school accounts）
        - 返回的账号列表会根据当前登录用户的权限进行过滤
        - 使用get_initial_data()的权限逻辑确保用户只能看到授权范围内的账号

        权限模型：
        - 仅需要登录即可调用此接口，权限过滤在数据层面实现
        - 普通用户：只能查看自己的学校账号（请求其他用户名时返回空结果）
        - 管理员/有auto_fill_password权限：可以查看所有学校账号

        安全机制：
        - get_initial_data权限过滤：根据用户权限自动过滤账号数据
        - 输入验证：对username参数进行安全检查
        - 会话验证：确保请求来自有效的登录会话

        请求参数：
        - username (可选): 目标认证用户名，默认为当前登录用户

        返回格式：
        {
            "success": true,
            "username": "目标用户名",
            "accounts": {
                "school_account_1": {"password": "xxx", "ua": "xxx", ...},
                "school_account_2": {"password": "yyy", "ua": "yyy", ...}
            }
        }
        
        传入 username 之后返回参数异常，只作为返回当前账号的接口，如果需要查询其他账号，请使用 /auth/get_user_school_accounts_only 
        
        """
        try:
            # ========== 步骤1：获取当前登录用户信息 ==========
            # 从Flask的g对象中获取当前登录的用户名
            # g.user 是在 @login_required 装饰器中设置的全局请求上下文变量
            auth_username = g.user

            # 记录API调用日志，用于审计和调试
            # 包含调用者信息，便于追踪安全问题
            logging.info(
                f"[API调用] auth_get_user_school_accounts - "
                f"调用者: {auth_username}"
            )

            # ========== 步骤2：获取并验证目标用户名 ==========
            # 从URL查询参数获取目标用户名，如果未指定则默认为当前登录用户
            # 这允许管理员查询其他用户的账号信息
            target_username = request.args.get("username", auth_username)

            # [安全加固] 验证target_username参数，防止注入攻击和路径遍历
            # 检查1：确保username不为空且为字符串类型
            if not target_username or not isinstance(target_username, str):
                logging.warning(
                    f"[参数验证失败] 无效的username参数: {target_username}"
                )
                return jsonify({
                    "success": False,
                    "message": "无效的用户名参数"
                }), 400

            # 检查2：验证username长度，防止过长输入导致的DoS攻击
            # 使用全局常量 MAX_USERNAME_LENGTH（定义在文件开头，值为200）
            if len(target_username) > MAX_USERNAME_LENGTH:
                logging.warning(
                    f"[参数验证失败] username参数过长: {len(target_username)} > {MAX_USERNAME_LENGTH}"
                )
                return jsonify({
                    "success": False,
                    "message": f"用户名长度不能超过{MAX_USERNAME_LENGTH}个字符"
                }), 400

            # 检查3：验证username格式，只允许字母、数字、下划线、连字符、点和@符号
            # 使用全局正则表达式 USERNAME_PATTERN（定义在文件开头）
            # 这可以防止路径遍历攻击（如 ../../../etc/passwd）和特殊字符注入
            if USERNAME_PATTERN and not USERNAME_PATTERN.match(target_username):
                logging.warning(
                    f"[参数验证失败] username包含非法字符: {target_username}"
                )
                return jsonify({
                    "success": False,
                    "message": "用户名包含非法字符，只允许字母、数字、下划线、连字符、点和@符号"
                }), 400

            # 记录目标用户信息，便于审计
            logging.debug(
                f"[参数验证通过] 目标用户: {target_username}, "
                f"请求者: {auth_username}"
            )

            # ========== 步骤3：获取API实例 ==========
            # 从请求头获取会话ID（Session ID）
            # 会话ID用于标识用户的登录会话，每个会话对应一个api_instance
            session_id = request.headers.get("X-Session-ID", "")

            # 验证会话ID是否存在于活跃会话列表中
            # web_sessions 是全局字典，存储所有活跃的用户会话
            if session_id and session_id in web_sessions:
                api_instance = web_sessions[session_id]
                logging.debug(f"[会话验证] 找到有效会话: {session_id[:8]}...")
            else:
                # 会话无效的情况：
                # 1. 会话ID为空（客户端未发送）
                # 2. 会话已过期或被清理
                # 3. 会话ID被伪造
                logging.warning(
                    f"[会话验证失败] 无效的会话ID: {session_id[:8] if session_id else 'empty'}..."
                )
                return jsonify({
                    "success": False,
                    "message": "会话无效或已过期，请重新登录"
                }), 401

            # ========== 步骤4：获取允许查看的学校账号列表（权限过滤保护）==========
            # 调用 get_initial_data() 获取当前用户权限下可见的学校账号列表
            # 该方法会根据用户权限返回不同的账号列表：
            # - 游客：返回空列表 []
            # - 普通用户：返回自己的学校账号列表（从school_accounts配置中读取）
            # - 管理员或有 auto_fill_password 权限的用户：返回所有学校账号（遍历user_dir目录）
            #
            # 这个权限过滤确保用户只能看到get_initial_data()允许的账号
            try:
                initial_data = api_instance.get_initial_data()
                allowed_users = initial_data.get("users", [])
                logging.debug(
                    f"[权限过滤] 用户 {auth_username} 可见的学校账号数量: {len(allowed_users)}"
                )
            except Exception as e:
                # 处理get_initial_data()可能抛出的异常
                # 例如：文件系统错误、配置文件损坏等
                logging.error(
                    f"[权限过滤失败] 调用get_initial_data()时发生异常: {str(e)}",
                    exc_info=True
                )
                return jsonify({
                    "success": False,
                    "message": "获取权限信息失败，请稍后重试"
                }), 500

            # ========== 步骤5：加载目标用户的学校账号信息 ==========
            # 调用 _load_user_school_accounts() 加载指定认证用户的所有学校账号
            # 参数说明：
            # - target_username: 认证系统的用户名（auth username），如 "user123"
            # 返回值说明：
            # - accounts: 字典格式，key为学校账号名称，value为账号详细信息
            #   例如：{"20210001": {"password": "123456", "ua": "Mozilla/5.0...", ...}}
            #
            # 注意：这里加载的是原始的、未经过滤的账号数据
            # 后续会根据allowed_users进行过滤
            try:
                accounts = api_instance._load_user_school_accounts(
                    target_username)

                # 如果请求者具有 manage_users 权限，则返回所有用户的学校账号
                # 管理员视图：遍历 school_accounts/user_accounts 目录并汇总所有 JSON
                # 同时兼容旧版格式：从 school_accounts 目录直接读取 ini 文件
                try:
                    if auth_system.check_permission(auth_username, "manage_users"):
                        aggregated = {}

                        # 方式1：从 school_accounts/user_accounts 目录读取 JSON 文件
                        user_accounts_dir = os.path.join(
                            SCHOOL_ACCOUNTS_DIR, "user_accounts")
                        if os.path.isdir(user_accounts_dir):
                            for fname in os.listdir(user_accounts_dir):
                                if not fname.endswith('.json'):
                                    continue
                                fpath = os.path.join(user_accounts_dir, fname)
                                try:
                                    with open(fpath, 'r', encoding='utf-8') as uf:
                                        other = json.load(uf)
                                except Exception:
                                    logging.debug(
                                        f"跳过无法读取的 user_accounts 文件: {fpath}")
                                    continue

                                for school_username, account_info in (other or {}).items():
                                    if isinstance(account_info, dict):
                                        pwd = account_info.get('password', '')
                                        ua = account_info.get(
                                            'ua') if 'ua' in account_info else None
                                    else:
                                        pwd = account_info or ''
                                        ua = None

                                    # 排除空密码
                                    if pwd is None or str(pwd).strip() == "":
                                        continue

                                    if school_username in aggregated:
                                        continue

                                    entry = {'password': pwd, 'ua': ua}
                                    stats = api_instance._load_school_account_stats_from_ini(
                                        school_username)
                                    entry['overdue_count'] = stats.get(
                                        'overdue_count', 0)
                                    entry['completed_count'] = stats.get(
                                        'completed_count', 0)

                                    aggregated[school_username] = entry

                        # 方式2：兼容旧版格式，从 school_accounts 目录直接读取 ini 文件
                        # 这支持管理员访问那些只有 ini 文件（没有对应 JSON 文件）的学校账号
                        try:
                            for fname in os.listdir(SCHOOL_ACCOUNTS_DIR):
                                # 只处理 .ini 文件，排除子目录和其他文件
                                if not fname.endswith('.ini'):
                                    continue

                                school_username = fname[:-4]  # 去除 .ini 扩展名

                                # 如果已经从 JSON 中读取过，则跳过
                                if school_username in aggregated:
                                    continue

                                # 从 ini 文件读取账号配置
                                ini_path = os.path.join(
                                    SCHOOL_ACCOUNTS_DIR, fname)
                                try:
                                    config = configparser.RawConfigParser()
                                    config.optionxform = str
                                    config.read(ini_path, encoding='utf-8')

                                    # 从 [Config] 部分读取密码
                                    password = config.get(
                                        'Config', 'Password', fallback='')

                                    # 排除空密码
                                    if password is None or str(password).strip() == "":
                                        continue

                                    # 从 [System] 部分读取 UA
                                    ua = config.get(
                                        'System', 'UA', fallback=None)

                                    # 从 [stats] 部分读取统计数据
                                    overdue_count = config.getint(
                                        'stats', 'overdue_count', fallback=0)
                                    completed_count = config.getint(
                                        'stats', 'completed_count', fallback=0)

                                    # 构建账号条目
                                    entry = {
                                        'password': password,
                                        'ua': ua,
                                        'overdue_count': overdue_count,
                                        'completed_count': completed_count
                                    }

                                    aggregated[school_username] = entry
                                    logging.debug(
                                        f"[旧版兼容] 从 ini 文件读取账号: {school_username}")

                                except Exception as e:
                                    logging.debug(
                                        f"读取 ini 文件失败 {ini_path}: {e}")
                                    continue

                        except Exception as e:
                            logging.debug(f"遍历 school_accounts 目录时出错: {e}")

                        accounts = aggregated
                        logging.debug(
                            f"[管理员视图] 管理员 {auth_username} 查看所有学校账号，共 {len(accounts)} 个"
                        )
                except Exception as e:
                    logging.debug(f"构建管理员全量账号视图时出错: {e}")

                logging.debug(
                    f"[加载账号] 为用户 {target_username} 加载了 {len(accounts)} 个学校账号"
                )
            except Exception as e:
                # 处理_load_user_school_accounts()可能抛出的异常
                # 例如：用户不存在、配置文件损坏、文件系统错误等
                logging.error(
                    f"[加载账号失败] 为用户 {target_username} 加载学校账号时发生异常: {str(e)}",
                    exc_info=True
                )
                return jsonify({
                    "success": False,
                    "message": f"加载用户 {target_username} 的账号信息失败"
                }), 500

            # ========== 步骤6：过滤账号（应用权限限制）==========
            # [性能优化] 将 allowed_users 列表转换为集合（set）
            # 原因：列表的 'in' 操作是 O(n)，集合的 'in' 操作是 O(1)
            # 当账号数量很多时（例如几百个），这个优化能显著提升性能
            allowed_users_set = set(allowed_users)

            # 过滤账号：只保留在 allowed_users_set 中的账号
            # 过滤逻辑说明：
            # - allowed_users_set: get_initial_data() 返回的学校账号名称集合
            # - accounts: 从 _load_user_school_accounts(target_username) 加载的账号字典
            # - 过滤结果：只包含同时满足以下条件的账号：
            #   1. 账号属于target_username（来自accounts）
            #   2. 账号在当前用户的可见范围内（在allowed_users_set中）
            #
            # 权限场景示例：
            # 场景1：普通用户查看自己的账号
            #   - target_username = "user123"（当前用户）
            #   - allowed_users_set = {"20210001", "20210002"}（user123的学校账号）
            #   - accounts = {"20210001": {...}, "20210002": {...}}
            #   - 结果：返回user123的所有学校账号
            #
            # 场景2：管理员查看其他用户的账号
            #   - target_username = "user456"（其他用户）
            #   - allowed_users_set = {"所有学校账号"}（管理员可见全部）
            #   - accounts = {"20210003": {...}, "20210004": {...}}（user456的账号）
            #   - 结果：返回user456的所有学校账号
            #
            # 场景3：普通用户试图查看其他用户的账号（安全防护）
            #   - target_username = "user456"（其他用户）
            #   - allowed_users_set = {"20210001", "20210002"}（只有自己的账号）
            #   - accounts = {"20210003": {...}, "20210004": {...}}（user456的账号）
            #   - 结果：返回空字典{}（没有交集，防止越权访问）
            if auth_system.check_permission(auth_username, "manage_users"):
                # 管理员查看：直接使用 accounts（已在上面汇总为所有账号）
                filtered_accounts = accounts
            else:
                filtered_accounts = {
                    account_name: account_info
                    for account_name, account_info in accounts.items()
                    if account_name in allowed_users_set
                }

            # 记录过滤结果，用于审计和调试
            logging.info(
                f"[过滤完成] 用户 {auth_username} 查询 {target_username} 的账号: "
                f"原始数量={len(accounts)}, 过滤后数量={len(filtered_accounts)}"
            )

            # [安全审计] 如果过滤后账号数量为0，记录警告日志
            # 这可能表示：
            # 1. target_username确实没有学校账号（正常）
            # 2. 普通用户试图越权访问其他用户的账号（安全事件）
            if len(filtered_accounts) == 0 and len(accounts) > 0:
                logging.warning(
                    f"[潜在越权] 用户 {auth_username} 查询 {target_username} 的账号被完全过滤: "
                    f"原始账号数={len(accounts)}, 过滤后=0"
                )

            # ========== 步骤7：返回结果 ==========
            # 返回过滤后的账号列表
            # 注意：这里返回的是字典格式，与原接口保持一致，确保向后兼容
            # 返回值说明：
            # - success: 操作是否成功（布尔值）
            # - username: 目标认证用户名（auth username），即查询的是谁的账号
            # - accounts: 过滤后的学校账号字典
            #   - key: 学校账号名称（school account name），如 "20210001"
            #   - value: 账号详细信息（字典），包含password、ua等字段
            return jsonify({
                "success": True,
                "username": target_username,
                "accounts": filtered_accounts
            })

        except Exception as e:
            # ========== 异常处理（最外层保护）==========
            # 捕获所有未预期的异常，防止敏感信息泄露
            # 记录详细的错误信息到日志（包含堆栈跟踪），但向客户端返回通用错误消息
            logging.error(
                f"[接口异常] auth_get_user_school_accounts发生未预期的异常: {str(e)}",
                exc_info=True
            )
            # 返回通用错误消息，避免向客户端暴露内部实现细节
            return jsonify({
                "success": False,
                "message": "服务器内部错误，请稍后重试"
            }), 500

    @app.route("/auth/get_user_school_accounts_only", methods=["GET"])
    @login_required  # 只需要登录即可，权限过滤在数据层通过get_initial_data实现
    def auth_get_user_school_accounts_only():
        """
        获取指定认证用户的所有 school_account（基于get_initial_data权限过滤）

        功能说明：
        - 该接口用于获取认证用户（auth user）关联的学校账号（school accounts）
        - 返回的账号列表会根据当前登录用户的权限进行过滤
        - 使用get_initial_data()的权限逻辑确保用户只能看到授权范围内的账号

        权限模型：
        - 仅需要登录即可调用此接口，权限过滤在数据层面实现
        - 普通用户：只能查看自己的学校账号（请求其他用户名时返回空结果）
        - 管理员/有auto_fill_password权限：可以查看所有学校账号

        安全机制：
        - get_initial_data权限过滤：根据用户权限自动过滤账号数据
        - 输入验证：对username参数进行安全检查
        - 会话验证：确保请求来自有效的登录会话

        请求参数：
        - username (可选): 目标认证用户名，默认为当前登录用户

        返回格式：
        {
            "success": true,
            "username": "目标用户名",
            "accounts": {
                "school_account_1": {"password": "xxx", "ua": "xxx", ...},
                "school_account_2": {"password": "yyy", "ua": "yyy", ...}
            }
        }
        """
        try:
            # ========== 步骤1：获取当前登录用户信息 ==========
            # 从Flask的g对象中获取当前登录的用户名
            # g.user 是在 @login_required 装饰器中设置的全局请求上下文变量
            auth_username = g.user

            # 记录API调用日志，用于审计和调试
            # 包含调用者信息，便于追踪安全问题
            logging.info(
                f"[API调用] auth_get_user_school_accounts_only - "
                f"调用者: {auth_username}"
            )

            # ========== 步骤2：获取并验证目标用户名 ==========
            # 从URL查询参数获取目标用户名，如果未指定则默认为当前登录用户
            # 这允许管理员查询其他用户的账号信息
            target_username = request.args.get("username", auth_username)

            # [安全加固] 验证target_username参数，防止注入攻击和路径遍历
            # 检查1：确保username不为空且为字符串类型
            if not target_username or not isinstance(target_username, str):
                logging.warning(
                    f"[参数验证失败] 无效的username参数: {target_username}"
                )
                return jsonify({
                    "success": False,
                    "message": "无效的用户名参数"
                }), 400

            # 检查2：验证username长度，防止过长输入导致的DoS攻击
            # 使用全局常量 MAX_USERNAME_LENGTH（定义在文件开头，值为200）
            if len(target_username) > MAX_USERNAME_LENGTH:
                logging.warning(
                    f"[参数验证失败] username参数过长: {len(target_username)} > {MAX_USERNAME_LENGTH}"
                )
                return jsonify({
                    "success": False,
                    "message": f"用户名长度不能超过{MAX_USERNAME_LENGTH}个字符"
                }), 400

            # 检查3：验证username格式，只允许字母、数字、下划线、连字符、点和@符号
            # 使用全局正则表达式 USERNAME_PATTERN（定义在文件开头）
            # 这可以防止路径遍历攻击（如 ../../../etc/passwd）和特殊字符注入
            if USERNAME_PATTERN and not USERNAME_PATTERN.match(target_username):
                logging.warning(
                    f"[参数验证失败] username包含非法字符: {target_username}"
                )
                return jsonify({
                    "success": False,
                    "message": "用户名包含非法字符，只允许字母、数字、下划线、连字符、点和@符号"
                }), 400

            # 记录目标用户信息，便于审计
            logging.debug(
                f"[参数验证通过] 目标用户: {target_username}, "
                f"请求者: {auth_username}"
            )

            # ========== 步骤3：获取API实例 ==========
            # 从请求头获取会话ID（Session ID）
            # 会话ID用于标识用户的登录会话，每个会话对应一个api_instance
            session_id = request.headers.get("X-Session-ID", "")

            # 验证会话ID是否存在于活跃会话列表中
            # web_sessions 是全局字典，存储所有活跃的用户会话
            if session_id and session_id in web_sessions:
                api_instance = web_sessions[session_id]
                logging.debug(f"[会话验证] 找到有效会话: {session_id[:8]}...")
            else:
                # 会话无效的情况：
                # 1. 会话ID为空（客户端未发送）
                # 2. 会话已过期或被清理
                # 3. 会话ID被伪造
                logging.warning(
                    f"[会话验证失败] 无效的会话ID: {session_id[:8] if session_id else 'empty'}..."
                )
                return jsonify({
                    "success": False,
                    "message": "会话无效或已过期，请重新登录"
                }), 401

            # ========== 步骤4：获取允许查看的学校账号列表（权限过滤保护）==========
            # 调用 get_initial_data() 获取当前用户权限下可见的学校账号列表
            # 该方法会根据用户权限返回不同的账号列表：
            # - 游客：返回空列表 []
            # - 普通用户：返回自己的学校账号列表（从school_accounts配置中读取）
            # - 管理员或有 auto_fill_password 权限的用户：返回所有学校账号（遍历user_dir目录）
            #
            # 这个权限过滤确保用户只能看到get_initial_data()允许的账号
            try:
                initial_data = api_instance.get_initial_data()
                allowed_users = initial_data.get("users", [])
                logging.debug(
                    f"[权限过滤] 用户 {auth_username} 可见的学校账号数量: {len(allowed_users)}"
                )
            except Exception as e:
                # 处理get_initial_data()可能抛出的异常
                # 例如：文件系统错误、配置文件损坏等
                logging.error(
                    f"[权限过滤失败] 调用get_initial_data()时发生异常: {str(e)}",
                    exc_info=True
                )
                return jsonify({
                    "success": False,
                    "message": "获取权限信息失败，请稍后重试"
                }), 500

            # ========== 步骤5：加载目标用户的学校账号信息 ==========
            # 调用 _load_user_school_accounts() 加载指定认证用户的所有学校账号
            # 参数说明：
            # - target_username: 认证系统的用户名（auth username），如 "user123"
            # 返回值说明：
            # - accounts: 字典格式，key为学校账号名称，value为账号详细信息
            #   例如：{"20210001": {"password": "123456", "ua": "Mozilla/5.0...", ...}}
            #
            # 注意：这里加载的是原始的、未经过滤的账号数据
            # 后续会根据allowed_users进行过滤
            try:
                accounts = api_instance._load_user_school_accounts(
                    target_username)
                logging.debug(
                    f"[加载账号] 为用户 {target_username} 加载了 {len(accounts)} 个学校账号"
                )
            except Exception as e:
                # 处理_load_user_school_accounts()可能抛出的异常
                # 例如：用户不存在、配置文件损坏、文件系统错误等
                logging.error(
                    f"[加载账号失败] 为用户 {target_username} 加载学校账号时发生异常: {str(e)}",
                    exc_info=True
                )
                return jsonify({
                    "success": False,
                    "message": f"加载用户 {target_username} 的账号信息失败"
                }), 500

            # ========== 步骤6：过滤账号（应用权限限制）==========
            # [性能优化] 将 allowed_users 列表转换为集合（set）
            # 原因：列表的 'in' 操作是 O(n)，集合的 'in' 操作是 O(1)
            # 当账号数量很多时（例如几百个），这个优化能显著提升性能
            allowed_users_set = set(allowed_users)

            # 过滤账号：只保留在 allowed_users_set 中的账号
            # 过滤逻辑说明：
            # - allowed_users_set: get_initial_data() 返回的学校账号名称集合
            # - accounts: 从 _load_user_school_accounts(target_username) 加载的账号字典
            # - 过滤结果：只包含同时满足以下条件的账号：
            #   1. 账号属于target_username（来自accounts）
            #   2. 账号在当前用户的可见范围内（在allowed_users_set中）
            #
            # 权限场景示例：
            # 场景1：普通用户查看自己的账号
            #   - target_username = "user123"（当前用户）
            #   - allowed_users_set = {"20210001", "20210002"}（user123的学校账号）
            #   - accounts = {"20210001": {...}, "20210002": {...}}
            #   - 结果：返回user123的所有学校账号
            #
            # 场景2：管理员查看其他用户的账号
            #   - target_username = "user456"（其他用户）
            #   - allowed_users_set = {"所有学校账号"}（管理员可见全部）
            #   - accounts = {"20210003": {...}, "20210004": {...}}（user456的账号）
            #   - 结果：返回user456的所有学校账号
            #
            # 场景3：普通用户试图查看其他用户的账号（安全防护）
            #   - target_username = "user456"（其他用户）
            #   - allowed_users_set = {"20210001", "20210002"}（只有自己的账号）
            #   - accounts = {"20210003": {...}, "20210004": {...}}（user456的账号）
            #   - 结果：返回空字典{}（没有交集，防止越权访问）
            if auth_system.check_permission(auth_username, "manage_users"):
                # 管理员查看：直接使用 accounts（已在上面汇总为所有账号）
                filtered_accounts = accounts
            else:
                filtered_accounts = {
                    account_name: account_info
                    for account_name, account_info in accounts.items()
                    if account_name in allowed_users_set
                }

            # 记录过滤结果，用于审计和调试
            logging.info(
                f"[过滤完成] 用户 {auth_username} 查询 {target_username} 的账号: "
                f"原始数量={len(accounts)}, 过滤后数量={len(filtered_accounts)}"
            )

            # [安全审计] 如果过滤后账号数量为0，记录警告日志
            # 这可能表示：
            # 1. target_username确实没有学校账号（正常）
            # 2. 普通用户试图越权访问其他用户的账号（安全事件）
            if len(filtered_accounts) == 0 and len(accounts) > 0:
                logging.warning(
                    f"[潜在越权] 用户 {auth_username} 查询 {target_username} 的账号被完全过滤: "
                    f"原始账号数={len(accounts)}, 过滤后=0"
                )

            # ========== 步骤7：返回结果 ==========
            # 返回过滤后的账号列表
            # 注意：这里返回的是字典格式，与原接口保持一致，确保向后兼容
            # 返回值说明：
            # - success: 操作是否成功（布尔值）
            # - username: 目标认证用户名（auth username），即查询的是谁的账号
            # - accounts: 过滤后的学校账号字典
            #   - key: 学校账号名称（school account name），如 "20210001"
            #   - value: 账号详细信息（字典），包含password、ua等字段
            return jsonify({
                "success": True,
                "username": target_username,
                "accounts": filtered_accounts
            })

        except Exception as e:
            # ========== 异常处理（最外层保护）==========
            # 捕获所有未预期的异常，防止敏感信息泄露
            # 记录详细的错误信息到日志（包含堆栈跟踪），但向客户端返回通用错误消息
            logging.error(
                f"[接口异常] auth_get_user_school_accounts发生未预期的异常: {str(e)}",
                exc_info=True
            )
            # 返回通用错误消息，避免向客户端暴露内部实现细节
            return jsonify({
                "success": False,
                "message": "服务器内部错误，请稍后重试"
            }), 500

    @app.route("/auth/admin/get_all_users_school_accounts", methods=["GET"])
    @login_required  # 只需要登录即可，细粒度权限在函数内部检查
    def auth_admin_get_all_users_school_accounts():
        """获取所有认证用户的 school_account 列表（管理员或有 auto_fill_password 权限）"""
        # 从Flask的g对象中获取当前登录的用户名
        auth_username = g.user

        # 细粒度权限检查：需要 'manage_users' 权限
        # manage_users 权限允许查看所有用户的学校账号信息
        # 这是高度敏感的批量数据访问操作
        if not auth_system.check_permission(auth_username, "manage_users"):
            return jsonify({
                "success": False,
                "message": "权限不足，需要用户管理权限（manage_users）"
            }), 403

        # 定义用户账号目录路径
        user_accounts_dir = os.path.join(SCHOOL_ACCOUNTS_DIR, "user_accounts")
        all_users_accounts = {}

        if os.path.exists(user_accounts_dir):
            for filename in os.listdir(user_accounts_dir):
                if filename.endswith(".json"):
                    username = filename[:-5]
                    try:
                        file_path = os.path.join(user_accounts_dir, filename)
                        with open(file_path, "r", encoding="utf-8") as f:
                            accounts = json.load(f)
                        all_users_accounts[username] = accounts
                    except Exception as e:
                        logging.error(
                            f"读取用户 {username} 的 school_accounts 失败: {e}"
                        )

        return jsonify({"success": True, "all_accounts": all_users_accounts})

    # ========== 新增：School Account 管理API（保存/添加） ==========
    @app.route("/api/admin/school_account/save", methods=["POST"])
    @login_required  # 只需要登录即可，细粒度权限在函数内部检查
    def api_admin_school_account_save():
        """
        保存或添加 School Account（PC端管理面板CRUD支持）。
        """
        # 从Flask的g对象中获取当前登录的用户名
        current_auth_username = g.user

        # 细粒度权限检查：需要 'manage_users' 权限
        # manage_users 权限允许管理用户的学校账号，包括添加、修改和删除
        # 学校账号包含敏感的登录凭证，需要严格的权限控制
        if not auth_system.check_permission(current_auth_username, "manage_users"):
            return jsonify({
                "success": False,
                "message": "权限不足，需要用户管理权限（manage_users）"
            }), 403

        # 获取session_id用于后续操作
        session_id = request.headers.get("X-Session-ID", "")
        if not session_id or session_id not in web_sessions:
            return jsonify({"success": False, "message": "未登录或会话无效"}), 401
        api_instance = web_sessions[session_id]

        # ========== 2. 解析请求数据 ==========
        try:
            data = request.get_json()
            if not data:
                return jsonify({"success": False, "message": "缺少请求数据"}), 400
            auth_username = str(data.get("auth_username") or "").strip()
            school_username = str(data.get("school_username") or "").strip()
            password = str(data.get("password") or "").strip()
            # [修正] 安全获取 ua，防止 None.strip() 报错
            ua = str(data.get("ua") or "").strip()
            if not auth_username or not school_username or not password:
                return (
                    jsonify(
                        {
                            "success": False,
                            "message": "缺少必填字段：auth_username, school_username, password",
                        }
                    ),
                    400,
                )
            # 如果前端未提供UA（为空），则自动生成一个随机UA
            if (not ua) or (ua.strip() == "") or (ua.lower() == "null") or (ua.lower() == "undefined"):
                ua = ApiClient.generate_random_ua()
                logging.info(
                    f"[SchoolAccount] 检测到UA为空，已为 {school_username} 自动生成随机UA")

        except Exception as e:
            logging.error(f"解析school_account保存请求失败: {e}", exc_info=True)
            return jsonify({"success": False, "message": "请求数据格式错误"}), 400

        # [修正] 获取当前用户的权限组，定义 auth_group 变量
        auth_group = auth_system.get_user_group(current_auth_username)

        is_admin = auth_group in ["admin", "super_admin"]
        if not is_admin and auth_username != current_auth_username:
            logging.warning(
                f"用户 {current_auth_username} 试图保存 {auth_username} 的账户，权限不足"
            )
            return (
                jsonify({"success": False, "message": "权限不足：只能保存自己的账户"}),
                403,
            )
        try:
            accounts = api_instance._load_user_school_accounts(auth_username)
            if accounts is None:
                accounts = {}

        except Exception as e:
            logging.error(
                f"加载用户 {auth_username} 的 school_accounts 失败: {e}", exc_info=True
            )
            return jsonify({"success": False, "message": "加载账户数据失败"}), 500
        is_new_account = school_username not in accounts
        accounts[school_username] = {
            "password": password,
            "ua": ua if ua else "",
        }
        action = "添加" if is_new_account else "更新"
        logging.info(
            f"{action} school_account: 认证用户={auth_username}, 学校账户={school_username}, 操作者={current_auth_username}"
        )
        try:
            api_instance._save_user_school_accounts(auth_username, accounts)
            return jsonify(
                {
                    "success": True,
                    "message": f"账户 {school_username} {action}成功",
                    "is_new": is_new_account,
                }
            )

        except Exception as e:
            logging.error(
                f"保存用户 {auth_username} 的 school_accounts 失败: {e}", exc_info=True
            )
            return jsonify({"success": False, "message": "保存账户数据失败"}), 500

    @app.route("/api/admin/backup-info", methods=["GET"])
    @login_required
    @admin_required
    def api_admin_view_backup_info():
        """
        查看学校账号备份信息
        读取 school_accounts/{school_username}_backup.json 文件并返回内容
        """
        # 细粒度权限检查：需要 'manage_users' 权限
        if not auth_system.check_permission(g.user, "manage_users"):
            return jsonify({"success": False, "message": "权限不足，需要用户管理权限"}), 403

        school_username = request.args.get("school_username", "").strip()
        if not school_username:
            return jsonify({"success": False, "message": "缺少 school_username 参数"}), 400

        # 安全检查：防止路径遍历，只允许字母数字下划线等安全字符
        # 如果用户名包含特殊字符，建议根据实际情况调整正则
        if ".." in school_username or "/" in school_username or "\\" in school_username:
            return jsonify({"success": False, "message": "非法的用户名格式"}), 400

        # 构建备份文件路径
        # SCHOOL_ACCOUNTS_DIR 是全局变量，通常是 "school_accounts"
        backup_filename = f"{school_username}_backup.json"
        backup_filepath = os.path.join(SCHOOL_ACCOUNTS_DIR, backup_filename)

        if not os.path.exists(backup_filepath):
            return jsonify({
                "success": False,
                "message": f"未找到该账号的备份数据 ({backup_filename})，请确认是否已执行过备份操作。"
            }), 404

        try:
            with open(backup_filepath, "r", encoding="utf-8") as f:
                data = json.load(f)

            return jsonify({
                "success": True,
                "data": data,
                "message": "获取成功"
            })
        except json.JSONDecodeError:
            return jsonify({"success": False, "message": "备份文件格式错误(非有效JSON)"}), 500
        except Exception as e:
            app.logger.error(f"读取备份文件失败: {e}", exc_info=True)
            return jsonify({"success": False, "message": f"读取文件出错: {str(e)}"}), 500

