    @app.route("/auth/user/avatar", methods=["GET"])
    def auth_get_user_avatar():
        """根据用户名获取头像URL（管理员可查询所有用户）

        查询参数:
        - username: 用户名（可选，不提供则返回当前用户）
        """
        session_id = request.headers.get("X-Session-ID", "")
        target_username = request.args.get("username", "")
        if not session_id or session_id not in web_sessions:
            return jsonify({"success": False, "message": "未授权访问"}), 401

        api_instance = web_sessions[session_id]
        if not hasattr(api_instance, "auth_username"):
            return jsonify({"success": False, "message": "未登录"}), 401

        current_username = getattr(api_instance, "auth_username", "")
        is_admin = auth_system.check_permission(
            current_username, "manage_users")
        if not target_username:
            target_username = current_username

            if not target_username or target_username == "guest":
                return jsonify(
                    {"success": True, "avatar_url": "", "message": "游客无头像"}
                )
        if not is_admin and target_username != current_username:
            return (
                jsonify({"success": False, "message": "权限不足，只能查询自己的头像"}),
                403,
            )
        details = auth_system.get_user_details(target_username)
        if details:
            return jsonify(
                {
                    "success": True,
                    "avatar_url": details.get("avatar_url", ""),
                    "username": target_username,
                }
            )

        return jsonify({"success": False, "message": "用户不存在", "avatar_url": ""})

    @app.route("/auth/admin/update_max_sessions", methods=["POST"])
    @login_required  # 只需要登录即可，细粒度权限在函数内部检查
    def auth_admin_update_max_sessions():
        """更新用户最大会话数量（管理员）"""
        # 从Flask的g对象中获取当前登录的用户名
        auth_username = g.user

        # 细粒度权限检查：需要 'manage_system' 权限
        # manage_system 权限允许管理系统级别的配置，包括用户会话数量限制
        # 这是影响系统资源和用户体验的重要配置
        if not auth_system.check_permission(auth_username, "manage_system"):
            return jsonify({
                "success": False,
                "message": "权限不足，需要系统管理权限（manage_system）"
            }), 403

        session_id = request.headers.get("X-Session-ID", "")

        data = request.json
        target_username = data.get("username", "")
        max_sessions = data.get("max_sessions", 1)
        if not isinstance(max_sessions, int) or (
            max_sessions < 1 and max_sessions != -1
        ):
            return (
                jsonify(
                    {
                        "success": False,
                        "message": "无效的会话数量：必须为正整数或-1（无限制）",
                    }
                ),
                400,
            )

        result = auth_system.update_max_sessions(target_username, max_sessions)
        # 使用统一函数获取客户端真实IP
        ip_address = request.environ.get("REMOTE_ADDR") or request.remote_addr
        auth_system.log_audit(
            auth_username,
            "update_max_sessions",
            f"修改用户 {target_username} 的最大会话数为: {max_sessions}",
            ip_address,
            session_id,
        )

        return jsonify(result)

    @app.route("/api/admin/update_available_runs", methods=["POST"])
    @login_required  # 只需要登录即可，细粒度权限在函数内部检查
    def api_admin_update_available_runs():
        """
        更新用户的可用执行次数（管理员API）

        请求头:
            X-Session-ID: 当前会话ID，用于身份验证和权限检查

        请求体 (JSON):
            {
                "username": "目标用户名",
                "available_runs": 新的可用次数（整数）
            }

        返回 (JSON):
            {
                "success": true/false,
                "message": "操作结果说明"
            }

        权限要求:
            - 需要有 manage_users 权限（通常为管理员）

        参数说明:
            - available_runs: -1表示无限次数，0表示无可用次数，正数表示具体次数
        """
        # 从Flask的g对象中获取当前登录的用户名
        auth_username = g.user

        # 检查细粒度权限：管理用户权限
        # manage_users 权限允许修改用户的可用执行次数配额
        if not auth_system.check_permission(auth_username, "manage_users"):
            return jsonify({"success": False, "message": "权限不足，需要用户管理权限（manage_users）"}), 403
        # 从Flask的g对象中获取会话ID（由 @login_required 装饰器设置），用于审计日志记录
        session_id = g.session_id

        # 步骤5：解析请求体中的JSON数据
        data = request.json
        # 提取目标用户名和新的可用次数值
        target_username = data.get("username", "")
        available_runs = data.get("available_runs", 0)

        # 步骤6：数据验证 - 检查目标用户名是否为空
        if not target_username:
            return (
                jsonify(
                    {
                        "success": False,
                        "message": "缺少必要参数：用户名不能为空",
                    }
                ),
                400,  # 400 Bad Request - 客户端请求参数错误
            )

        # 步骤7：数据验证 - 检查可用次数是否为整数类型
        if not isinstance(available_runs, int):
            return (
                jsonify(
                    {
                        "success": False,
                        "message": "无效的次数值：必须为整数",
                    }
                ),
                400,
            )

        # 步骤8：数据验证 - 检查可用次数的取值范围
        # 有效值: -1（无限）或 >= 0 的整数
        if available_runs < -1:
            return (
                jsonify(
                    {
                        "success": False,
                        "message": "无效的次数值：必须为-1（无限）或非负整数",
                    }
                ),
                400,
            )

        # 步骤9：调用 AuthSystem 的方法执行实际的更新操作
        result = auth_system.update_available_runs(
            target_username, available_runs)

        # 步骤10：记录审计日志 - 记录管理员的操作行为，便于追溯
        # 获取客户端真实IP地址
        ip_address = request.environ.get("REMOTE_ADDR") or request.remote_addr
        auth_system.log_audit(
            auth_username,  # 操作者（管理员）
            "update_available_runs",  # 操作类型
            # 操作详情
            f"修改用户 {target_username} 的可用次数为: {available_runs} ({'无限' if available_runs == -1 else str(available_runs) + '次'})",
            ip_address,  # 操作者IP
            session_id,  # 会话ID
        )

        # 步骤11：返回操作结果给前端
        return jsonify(result)

    @app.route("/auth/user/sessions", methods=["GET"])
    def auth_user_sessions():
        """获取用户的所有会话"""
        session_id = request.headers.get("X-Session-ID", "")
        api_instance = None
        is_guest = False
        auth_username = ""

        with web_sessions_lock:
            if session_id in web_sessions:
                api_instance = web_sessions[session_id]
                is_guest = getattr(api_instance, "is_guest", False)
                auth_username = getattr(api_instance, "auth_username", "")
            else:
                state = load_session_state(session_id)
                if state:
                    is_guest = state.get("is_guest", False)
                    auth_username = state.get("auth_username", "")
                else:
                    return (
                        jsonify({"success": False, "message": "会话无效或未登录"}),
                        401,
                    )

        sessions_info = []

        if is_guest:
            logging.debug(
                f"auth_user_sessions: Handling guest session {session_id[:8]}"
            )
            session_file = get_session_file_path(session_id)
            created_at = 0
            last_activity = 0
            login_success_status = False

            if os.path.exists(session_file):
                try:
                    with open(session_file, "r", encoding="utf-8") as f:
                        session_data = json.load(f)
                    created_at = session_data.get("created_at", 0)
                    last_activity = session_data.get("last_accessed", 0)
                except Exception as e:
                    logging.warning(
                        f"Failed to read guest session file {session_file}: {e}"
                    )

            sessions_info.append(
                {
                    "session_id": session_id,
                    "session_hash": hashlib.sha256(session_id.encode()).hexdigest()[
                        :16
                    ],
                    "created_at": created_at,
                    "last_activity": last_activity,
                    "is_current": True,
                    "login_success": login_success_status,
                    "user_data": {"username": "guest"},
                }
            )
            logging.debug(
                f"auth_user_sessions: Guest session info prepared: {sessions_info}"
            )
            return jsonify(
                {"success": True, "sessions": sessions_info, "max_sessions": -1}
            )

        elif auth_username:
            logging.debug(
                f"auth_user_sessions: Handling registered user {auth_username}"
            )
            session_ids = auth_system.get_user_sessions(auth_username)
            logging.debug(
                f"auth_user_sessions: Found linked session IDs for {auth_username}: {session_ids}"
            )
            user_details = auth_system.get_user_details(auth_username)
            max_sessions = user_details.get(
                "max_sessions", 1) if user_details else 1

            for sid in session_ids:
                session_file = get_session_file_path(sid)
                if os.path.exists(session_file):
                    try:
                        with open(session_file, "r", encoding="utf-8") as f:
                            session_data = json.load(f)
                        if session_data.get("auth_username") == auth_username:
                            is_multi_mode = session_data.get(
                                "is_multi_account_mode", False
                            )
                            session_login_success = session_data.get(
                                "login_success", False
                            )

                            if is_multi_mode:
                                account_states = session_data.get(
                                    "multi_account_states", {}
                                )
                                session_login_success = any(
                                    acc.get("school_account_logged_in", False)
                                    for acc in account_states.values()
                                )

                            sessions_info.append(
                                {
                                    "session_id": sid,
                                    "session_hash": hashlib.sha256(
                                        sid.encode()
                                    ).hexdigest()[:16],
                                    "created_at": session_data.get("created_at", 0),
                                    "last_activity": session_data.get(
                                        "last_accessed", 0
                                    ),
                                    "is_current": sid == session_id,
                                    "login_success": session_login_success,
                                    "is_multi_account_mode": is_multi_mode,
                                    "user_data": session_data.get("user_data", {}),
                                }
                            )
                    except Exception as e:
                        logging.warning(
                            f"Failed to read session file {session_file} for user {auth_username}: {e}"
                        )
                        continue
            logging.debug(
                f"auth_user_sessions: Registered user session info prepared: {len(sessions_info)} sessions"
            )
            return jsonify(
                {
                    "success": True,
                    "sessions": sessions_info,
                    "max_sessions": max_sessions,
                }
            )
        else:
            logging.warning(
                f"auth_user_sessions: Invalid state for session {session_id[:8]} - neither guest nor valid user."
            )
            return jsonify({"success": False, "message": "会话状态异常"}), 500

    @app.route("/auth/user/delete_session", methods=["POST"])
    def auth_user_delete_session():
        """删除用户的一个会话"""
        session_id = request.headers.get("X-Session-ID", "")
        if not session_id or session_id not in web_sessions:
            return jsonify({"success": False, "message": "未登录"}), 401

        api_instance = web_sessions[session_id]
        auth_username = getattr(api_instance, "auth_username", "")

        if not auth_username or auth_username == "guest":
            return jsonify({"success": False, "message": "游客无会话管理"})

        data = request.json
        target_session_id = data.get("session_id", "")

        if not target_session_id:
            return jsonify({"success": False, "message": "会话ID缺失"})
        if target_session_id == session_id:
            return jsonify({"success": False, "message": "不能删除当前会话"})

        # 在删除会话前，检查并移除关联的自动签到配置
        # 查找所有使用该会话UUID的自动签到账号
        auto_attendance_accounts = _get_auto_attendance_by_session(
            target_session_id)
        if auto_attendance_accounts:
            logging.info(
                f"[会话删除] 会话 {target_session_id} 关联了 {len(auto_attendance_accounts)} 个自动签到账号，将一并移除"
            )
            # 逐个禁用自动签到
            for school_username in auto_attendance_accounts:
                _disable_auto_attendance(school_username)
                logging.info(
                    f"[会话删除] 已禁用账号 {school_username} 的自动签到（会话已删除）"
                )

        auth_system.unlink_session_from_user(auth_username, target_session_id)
        session_file = get_session_file_path(target_session_id)
        if os.path.exists(session_file):
            try:
                os.remove(session_file)
            except (FileNotFoundError, PermissionError) as e:
                logging.debug(f"[会话删除] 删除会话文件失败: {e}")
        with web_sessions_lock:
            if target_session_id in web_sessions:
                del web_sessions[target_session_id]

        return jsonify({"success": True, "message": "会话已删除"})

    @app.route("/auth/user/create_session_persistence", methods=["POST"])
    def auth_user_create_session_persistence():
        """创建会话持久化文件（登录状态下）"""
        session_id = request.headers.get("X-Session-ID", "")

        api_instance = None
        is_guest = True

        if session_id:
            with web_sessions_lock:
                if session_id in web_sessions:
                    api_instance = web_sessions[session_id]
                    is_guest = getattr(api_instance, "is_guest", True)
                else:
                    state = load_session_state(session_id)
                    if state:
                        is_guest = state.get("is_guest", True)
        if is_guest:
            logging.warning(
                f"Attempt by guest session {session_id[:8]} to create persistent session blocked."
            )
            return (
                jsonify({"success": False, "message": "游客不允许创建额外的会话"}),
                403,
            )
        if not api_instance:
            return jsonify({"success": False, "message": "会话无效或未登录"}), 401

        auth_username = getattr(api_instance, "auth_username", "")

        api_instance = web_sessions[session_id]
        auth_username = getattr(api_instance, "auth_username", "")
        is_guest = getattr(api_instance, "is_guest", False)
        data = request.json or {}
        new_session_id = data.get("session_id", "")

        if not new_session_id:
            return jsonify({"success": False, "message": "缺少会话ID"}), 400
        uuid_pattern = re.compile(
            r"^[a-f0-9]{8}-[a-f0-9]{4}-4[a-f0-9]{3}-[89ab][a-f0-9]{3}-[a-f0-9]{12}$",
            re.IGNORECASE,
        )
        if not uuid_pattern.match(new_session_id):
            return jsonify({"success": False, "message": "无效的UUID格式"}), 400
        new_api_instance = Api(args)
        new_api_instance._session_created_at = time.time()
        new_api_instance._web_session_id = new_session_id
        if hasattr(api_instance, "auth_username"):
            new_api_instance.auth_username = api_instance.auth_username
            new_api_instance.auth_group = getattr(
                api_instance, "auth_group", "guest")
            new_api_instance.is_guest = is_guest
            new_api_instance.is_authenticated = True
        if hasattr(api_instance, "params"):
            new_api_instance.params = copy.deepcopy(api_instance.params)
        if hasattr(api_instance, "device_ua"):
            new_api_instance.device_ua = api_instance.device_ua
        cleanup_message = ""
        if not is_guest and auth_username:
            old_sessions, cleanup_message = (
                auth_system.check_single_session_enforcement(
                    auth_username, new_session_id
                )
            )
            if old_sessions:

                def cleanup_old_sessions_async():
                    for old_sid in old_sessions:
                        try:
                            cleanup_session(old_sid, "session_limit_exceeded")
                        except Exception as e:
                            logging.error(f"后台清理旧会话失败 {old_sid[:16]}...: {e}")

                cleanup_thread = threading.Thread(
                    target=cleanup_old_sessions_async, daemon=True
                )
                cleanup_thread.start()
            auth_system.link_session_to_user(auth_username, new_session_id)
            # 使用统一函数获取客户端真实IP
            ip_address = request.environ.get(
                "REMOTE_ADDR") or request.remote_addr
            audit_details = f"创建新会话持久化文件，会话ID: {new_session_id}"
            if cleanup_message:
                audit_details += f"; {cleanup_message}"

            auth_system.log_audit(
                auth_username,
                "create_session_persistence",
                audit_details,
                ip_address,
                session_id,
            )
        with web_sessions_lock:
            web_sessions[new_session_id] = new_api_instance
            save_session_state(
                new_session_id, new_api_instance, force_save=True)

        response_data = {
            "success": True,
            "message": "会话持久化文件已创建",
            "session_id": new_session_id,
        }
        if cleanup_message:
            response_data["cleanup_message"] = cleanup_message

        logging.info(f"用户 {auth_username} 创建新会话持久化: {new_session_id[:32]}...")
        response = make_response(jsonify(response_data))
        if not is_guest and auth_username:
            try:
                new_token = token_manager.create_token(
                    auth_username, new_session_id)
                logging.info(f"为新会话 {new_session_id[:8]}... 生成了 Token")
                response.set_cookie(
                    "auth_token",
                    value=new_token,
                    max_age=3600,
                    httponly=True,
                    secure=False,
                    samesite="Lax",
                )
                logging.info(
                    f"已为新会话 {new_session_id[:8]}... 设置 auth_token Cookie"
                )

            except Exception as token_err:
                logging.error(
                    f"为新会话 {new_session_id[:8]} 生成 Token 或设置 Cookie 时出错: {token_err}",
                    exc_info=True,
                )
        return response

    @app.route("/auth/admin/all_sessions", methods=["GET"])
    @login_required  # 只需要登录即可，细粒度权限在函数内部检查
    def auth_admin_all_sessions():
        """管理员：获取所有活跃会话（查看所有会话）"""
        # 从Flask的g对象中获取当前登录的用户名
        auth_username = g.user

        # 检查细粒度权限：查看所有会话权限
        # view_all_sessions 权限允许查看系统中所有用户的活跃会话信息
        # 这用于监控系统活动和安全审计
        if not auth_system.check_permission(auth_username, "view_all_sessions"):
            return jsonify({"success": False, "message": "权限不足，需要查看所有会话权限（view_all_sessions）"}), 403

        session_id = request.headers.get("X-Session-ID", "")

        with web_sessions_lock:
            if session_id not in web_sessions:
                state = load_session_state(session_id)
                if not state:
                    return (
                        jsonify({"success": False, "message": "当前会话无效或已过期"}),
                        401,
                    )
                api_instance = Api(args)
                restore_session_to_api_instance(api_instance, state)
                web_sessions[session_id] = api_instance
                logging.info(f"创建新会话时，按需恢复了发起请求的会话 {session_id[:8]}")
            else:
                api_instance = web_sessions[session_id]

        auth_username = getattr(api_instance, "auth_username", None)
        is_guest = getattr(api_instance, "is_guest", True)
        if not is_guest and auth_username:
            token_from_cookie = request.cookies.get("auth_token")
            if not token_from_cookie:
                logging.warning(
                    f"用户 {auth_username} 尝试创建会话但缺少 auth_token cookie"
                )
                return (
                    jsonify(
                        {
                            "success": False,
                            "message": "缺少认证令牌(cookie)，请重新登录",
                            "need_login": True,
                        }
                    ),
                    401,
                )

            is_valid, reason = token_manager.verify_token(
                auth_username, session_id, token_from_cookie
            )
            if not is_valid:
                logging.warning(
                    f"用户 {auth_username} 尝试创建会话但令牌无效: {reason}"
                )
                response_data = {
                    "success": False,
                    "message": f"令牌验证失败 ({reason})，请重新登录",
                    "need_login": True,
                }
                response = make_response(jsonify(response_data), 401)
                response.set_cookie("auth_token", "", max_age=0)
                return response
            else:
                token_manager.refresh_token(auth_username, session_id)
                logging.debug(
                    f"用户 {auth_username} (会话 {session_id[:8]}) Token 验证通过并已刷新"
                )
        elif not is_guest and not auth_username:
            logging.error(f"会话 {session_id[:8]} 存在但缺少用户名，无法创建新会话")
            return (
                jsonify(
                    {
                        "success": False,
                        "message": "当前会话状态异常，请重新登录",
                        "need_login": True,
                    }
                ),
                401,
            )
        # 权限检查已在函数开头完成，这里不需要重复检查
        all_sessions = []
        session_ids_in_memory = set()
        with web_sessions_lock:
            for sid, api in web_sessions.items():
                is_multi = getattr(api, "is_multi_account_mode", False)
                login_success = getattr(api, "login_success", False)
                if is_multi:
                    accounts = getattr(api, "accounts", {})
                    login_success = any(
                        getattr(acc, "login_success", False)
                        for acc in accounts.values()
                    )
                session_info = {
                    "session_id": sid,
                    "session_hash": hashlib.sha256(sid.encode()).hexdigest()[:16],
                    "auth_username": getattr(api, "auth_username", None),
                    "auth_group": getattr(api, "auth_group", "guest"),
                    "is_authenticated": getattr(api, "is_authenticated", False),
                    "is_guest": getattr(api, "is_guest", False),
                    "created_at": getattr(api, "_session_created_at", 0),
                    "login_success": login_success,
                    "is_multi_account_mode": is_multi,
                    "user_info": getattr(api, "user_info", {}),
                    "is_current": sid == session_id,
                    "username": getattr(api, "auth_username", None),
                }
                all_sessions.append(session_info)
                session_ids_in_memory.add(sid)
        try:
            if os.path.exists(SESSION_STORAGE_DIR):
                for filename in os.listdir(SESSION_STORAGE_DIR):
                    if filename == "_index.json" or not filename.endswith(".json"):
                        continue

                    session_file = os.path.join(SESSION_STORAGE_DIR, filename)
                    try:
                        with open(session_file, "r", encoding="utf-8") as f:
                            state = json.load(f)

                        sid = state.get("session_id")
                        if not sid or sid in session_ids_in_memory:
                            continue
                        is_multi_mode = state.get(
                            "is_multi_account_mode", False)
                        session_login_success = state.get(
                            "login_success", False)

                        if is_multi_mode:
                            account_states = state.get(
                                "multi_account_states", {})
                            session_login_success = any(
                                acc.get("school_account_logged_in", False)
                                for acc in account_states.values()
                            )
                        session_info = {
                            "session_id": sid,
                            "session_hash": hashlib.sha256(sid.encode()).hexdigest()[
                                :16
                            ],
                            "auth_username": state.get("auth_username", None),
                            "auth_group": state.get("auth_group", "guest"),
                            "is_authenticated": state.get("is_authenticated", False),
                            "is_guest": state.get("is_guest", False),
                            "created_at": state.get("created_at", 0),
                            "login_success": session_login_success,
                            "is_multi_account_mode": is_multi_mode,
                            "user_info": state.get("user_info", {}),
                            "is_current": sid == session_id,
                            "username": state.get("auth_username", None),
                        }
                        all_sessions.append(session_info)
                    except Exception as e:
                        logging.warning(f"读取会话文件 {filename} 失败: {e}")
                        continue
        except Exception as e:
            logging.error(f"扫描会话文件目录失败: {e}")

        return jsonify(
            {
                "success": True,
                "sessions": all_sessions,
                "total_count": len(all_sessions),
            }
        )

    @app.route("/auth/admin/destroy_session", methods=["POST"])
    @login_required  # 只需要登录即可，细粒度权限在函数内部检查
    def auth_admin_destroy_session():
        """管理员：强制销毁任意会话（管理用户会话）"""
        # 从Flask的g对象中获取当前登录的用户名
        auth_username = g.user

        # 检查细粒度权限：管理用户会话权限
        # manage_user_sessions 权限允许强制销毁任意用户的会话
        # 这是敏感操作，用于应对安全事件或异常会话
        if not auth_system.check_permission(auth_username, "manage_user_sessions"):
            return jsonify({"success": False, "message": "权限不足，需要管理用户会话权限（manage_user_sessions）"}), 403

        session_id = request.headers.get("X-Session-ID", "")

        data = request.json
        target_session_id = data.get("session_id", "")

        if not target_session_id:
            return jsonify({"success": False, "message": "会话ID缺失"})
        if target_session_id == session_id:
            return jsonify({"success": False, "message": "不能销毁当前会话"})
        target_username = "unknown"
        with web_sessions_lock:
            if target_session_id in web_sessions:
                target_api = web_sessions[target_session_id]
                target_username = getattr(
                    target_api, "auth_username", "unknown")
        if target_username != "unknown" and target_username != "guest":
            auth_system.unlink_session_from_user(
                target_username, target_session_id)
        session_hash = hashlib.sha256(target_session_id.encode()).hexdigest()
        session_file = os.path.join(
            SESSION_STORAGE_DIR, f"{session_hash}.json")
        if os.path.exists(session_file):
            try:
                os.remove(session_file)
            except (FileNotFoundError, PermissionError) as e:
                logging.debug(f"[会话强制登出] 删除会话文件失败: {e}")
        with web_sessions_lock:
            if target_session_id in web_sessions:
                del web_sessions[target_session_id]
        # 使用统一函数获取客户端真实IP
        ip_address = request.environ.get("REMOTE_ADDR") or request.remote_addr
        auth_system.log_audit(
            auth_username,
            "destroy_session",
            f"强制销毁用户 {target_username} 的会话: {target_session_id[:32]}...",
            ip_address,
            session_id,
        )

        return jsonify(
            {"success": True, "message": f"已销毁用户 {target_username} 的会话"}
        )

    @app.route("/auth/admin/audit_logs", methods=["GET"])
    @login_required  # 只需要登录即可，细粒度权限在函数内部检查
    def auth_admin_audit_logs():
        """获取审计日志（管理员）"""
        # 从Flask的g对象中获取当前登录的用户名
        auth_username = g.user

        # 检查细粒度权限：查看审计日志权限
        # view_audit_logs 权限允许查看系统的操作审计日志
        # 审计日志记录了所有敏感操作，用于安全审计和合规要求
        if not auth_system.check_permission(auth_username, "view_audit_logs"):
            return jsonify({"success": False, "message": "权限不足，需要查看审计日志权限（view_audit_logs）"}), 403
        username = request.args.get("username", None)
        action = request.args.get("action", None)
        limit = int(request.args.get("limit", 100))

        logs = auth_system.get_audit_logs(username, action, limit)
        return jsonify({"success": True, "logs": logs})

    @app.route("/api/sms/send_code", methods=["POST"])
    def sms_send_code():
        """
        发送短信验证码API
        """
        try:
            # [修正] 使用 strict=False 允许重复项，optionxform=str 保持大小写敏感
            config = configparser.ConfigParser(strict=False)
            config.optionxform = str
            config.read("config.ini", encoding="utf-8")
            if (
                config.get("Features", "enable_sms_service",
                           fallback="false").lower()
                != "true"
            ):
                return jsonify({"success": False, "message": "短信服务未启用"})
            data = request.get_json() or {}
            phone = data.get("phone", "").strip()
            scene = data.get("scene", "register").strip()
            captcha_input = data.get("captcha", "").strip()
            captcha_id = data.get("captcha_id", "").strip()

            is_captcha_valid, captcha_error_msg = verify_captcha(
                captcha_id, captcha_input
            )
            if not is_captcha_valid:
                return jsonify({"success": False, "message": captcha_error_msg})
            if not phone or not re.match(r"^1[3-9]\d{9}$", phone):
                return jsonify({"success": False, "message": "手机号格式不正确"})
            sms_interval_seconds = int(
                config.get(
                    "SMS_Service_SMSBao", "send_interval_seconds", fallback="180"
                )
            )
            last_send_key = f"sms_last_send_{phone}"
            last_send_time = cache.get(last_send_key, 0)
            current_time = time.time()

            if (
                last_send_time
                and (current_time - last_send_time) < sms_interval_seconds
            ):
                remaining_seconds = int(
                    sms_interval_seconds - (current_time - last_send_time)
                )
                return jsonify(
                    {
                        "success": False,
                        "message": f"发送过于频繁，请{remaining_seconds}秒后再试",
                        "retry_after": remaining_seconds,
                    }
                )
            client_ip = request.environ.get(
                "REMOTE_ADDR") or request.remote_addr
            current_date = time.strftime("%Y-%m-%d")
            ip_limit_key = f"sms_ip_{client_ip}_{current_date}"
            ip_count = cache.get(ip_limit_key, 0)
            ip_limit = int(
                config.get("SMS_Service_SMSBao",
                           "rate_limit_per_ip_day", fallback="20")
            )
            if ip_count >= ip_limit:
                return jsonify(
                    {
                        "success": False,
                        "message": f"IP每日发送次数已达上限({ip_limit}次)",
                    }
                )
            phone_limit_key = f"sms_phone_{phone}_{current_date}"
            phone_count = cache.get(phone_limit_key, 0)
            phone_limit = int(
                config.get(
                    "SMS_Service_SMSBao", "rate_limit_per_phone_day", fallback="5"
                )
            )
            if phone_count >= phone_limit:
                return jsonify(
                    {
                        "success": False,
                        "message": f"该手机号每日发送次数已达上限({phone_limit}次)",
                    }
                )
            code = "".join([str(random.randint(0, 9)) for _ in range(6)])
            username = config.get("SMS_Service_SMSBao",
                                  "username", fallback="")
            api_key = config.get("SMS_Service_SMSBao", "api_key", fallback="")
            signature = config.get(
                "SMS_Service_SMSBao", "signature", fallback="【电科大跑步助手】"
            )
            code_expire_minutes = int(
                config.get("SMS_Service_SMSBao",
                           "code_expire_minutes", fallback="5")
            )
            template = config.get(
                "SMS_Service_SMSBao",
                "template_register",
                fallback=f"您的验证码是：{{code}}，{code_expire_minutes}分钟内有效。",
            )

            if not username or not api_key:
                return jsonify(
                    {"success": False, "message": "短信服务配置不完整，请联系管理员"}
                )
            content = signature + template.replace("{code}", code).replace(
                "{minutes}", str(code_expire_minutes)
            )
            # import urllib.parse
            # import urllib.request

            url = f"http://api.smsbao.com/sms?u={username}&p={api_key}&m={phone}&c={urllib.parse.quote(content)}"

            logging.debug(f"[短信服务] 发送请求到短信宝API: {url}")

            try:
                response = urllib.request.urlopen(url, timeout=10)
                result = response.read().decode("utf-8").strip()
                if result == "0":
                    code_expire_minutes = int(
                        config.get(
                            "SMS_Service_SMSBao", "code_expire_minutes", fallback="5"
                        )
                    )
                    code_expire_seconds = code_expire_minutes * 60
                    sms_verification_codes[phone] = (
                        code,
                        time.time() + code_expire_seconds,
                    )
                    cache[ip_limit_key] = ip_count + 1
                    cache[phone_limit_key] = phone_count + 1
                    cache[last_send_key] = current_time
                    app.logger.info(
                        f"[短信服务] 向 {phone} 发送验证码成功，场景：{scene}，有效期：{code_expire_minutes}分钟"
                    )
                    try:
                        log_dir = LOGIN_LOGS_DIR
                        os.makedirs(log_dir, exist_ok=True)
                        session_id = request.headers.get("X-Session-ID", None)
                        username = None
                        if scene == "register":
                            username = f"注册用户({phone})"
                        elif scene == "modify":
                            if g and hasattr(g, "user"):
                                username = g.user
                            else:
                                username = "未知用户"
                        elif scene == "admin_modify":
                            username = data.get("target_username", "未知用户")
                        else:
                            if g and hasattr(g, "user"):
                                username = g.user
                            else:
                                username = phone
                        history_entry = {
                            "username": username,
                            "phone": phone,
                            "scene": scene,
                            "timestamp": time.time(),
                            "datetime": time.strftime("%Y-%m-%d %H:%M:%S"),
                            "content": content,
                            "ip": client_ip,
                        }
                        if (
                            session_id is not None
                            and session_id != ""
                            and session_id != "null"
                        ):
                            history_entry["session_id"] = session_id
                        history_file = os.path.join(
                            log_dir, "sms_history.jsonl")
                        with open(history_file, "a", encoding="utf-8") as f:
                            f.write(
                                json.dumps(history_entry,
                                           ensure_ascii=False) + "\n"
                            )

                        app.logger.debug(
                            f"[短信历史] 已记录发送历史: {phone} -> {username}"
                        )
                        if scene in [
                            "admin_modify",
                            "register",
                        ]:
                            session_id = getattr(g, "api_instance", None)
                            if session_id:
                                session_id = getattr(
                                    session_id, "_web_session_id", None
                                )

                            if session_id:
                                pass
                            else:
                                logging.debug(
                                    "[SocketIO] sms_send_code：无法获取 session_id，跳过推送"
                                )

                    except Exception as e:
                        app.logger.error(f"[短信历史] 记录失败: {str(e)}")
                    return jsonify(
                        {
                            "success": True,
                            "message": f"验证码已发送，{code_expire_minutes}分钟内有效",
                            "expire_minutes": code_expire_minutes,
                            "retry_after": sms_interval_seconds,
                        }
                    )
                else:
                    error_map = {
                        "30": "密码错误",
                        "40": "账号不存在",
                        "41": "余额不足",
                        "42": "账户已过期",
                        "43": "IP地址限制",
                        "50": "内容含有敏感词",
                    }
                    detailed_error_msg = error_map.get(
                        result, f"未知错误(错误码:{result})"
                    )
                    app.logger.error(
                        f"[短信服务] 短信宝API返回错误码: {result}, 原因: {detailed_error_msg}, 手机号: {phone}"
                    )
                    return jsonify(
                        {"success": False, "message": "验证码发送失败，请稍后重试"}
                    )

            except Exception as e:
                app.logger.error(
                    f"[短信服务] API调用异常：{str(e)}, 手机号: {phone}", exc_info=True
                )
                return jsonify(
                    {"success": False, "message": "验证码发送失败，请稍后重试"}
                )

        except Exception as e:
            app.logger.error(f"[短信服务] 处理请求异常：{str(e)}", exc_info=True)
            return jsonify({"success": False, "message": "验证码发送失败，请稍后重试"})

    @app.route("/sms-reply-webhook", methods=["GET"])
    def sms_reply_webhook():
        """
        【短信宝平台回调接口】接收用户回复推送

        这是一个符合短信宝（smsbao.com）平台规范的Webhook端点，用于接收用户对短信的回复。

        技术规范：
        - HTTP方法：GET（短信宝平台使用GET请求推送数据）
        - 请求参数：
          * m（必须）：发送方的手机号（11位中国大陆手机号）
          * c（必须）：用户回复的短信内容，采用 UTF-8 URLENCODE 编码
        - 响应要求：必须返回字符串 "0" 表示成功接收

        业务逻辑：
        1. 接收并解析短信宝推送的回复数据
        2. 对内容进行 UTF-8 URL解码（因为短信宝会对中文进行URL编码）
        3. 持久化到本地JSON日志文件，便于后续分析和追溯
        4. 记录应用日志，方便实时监控
        5. 返回 "0" 告知短信宝平台已成功接收

        返回值:
        str: 固定返回 "0"，这是短信宝平台约定的成功响应码
        """
        try:
            # ========== 第一步：获取短信宝平台推送的参数 ==========

            # 获取参数 "m"（mobile的缩写）：发送方的手机号
            # 使用 request.args.get() 从URL查询字符串中安全地获取参数
            # 如果参数不存在，默认返回空字符串（而非None），避免后续处理时出现类型错误
            phone = request.args.get("m", "")

            # 获取参数 "c"（content的缩写）：用户回复的短信内容
            # 注意：短信宝会对这个参数进行 UTF-8 URLENCODE 编码
            # 例如："你好" 会被编码为 "%E4%BD%A0%E5%A5%BD"
            content = request.args.get("c", "")

            # ========== 第二步：参数有效性校验 ==========

            # 校验必需参数是否存在且不为空
            # 如果手机号或内容任一缺失，说明这不是一个有效的短信宝回调请求
            # 即使数据无效，我们也返回 "0"，避免短信宝平台重复推送
            if not phone or not content:
                return "0"  # 返回成功响应，避免平台重试

            # ========== 第三步：内容解码（关键步骤）==========

            try:
                # 导入 urllib.parse 模块，用于URL解码
                # import urllib.parse

                # 对内容参数进行 UTF-8 URL 解码
                # 为什么需要解码？
                # - 短信宝平台为了确保中文字符在HTTP传输中不出错，会对内容进行URL编码
                # - 例如："你好" -> "%E4%BD%A0%E5%A5%BD"
                # - 我们需要将其还原为可读的中文："你好"
                #
                # urllib.parse.unquote() 参数说明：
                # - 第一个参数：要解码的字符串
                # - encoding="utf-8"：指定解码使用的字符编码为UTF-8（与短信宝平台保持一致）
                content = urllib.parse.unquote(content, encoding="utf-8")

            except Exception:
                # 捕获解码过程中可能出现的任何异常
                # 可能的异常场景：
                # - 内容格式异常（虽然不太可能）
                # - 编码格式不匹配
                #
                # 异常处理策略：使用 pass 静默忽略
                # 原因：即使解码失败，我们仍然可以使用原始（编码后的）内容进行记录
                # 这样可以确保不会因为解码问题导致整个回调处理失败
                pass

            # ========== 第四步：准备持久化存储 ==========

            # 指定日志文件的存储目录
            # LOGIN_LOGS_DIR 是全局配置的日志目录路径（通常为 "logs"）
            log_dir = LOGIN_LOGS_DIR

            # 确保日志目录存在
            # os.makedirs() 参数说明：
            # - exist_ok=True：如果目录已存在，不抛出异常，静默成功
            # 这是一个防御性编程实践，避免因目录不存在导致后续文件写入失败
            os.makedirs(log_dir, exist_ok=True)

            # 构建完整的日志文件路径
            # 日志文件名固定为 "sms_replies.json"
            # 最终路径示例："/path/to/logs/sms_replies.json"
            log_file = os.path.join(log_dir, "sms_replies.json")

            # 导入 json 模块，用于将Python字典序列化为JSON格式
            # import json

            # ========== 第五步：构建日志条目 ==========

            # 创建一个字典，包含本次短信回复的完整信息
            # 这个结构化数据便于后续进行数据分析、审计和问题追溯
            log_entry = {
                # Unix时间戳（秒级浮点数）
                # 便于程序进行时间计算（例如，计算两次回复的时间间隔）
                "timestamp": time.time(),

                # 人类可读的日期时间字符串，格式：YYYY-MM-DD HH:MM:SS
                # 便于人工查看日志时快速了解时间信息
                "datetime": time.strftime("%Y-%m-%d %H:%M:%S"),

                # 回复者的手机号（来自参数 "m"）
                "phone": phone,

                # 回复内容（已解码，为可读的中文文本）
                "content": content,

                # 短信宝平台服务器的IP地址
                # request.environ.get("REMOTE_ADDR") or request.remote_addr 获取发起HTTP请求的客户端IP
                # 记录IP地址的目的：
                # - 安全审计：验证请求确实来自短信宝平台的官方服务器
                # - 问题排查：如果出现异常请求，可以通过IP追溯来源
                "ip": request.environ.get("REMOTE_ADDR") or request.remote_addr,
            }

            # ========== 第六步：持久化到文件 ==========

            # 以追加模式（append mode）打开日志文件
            # 参数说明：
            # - "a"：追加模式，不会覆盖现有内容，而是在文件末尾添加新内容
            # - encoding="utf-8"：使用UTF-8编码写入，确保中文正确存储
            with open(log_file, "a", encoding="utf-8") as f:
                # 将字典序列化为JSON字符串，并追加换行符
                # json.dumps() 参数说明：
                # - ensure_ascii=False：不将非ASCII字符（如中文）转义为 \uXXXX 形式
                #   这样可以让日志文件中直接显示中文，而不是 Unicode 编码
                # - 最后的 "\n"：添加换行符，确保每条日志占一行（JSONL格式）
                #
                # JSONL格式（JSON Lines）的优势：
                # - 每行是一个独立的JSON对象，便于逐行读取和流式处理
                # - 追加写入时不会破坏已有数据的格式
                f.write(json.dumps(log_entry, ensure_ascii=False) + "\n")

            # ========== 第七步：记录应用日志 ==========

            # 使用 Flask 应用的日志记录器记录一条信息级别的日志
            # 这条日志会输出到应用的标准日志系统（例如控制台、日志文件等）
            # 用途：
            # - 实时监控：管理员可以通过查看应用日志实时了解短信回复情况
            # - 快速排查：如果出现问题，可以快速从应用日志中定位
            app.logger.info(f"[短信回复] 收到用户 {phone} 的回复：{content}")

            # ========== 第八步：返回成功响应 ==========

            # 返回字符串 "0" 给短信宝平台
            # 为什么必须返回 "0"？
            # - 这是短信宝平台的技术约定，表示"已成功接收并处理"
            # - 如果返回其他内容（例如 "success"、空字符串、HTTP错误状态码），
            #   短信宝平台可能会认为推送失败，并进行重试，导致重复接收
            # - 返回 "0" 后，短信宝平台会将本次推送标记为成功，不再重试
            return "0"

        except Exception as e:
            # ========== 异常处理：确保健壮性 ==========

            # 捕获所有可能的异常，防止服务崩溃
            # 可能的异常场景：
            # - 文件系统错误（磁盘已满、权限不足等）
            # - 内存错误
            # - 其他未预见的运行时错误

            # 记录错误日志，便于后续排查问题
            # 日志中包含完整的异常信息（str(e)）
            app.logger.error(f"[短信回复] 处理异常：{str(e)}")

            # 即使发生异常，仍然返回 "0"
            # 原因：避免短信宝平台因为我们的内部错误而反复重试
            # 这是一种"宽进严出"的设计理念：
            # - 对外：始终表现为"成功接收"，保持接口的稳定性
            # - 对内：通过日志记录错误，由开发人员后续修复
            return "0"

    @app.route("/api/sms/test_send", methods=["POST"])
    @login_required
    def sms_test_send():
        """
        短信测试发送API
        """
        try:
            # 获取当前登录的用户名
            # g.user 由 @login_required 装饰器设置，包含已验证的用户身份
            current_user = g.user

            # 使用用户组别判断而非权限判断
            #
            # 修复原因：
            # 系统采用差分权限管理，允许普通用户(user组)通过配置拥有管理员权限
            # 例如：user组的用户可能被配置为拥有 manage_users 或 god_mode 权限
            # 因此，不能通过检查权限来判断用户是否是真正的管理员
            # 必须直接读取用户组别（group）来准确判断用户的管理员身份
            #
            # 技术实现：
            # - 使用 get_user_group() 方法直接获取用户所属的组别
            # - 只允许 "admin" 和 "super_admin" 组的用户访问此功能
            # - 这样确保即使普通用户拥有管理员权限，也无法访问管理员专属功能
            #
            # 安全考虑：
            # - 短信测试功能是管理员专属操作，不应对普通用户开放
            # - 通过组别判断可以严格控制访问权限，避免权限滥用
            user_group = auth_system.get_user_group(current_user)

            # 检查用户组别：只允许管理员和超级管理员访问
            if user_group not in ["admin", "super_admin"]:
                # 权限不足时返回403禁止访问状态码
                return (
                    jsonify(
                        {
                            "success": False,
                            "message": "权限不足，仅管理员可使用测试功能",
                        }
                    ),
                    403,
                )
            # 使用 strict=False 允许重复项，optionxform=str 保持大小写敏感
            config = configparser.ConfigParser(strict=False)
            config.optionxform = str
            config.read("config.ini", encoding="utf-8")
            if (
                config.get("Features", "enable_sms_service",
                           fallback="false").lower()
                != "true"
            ):
                return jsonify(
                    {"success": False, "message": "短信服务未启用，请先在配置中启用"}
                )
            data = request.get_json() or {}
            phone = data.get("phone", "").strip()
            custom_code = data.get("code", "").strip()
            if not phone or not re.match(r"^1[3-9]\d{9}$", phone):
                return jsonify({"success": False, "message": "手机号格式不正确"})
            if custom_code:
                if not re.match(r"^\d{4,8}$", custom_code):
                    return jsonify(
                        {
                            "success": False,
                            "message": "自定义验证码格式不正确，仅支持4-8位数字",
                        }
                    )
                code = custom_code
            else:
                # import random

                code = "".join([str(random.randint(0, 9)) for _ in range(6)])
            username = config.get("SMS_Service_SMSBao",
                                  "username", fallback="")
            api_key = config.get("SMS_Service_SMSBao", "api_key", fallback="")
            signature = config.get(
                "SMS_Service_SMSBao", "signature", fallback="【电科大跑步助手】"
            )
            code_expire_minutes = int(
                config.get("SMS_Service_SMSBao",
                           "code_expire_minutes", fallback="5")
            )

            if not username or not api_key:
                return jsonify(
                    {
                        "success": False,
                        "message": "短信服务配置不完整，请先完善短信宝用户名和API Key",
                    }
                )
            content = (
                signature
                + f"【测试短信】您的验证码是：{code}，{code_expire_minutes}分钟内有效。这是一条测试短信。"
            )
            # import urllib.parse
            # import urllib.request

            url = f"http://api.smsbao.com/sms?u={username}&p={api_key}&m={phone}&c={urllib.parse.quote(content)}"

            logging.info(f"[短信测试] 管理员 {current_user} 发送测试短信到 {phone}")

            try:
                response = urllib.request.urlopen(url, timeout=10)
                result = response.read().decode("utf-8").strip()
                if result == "0":
                    try:
                        log_dir = LOGIN_LOGS_DIR
                        os.makedirs(log_dir, exist_ok=True)

                        client_ip = request.environ.get(
                            "REMOTE_ADDR") or request.remote_addr
                        history_entry = {
                            "username": f"{current_user}(测试)",
                            "phone": phone,
                            "scene": "admin_test",
                            "timestamp": time.time(),
                            "datetime": time.strftime("%Y-%m-%d %H:%M:%S"),
                            "content": content,
                            "ip": client_ip,
                            "test_code": code,
                        }

                        history_file = os.path.join(
                            log_dir, "sms_history.jsonl")
                        with open(history_file, "a", encoding="utf-8") as f:
                            f.write(
                                json.dumps(history_entry,
                                           ensure_ascii=False) + "\n"
                            )

                        logging.info(
                            f"[短信测试] 已记录测试短信历史: {phone} -> 验证码: {code}"
                        )
                    except Exception as e:
                        logging.error(f"[短信测试] 记录历史失败: {str(e)}")
                    return jsonify(
                        {
                            "success": True,
                            "message": f"测试短信发送成功！验证码：{code}",
                            "code": code,
                            "phone": phone,
                        }
                    )
                else:
                    error_map = {
                        "30": "密码错误",
                        "40": "账号不存在",
                        "41": "余额不足",
                        "42": "账户已过期",
                        "43": "IP地址限制",
                        "50": "内容含有敏感词",
                    }
                    error_msg = error_map.get(result, f"未知错误(错误码:{result})")
                    logging.error(
                        f"[短信测试] 短信宝API返回错误: {result} - {error_msg}"
                    )
                    return jsonify(
                        {
                            "success": False,
                            "message": f"发送失败：{error_msg}",
                            "error_code": result,
                        }
                    )

            except Exception as e:
                logging.error(f"[短信测试] API调用异常: {str(e)}", exc_info=True)
                return jsonify({"success": False, "message": f"网络错误：{str(e)}"})

        except Exception as e:
            logging.error(f"[短信测试] 处理请求异常: {str(e)}", exc_info=True)
            return jsonify({"success": False, "message": f"处理失败：{str(e)}"})

    @app.route("/api/sms/reply-logs", methods=["GET"])
    @login_required
    def sms_reply_logs():
        """
        获取短信回复记录API

        功能说明：
        查询短信宝webhook接收到的用户短信回复记录。
        仅管理员可访问此接口，用于查看用户回复的短信内容。

        权限要求：
        - 需要管理员或超级管理员权限

        查询参数（URL参数）：
            - limit (int, 可选): 返回记录数量，默认100，最大1000
            - phone (str, 可选): 按手机号筛选

        返回数据（JSON格式）：
            - success (bool): 是否成功
            - logs (list): 回复记录列表（按时间倒序）
                每条记录包含：
                - timestamp: 时间戳
                - datetime: 可读时间
                - phone: 回复手机号
                - content: 回复内容
                - ip: 请求IP地址
            - total (int): 总记录数
            - message (str): 错误信息（失败时）

        使用场景：
        - 查看用户通过短信回复的内容
        - 分析用户反馈
        - 调试短信回复webhook功能
        """
        try:
            # 获取当前登录的用户名
            # g.user 由 @login_required 装饰器设置，确保：
            # 1. X-Session-ID 请求头已验证（第15714行）
            # 2. 会话有效性已检查（第15720-15725行）
            # 3. 用户身份已认证（第15726-15727行）
            current_user = g.user

            # [修复] 使用用户组别判断而非权限判断
            #
            # 修复原因：
            # 系统采用差分权限管理，允许普通用户(user组)通过配置拥有管理员权限
            # 例如：user组的用户可能被配置为拥有 view_logs 权限
            # 因此，不能通过检查权限来判断用户是否是真正的管理员
            # 必须直接读取用户组别（group）来准确判断用户的管理员身份
            #
            # 技术实现：
            # - 使用 get_user_group() 方法直接获取用户所属的组别
            # - 只允许 "admin" 和 "super_admin" 组的用户访问此功能
            # - 这样确保即使普通用户拥有日志查看权限，也无法访问管理员专属的短信回复日志
            #
            # 安全考虑：
            # - 短信回复日志可能包含敏感的用户通信内容
            # - 必须严格限制为管理员和超级管理员才能访问
            # - 通过组别判断可以严格控制访问权限，避免权限滥用
            user_group = auth_system.get_user_group(current_user)

            # 检查用户组别：只允许管理员和超级管理员访问
            if user_group not in ["admin", "super_admin"]:
                # 权限不足时返回403禁止访问状态码
                return jsonify({
                    "success": False,
                    "message": "权限不足，仅管理员可查看短信回复记录"
                }), 403

            # 获取查询参数
            # limit: 返回记录数量，默认100，最大1000
            limit = int(request.args.get("limit", "100"))
            if limit < 1:
                limit = 100
            if limit > 1000:
                limit = 1000

            # phone: 按手机号筛选（可选）
            phone_filter = request.args.get("phone", "").strip()

            # 读取短信回复日志文件
            log_dir = LOGIN_LOGS_DIR  # 使用登录日志目录
            log_file = os.path.join(log_dir, "sms_replies.json")

            # 初始化日志列表
            logs = []

            # 检查日志文件是否存在
            if os.path.exists(log_file):
                try:
                    # 读取日志文件
                    # 文件格式：每行一个JSON对象
                    with open(log_file, "r", encoding="utf-8") as f:
                        for line in f:
                            line = line.strip()
                            if not line:
                                continue  # 跳过空行

                            try:
                                # 解析JSON行
                                entry = json.loads(line)

                                # 如果指定了手机号筛选，则进行筛选
                                if phone_filter and entry.get("phone") != phone_filter:
                                    continue

                                # 添加到日志列表
                                logs.append(entry)
                            except json.JSONDecodeError as e:
                                # 如果某行JSON解析失败，记录错误但继续处理其他行
                                app.logger.warning(
                                    f"[SMS回复日志] 解析JSON失败: {line[:50]}... 错误: {str(e)}")
                                continue

                    # 按时间戳倒序排序（最新的在前面）
                    logs.sort(key=lambda x: x.get(
                        "timestamp", 0), reverse=True)

                    # 限制返回数量
                    total = len(logs)
                    logs = logs[:limit]

                    # 返回成功响应
                    return jsonify({
                        "success": True,
                        "logs": logs,
                        "total": total,
                        "limit": limit
                    })

                except Exception as e:
                    # 文件读取异常
                    app.logger.error(f"[SMS回复日志] 读取日志文件失败: {str(e)}")
                    return jsonify({
                        "success": False,
                        "message": f"读取日志文件失败: {str(e)}"
                    }), 500
            else:
                # 日志文件不存在，返回空列表
                return jsonify({
                    "success": True,
                    "logs": [],
                    "total": 0,
                    "limit": limit,
                    "message": "暂无短信回复记录"
                })

        except Exception as e:
            # 处理请求异常
            app.logger.error(f"[SMS回复日志] 处理请求异常: {str(e)}", exc_info=True)
            return jsonify({
                "success": False,
                "message": f"处理失败：{str(e)}"
            }), 500

