    #         return "<html><body><h1>页面加载失败</h1><p>请联系客服</p></body></html>", 500

    @app.route("/api/payment/orders", methods=["GET"])
    @login_required
    def payment_list_orders():
        """
        查询订单列表接口

        请求方法：GET
        权限要求：需要登录

        查询参数（URL参数）：
            - status (str, 可选): 订单状态过滤
                - "pending": 待支付
                - "paid": 已支付
                - "closed": 已关闭
            - page (int, 可选): 页码，默认1
            - per_page (int, 可选): 每页数量，默认20

        返回数据（JSON格式）：
            - success (bool): 是否成功
            - message (str): 提示信息
            - orders (list): 订单列表
            - total (int): 总订单数
            - page (int): 当前页码
            - per_page (int): 每页数量

        功能说明：
        1. 普通用户只能查询自己的订单
        2. 管理员可以查询所有用户的订单
        3. 支持按状态筛选
        4. 支持分页查询
        5. 订单按创建时间倒序排列（最新的在前面）
        """
        try:
            # 获取查询参数
            status_filter = request.args.get("status", "").strip()  # 状态过滤
            page = int(request.args.get("page", "1"))              # 页码
            per_page = int(request.args.get("per_page", "20"))     # 每页数量

            # 验证参数
            if page < 1:
                page = 1
            if per_page < 1 or per_page > 100:
                per_page = 20

            # 检查是否是管理员
            is_admin = auth_system.check_permission(g.user, "manage_users")

            # ========== 读取所有订单文件 ==========

            orders = []

            # 遍历订单目录中的所有JSON文件
            for filename in os.listdir(PAYMENT_ORDERS_DIR):
                # 只处理.json文件
                if not filename.endswith(".json"):
                    continue

                # 构造文件完整路径
                file_path = os.path.join(PAYMENT_ORDERS_DIR, filename)

                try:
                    # 读取订单数据
                    with open(file_path, "r", encoding="utf-8") as f:
                        order_data = json.load(f)

                    # ========== 权限过滤 ==========
                    # 普通用户只能看到自己的订单
                    # 管理员可以看到所有订单
                    if not is_admin:
                        # 不是管理员，检查订单是否属于当前用户
                        if order_data.get("username") != g.user:
                            # 不是当前用户的订单，跳过
                            continue

                    # ========== 状态过滤 ==========
                    # 如果指定了状态过滤，只返回匹配的订单
                    if status_filter:
                        if order_data.get("status") != status_filter:
                            # 状态不匹配，跳过
                            continue

                    # 添加到订单列表
                    orders.append(order_data)

                except (json.JSONDecodeError, IOError) as e:
                    # 文件读取或解析失败，记录日志并跳过
                    logging.warning(
                        f"[订单列表] 读取订单文件失败: {filename}, 错误: {str(e)}")
                    continue

            # ========== 排序 ==========
            # 按创建时间倒序排列（最新的在前面）
            orders.sort(key=lambda x: x.get("created_at", 0), reverse=True)

            # ========== 分页 ==========
            total = len(orders)  # 总订单数
            start = (page - 1) * per_page  # 起始索引
            end = start + per_page  # 结束索引
            orders_page = orders[start:end]  # 当前页的订单

            # 返回订单列表
            return jsonify({
                "success": True,
                "message": "查询成功",
                "orders": orders_page,
                "total": total,
                "page": page,
                "per_page": per_page,
            })

        except Exception as e:
            logging.error(f"[订单列表] 查询订单列表异常: {str(e)}")
            logging.error(traceback.format_exc())
            return jsonify({"success": False, "message": f"查询失败: {str(e)}"}), 500

