    # 通过订单号直接查询订单接口（无需遍历所有订单，性能更优）
    # ==============================================================================

    @app.route("/api/payment/order_by_tradeno", methods=["GET"])
    @login_required
    def payment_get_order_by_tradeno():
        """
        通过订单号直接查询单个订单接口

        请求方法：GET
        权限要求：需要登录

        查询参数（URL参数）：
            - trade_no (str, 必需): 商户订单号

        返回数据（JSON格式）：
            - success (bool): 是否成功
            - message (str): 提示信息
            - order (dict): 订单详细数据（仅在success=true时存在）

        功能说明：
        1. 普通用户只能查询自己的订单，否则返回权限错误
        2. 管理员可以查询所有用户的订单
        3. 直接通过文件路径读取订单，无需遍历所有订单文件
        4. 相比 /api/payment/orders 接口，性能更优，适用于按订单号精确查询的场景

        使用场景：
        - 前端通过订单号快速获取订单金额等信息
        - 退款时验证订单是否存在
        - 订单详情页直接加载订单数据
        """
        try:
            # ========== 步骤1：获取并验证请求参数 ==========

            # 从URL查询参数中获取订单号（trade_no）
            # strip() 去除首尾空格，避免用户误输入空格导致查询失败
            trade_no = request.args.get("trade_no", "").strip()

            # 验证订单号是否为空
            # 如果为空，返回400错误（Bad Request - 客户端请求参数错误）
            if not trade_no:
                return jsonify({
                    "success": False,
                    "message": "订单号不能为空"
                }), 400

            # ========== 步骤2：构造订单文件路径 ==========

            # 使用 os.path.join() 安全地拼接路径，避免路径注入攻击
            # PAYMENT_ORDERS_DIR: 订单存储目录（全局常量）
            # 订单文件命名规则：{订单号}.json
            order_file = os.path.join(PAYMENT_ORDERS_DIR, f"{trade_no}.json")

            # 记录调试日志：开始查询订单
            logging.debug(
                f"[订单查询] 通过订单号查询订单 - "
                f"用户: {g.user}, 订单号: {trade_no}, 文件路径: {order_file}"
            )

            # ========== 步骤3：检查订单文件是否存在 ==========

            # 使用 os.path.exists() 检查文件是否存在
            # 如果文件不存在，说明订单号无效或订单已被删除
            if not os.path.exists(order_file):
                # 返回404错误（Not Found - 资源不存在）
                # 这里不使用500错误，因为这是正常的业务逻辑（订单不存在）
                logging.warning(
                    f"[订单查询] 订单文件不存在 - "
                    f"用户: {g.user}, 订单号: {trade_no}"
                )
                return jsonify({
                    "success": False,
                    "message": f"订单不存在：{trade_no}"
                }), 404

            # ========== 步骤4：读取订单文件 ==========

            try:
                # 以只读模式打开订单文件
                # encoding="utf-8": 指定UTF-8编码，确保正确读取中文内容
                with open(order_file, "r", encoding="utf-8") as f:
                    # json.load() 将JSON格式的文件内容解析为Python字典对象
                    order_data = json.load(f)

            except json.JSONDecodeError as json_err:
                # JSON解析失败（文件内容格式错误或损坏）
                # 这通常是由于文件写入不完整或手动编辑错误导致
                logging.error(
                    f"[订单查询] 订单文件格式错误 - "
                    f"订单号: {trade_no}, 错误: {str(json_err)}"
                )
                return jsonify({
                    "success": False,
                    "message": "订单文件格式错误，请联系管理员"
                }), 500

            except IOError as io_err:
                # 文件读取失败（磁盘IO错误、权限不足等）
                logging.error(
                    f"[订单查询] 读取订单文件失败 - "
                    f"订单号: {trade_no}, 错误: {str(io_err)}"
                )
                return jsonify({
                    "success": False,
                    "message": "读取订单失败，请稍后重试"
                }), 500

            # ========== 步骤5：权限检查（重要安全控制） ==========

            # 检查当前用户是否为管理员
            # check_permission() 会验证用户是否有"manage_users"权限
            is_admin = auth_system.check_permission(g.user, "manage_users")

            # 从订单数据中获取订单所属用户名
            # get() 方法安全地获取字段值，如果字段不存在则返回None
            order_username = order_data.get("username")

            # 权限验证逻辑：
            # - 如果不是管理员（is_admin=False）
            # - 并且订单不属于当前用户（order_username != g.user）
            # - 则拒绝访问，返回403错误（Forbidden - 禁止访问）
            if not is_admin and order_username != g.user:
                # 记录安全日志：用户尝试访问不属于自己的订单
                logging.warning(
                    f"[订单查询] 权限拒绝 - "
                    f"用户 {g.user} 尝试查询其他用户的订单: {trade_no} "
                    f"(订单所属用户: {order_username})"
                )
                return jsonify({
                    "success": False,
                    "message": "无权限访问该订单"
                }), 403

            # ========== 步骤6：返回订单数据 ==========

            # 记录订单查询操作日志
            # 记录成功的订单查询，用于审计和安全监控
            _write_payment_log(
                user_id=g.user,                     # 查询用户
                order_id=trade_no,                  # 订单号
                action="query_order_by_tradeno",   # 操作类型：通过订单号查询订单
                log_data={
                    "query_method": "direct",       # 查询方式：直接查询（区别于列表查询）
                    "order_status": order_data.get("status"),  # 订单状态
                    "order_amount": order_data.get("amount"),  # 订单金额
                    "is_admin": is_admin,           # 是否管理员查询
                    "result": "success"             # 查询结果：成功
                }
            )

            # 记录成功日志
            logging.info(
                f"[订单查询] 查询订单成功 - "
                f"用户: {g.user}, 订单号: {trade_no}, "
                f"订单状态: {order_data.get('status')}"
            )

            # 返回成功响应（HTTP 200 OK）
            # order字段包含完整的订单数据
            return jsonify({
                "success": True,
                "message": "查询成功",
                "order": order_data
            })

        except Exception as e:
            # ========== 捕获所有未预期的异常 ==========

            # 记录详细的错误日志，包含完整的堆栈跟踪
            # 这有助于快速定位和修复问题
            logging.error(
                f"[订单查询] 查询订单异常 - "
                f"用户: {g.user}, 订单号: {trade_no}, 错误: {str(e)}"
            )
            logging.error(traceback.format_exc())

            # 返回500错误（Internal Server Error - 服务器内部错误）
            # 不向客户端暴露详细的错误信息，避免安全风险
            return jsonify({
                "success": False,
                "message": f"查询失败: {str(e)}"
            }), 500

    # ==============================================================================
    # 支付验证接口 - 用于验证app_host的安全性
    # ==============================================================================

    @app.route("/api/payment/verify_host", methods=["POST"])
    @login_required
    def payment_verify_host():
        """
        验证app_host是否为本服务器的安全接口

        请求方法：POST
        权限要求：需要登录（仅管理员应使用）

        请求参数（JSON格式）：
            - app_host (str): 需要验证的应用域名（例如："https://example.com"）

        返回数据（JSON格式）：
            - success (bool): 验证是否通过
            - message (str): 验证结果信息
            - verified (bool): 是否验证通过

        功能说明：
        这个接口使用随机验证码机制来验证传入的app_host是否确实是本服务器。
        验证流程：
        1. 生成一个6位随机字符串作为验证码（challenge）
        2. 向 {app_host}/api/payment/verify_challenge 发送POST请求，携带验证码
        3. 检查响应中返回的验证码是否与发送的一致
        4. 如果一致，说明app_host指向的就是本服务器

        安全意义：
        - 防止攻击者配置错误的app_host导致支付回调被劫持
        - 确保支付异步通知URL指向正确的服务器
        - 使用随机验证码，每次验证都不同，防止重放攻击

        使用场景：
        - 管理员在配置彩虹易支付时，验证app_host配置是否正确
        - 前端动态传入app_host前，先进行验证
        """
        # 声明使用全局 requests 变量
        # requests 已在 check_and_import_dependencies() 中导入
        global requests

        try:
            # 从请求体中获取JSON数据
            data = request.get_json() or {}

            # 提取需要验证的app_host参数
            # strip() 去除首尾空白字符
            app_host = data.get("app_host", "").strip()

            # ========== 参数验证 ==========

            # 验证app_host是否为空
            if not app_host:
                return jsonify({
                    "success": False,
                    "message": "app_host参数不能为空",
                    "verified": False
                })

            # 验证app_host格式：必须以http://或https://开头
            # 这确保了URL的基本格式正确
            if not (app_host.startswith("http://") or app_host.startswith("https://")):
                return jsonify({
                    "success": False,
                    "message": "app_host格式不正确，必须以http://或https://开头",
                    "verified": False
                })

            # 移除app_host末尾的斜杠（如果存在）
            # 这样可以统一URL格式，避免出现双斜杠的情况
            # 例如：https://example.com/ -> https://example.com
            app_host = app_host.rstrip('/')

            # ========== 生成随机验证码 ==========

            # 生成一个2048位的随机字符串作为验证码（challenge）
            # 使用大小写字母和数字的组合，确保极高的安全性和随机性
            # string.ascii_letters 包含所有大小写字母（a-z, A-Z，共52个字符）
            # string.digits 包含所有数字（0-9，共10个字符）
            # 总共62个字符的字符集，2048位随机字符串的组合数为 62^2048
            # import string
            # random.choices() 从给定字符集中随机选择k个字符
            # k=2048 表示生成2048位验证码，提供极高的安全强度
            # ''.join() 将字符列表拼接成字符串
            challenge = ''.join(random.choices(
                string.ascii_letters + string.digits, k=2048))

            # 记录日志：开始验证app_host
            # 由于验证码长度为2048位，日志中只记录前32位和后32位，避免日志过长
            challenge_preview = f"{challenge[:32]}...{challenge[-32:]}" if len(
                challenge) > 64 else challenge
            logging.info(
                f"[支付验证] 开始验证app_host: {app_host}, 验证码长度: {len(challenge)}位, 预览: {challenge_preview}")

            # ========== 发送验证请求 ==========

            # 构造验证接口的完整URL
            # 格式：{app_host}/api/payment/verify_challenge
            verify_url = f"{app_host}/api/payment/verify_challenge"

            try:
                # 向verify_challenge接口发送POST请求
                # json参数：以JSON格式发送验证码
                # timeout参数：设置5秒超时，避免长时间等待
                # 5秒对于本地服务器已经足够，如果5秒内无响应说明可能不是本服务器
                response = requests.post(
                    verify_url,
                    json={"challenge": challenge},
                    timeout=5
                )

                # 检查HTTP响应状态码
                # 200表示请求成功
                if response.status_code == 200:
                    # 尝试解析响应JSON
                    try:
                        result = response.json()

                        # 从响应中提取返回的验证码
                        returned_challenge = result.get("challenge", "")

                        # 对比发送的验证码和返回的验证码
                        # 如果完全一致，说明确实是本服务器
                        if returned_challenge == challenge:
                            # 验证通过
                            logging.info(f"[支付验证] app_host验证通过: {app_host}")
                            return jsonify({
                                "success": True,
                                "message": "验证通过，这是本服务器",
                                "verified": True
                            })
                        else:
                            # 验证码不匹配，验证失败
                            logging.warning(
                                f"[支付验证] 验证码不匹配 - 发送: {challenge}, 返回: {returned_challenge}"
                            )
                            return jsonify({
                                "success": False,
                                "message": "验证失败：返回的验证码不匹配",
                                "verified": False
                            })

                    except json.JSONDecodeError:
                        # 响应不是有效的JSON格式
                        logging.warning(f"[支付验证] 响应不是有效的JSON格式")
                        return jsonify({
                            "success": False,
                            "message": "验证失败：响应格式不正确",
                            "verified": False
                        })

                else:
                    # HTTP状态码不是200
                    logging.warning(
                        f"[支付验证] HTTP请求失败 - 状态码: {response.status_code}"
                    )
                    return jsonify({
                        "success": False,
                        "message": f"验证失败：HTTP状态码 {response.status_code}",
                        "verified": False
                    })

            except requests.exceptions.Timeout:
                # 请求超时
                logging.warning(f"[支付验证] 请求超时 - {verify_url}")
                return jsonify({
                    "success": False,
                    "message": "验证失败：请求超时（5秒）",
                    "verified": False
                })

            except requests.exceptions.ConnectionError:
                # 连接错误（网络不通或域名无法解析）
                logging.warning(f"[支付验证] 连接失败 - {verify_url}")
                return jsonify({
                    "success": False,
                    "message": "验证失败：无法连接到目标服务器",
                    "verified": False
                })

            except Exception as e:
                # 其他异常
                logging.error(f"[支付验证] 验证过程异常: {str(e)}")
                return jsonify({
                    "success": False,
                    "message": f"验证失败：{str(e)}",
                    "verified": False
                })

        except Exception as e:
            # 捕获最外层的所有异常
            logging.error(f"[支付验证] verify_host接口异常: {str(e)}")
            logging.error(traceback.format_exc())
            return jsonify({
                "success": False,
                "message": f"验证失败：{str(e)}",
                "verified": False
            }), 500

    @app.route("/api/payment/verify_challenge", methods=["POST"])
    def payment_verify_challenge():
        """
        验证挑战响应接口（用于配合verify_host验证）

        本接口的作用：
        1. 接收客户端发送的 challenge（验证码）
        2. 验证请求来源IP是否为内网或服务器自己的公网IP
        3. 如果验证通过，将 challenge 存储到全局变量中
        4. 返回验证成功的响应（不包含challenge，由全局变量存储）

        新的验证机制：
        - 不再在响应中返回 challenge
        - 而是存储到全局变量 payment_verify_challenge_get 中
        - create_order 方法会从全局变量中读取进行比对
        """
        try:
            # 从请求体中获取JSON数据
            # 使用 request.get_json() 解析请求体中的 JSON 数据
            # 如果解析失败或请求体为空，则返回空字典
            data = request.get_json() or {}

            # 提取验证码参数
            # 使用.get()方法安全地获取，如果不存在返回空字符串
            # 这样可以避免 KeyError 异常
            challenge = data.get("challenge", "")

            # 记录日志：收到验证请求
            # 记录请求来源IP，用于安全审计
            client_ip = request.environ.get(
                "REMOTE_ADDR") or request.remote_addr
            logging.info(
                f"[支付验证] 收到验证请求 - 来源IP: {client_ip}, 验证码长度: {len(challenge)}位")

            # 验证请求来源IP是否被允许
            # 使用新的 IPVerifier.is_allowed_ip() 函数，支持 IPv4/IPv6 和公网IP验证
            if not IPVerifier().is_allowed_ip(client_ip):
                # IP验证失败：不是内网IP，也不是服务器的公网IP
                # 返回403 Forbidden状态码，拒绝访问
                logging.warning(f"[支付验证] IP验证失败 - 拒绝访问: {client_ip}")
                return jsonify({
                    "success": False,
                    "message": "仅允许内网IP或服务器本机IP访问此接口",
                }), 403

            # IP验证通过，将接收到的 challenge 存储到全局变量
            # 声明使用全局变量 payment_verify_challenge_get
            global payment_verify_challenge_get

            # 将 challenge 赋值给全局变量
            # 这个值将在 create_order 方法中被读取用于验证
            payment_verify_challenge_get = challenge

            # 记录日志：成功存储验证码
            # 只记录验证码的长度，不记录完整内容（太长）
            logging.info(f"[支付验证] 验证码已存储到全局变量，长度: {len(challenge)}位")

            # 返回验证成功响应
            # 注意：新的机制中不再返回 challenge
            # 只返回 success: True，表示验证码已成功接收和存储
            return jsonify({
                "success": True
            })

        except Exception as e:
            # 捕获所有异常
            # 即使出现异常，也返回错误信息而不是让请求失败
            # 这样可以让调用方知道发生了什么错误
            logging.error(f"[支付验证] verify_challenge接口异常: {str(e)}")
            logging.error(traceback.format_exc())
            return jsonify({
                "success": False,
                "message": f"处理失败：{str(e)}"
            }), 500

    # ==============================================================================
    # 支付管理接口 - 管理员配置支付方式
    # ==============================================================================

    @app.route("/api/admin/payment/config", methods=["GET", "PUT"])
    @login_required  # 只需要登录即可，细粒度权限在函数内部检查
    def admin_payment_config():
        """
        获取或更新支付配置接口（管理员专用）

        请求方法：GET（获取配置）、PUT（更新配置）
        权限要求：modify_config权限

        GET请求 - 获取当前支付配置：
        返回数据（JSON格式）：
            - success (bool): 是否成功
            - config (dict): 当前支付配置
                - enabled_payment_methods (list): 启用的支付方式列表
                - all_payment_methods (list): 所有支持的支付方式

        PUT请求 - 更新支付配置：
        请求参数（JSON格式）：
            - enabled_payment_methods (list): 要启用的支付方式列表
                - 例如：["alipay", "wxpay"] 或 ["alipay", "wxpay", "bank"]

        返回数据（JSON格式）：
            - success (bool): 是否成功
            - message (str): 操作结果信息

        功能说明：
        这个接口允许管理员动态配置启用哪些支付方式，无需重启服务器。
        配置会立即生效，影响后续创建的所有订单。

        使用场景：
        - 管理员在后台管理面板配置支付方式
        - 根据运营策略动态调整支持的支付方式
        - 临时禁用某些支付方式进行维护

        安全措施：
        - 需要modify_config权限
        - 验证支付方式的有效性
        - 记录配置变更日志
        """
        try:
            # 检查细粒度权限：修改配置权限
            # modify_config 权限允许修改支付配置
            # 支付配置影响系统的收款功能，需要谨慎管理
            if not auth_system.check_permission(g.user, "modify_config"):
                return jsonify({"success": False, "message": "权限不足，需要修改配置权限（modify_config）"}), 403

            # 定义所有支持的支付方式及其中文名称
            # 这是系统支持的完整支付方式列表
            all_methods = {
                "alipay": "支付宝",
                "wxpay": "微信支付",
                "bank": "网银支付"
            }

            if request.method == "GET":
                # ========== 处理GET请求：获取当前配置 ==========

                # 读取配置文件
                # ConfigParser 用于读取 INI 格式的配置文件
                config = configparser.ConfigParser()
                config.read("config.ini", encoding="utf-8")

                # 获取当前启用的支付方式
                # 从 [Rainbow_YiPay] 节读取 enabled_payment_methods 配置项
                # 格式为逗号分隔的字符串，如 "alipay,wxpay"
                enabled_methods_str = config.get(
                    "Rainbow_YiPay",
                    "enabled_payment_methods",
                    fallback="alipay,wxpay"
                ).strip()

                # 解析为列表
                # 使用列表推导式将逗号分隔的字符串转换为列表
                enabled_methods = [
                    method.strip()
                    for method in enabled_methods_str.split(",")
                    if method.strip()
                ]

                # 如果解析为空，使用默认值
                if not enabled_methods:
                    enabled_methods = ["alipay", "wxpay"]

                # ========== 读取支付方式的完整配置信息 ==========
                # 调用 _read_payment_methods_config() 从 payment_methods.json 读取
                # 该文件包含所有支付方式的详细配置（名称、SVG图标、颜色等）
                payment_methods = _read_payment_methods_config()

                # 记录日志
                logging.info(
                    f"[管理员配置] 读取支付方式配置 - 启用: {enabled_methods}, "
                    f"总数: {len(payment_methods)}"
                )

                # 构造返回数据
                # 包含当前启用的支付方式、所有支付方式列表和完整配置
                return jsonify({
                    "success": True,
                    "config": {
                        "enabled_payment_methods": enabled_methods,
                        "all_payment_methods": [
                            {"code": code, "name": name}
                            for code, name in all_methods.items()
                        ]
                    },
                    "payment_methods": payment_methods  # 添加完整的支付方式配置
                })

            elif request.method == "PUT":
                # ========== 处理PUT请求：更新配置 ==========

                # 获取请求数据
                data = request.get_json() or {}

                # 提取要启用的支付方式列表
                new_methods = data.get("enabled_payment_methods", [])

                # 验证参数
                if not isinstance(new_methods, list):
                    return jsonify({
                        "success": False,
                        "message": "enabled_payment_methods必须是数组"
                    }), 400

                # 验证是否至少启用一种支付方式
                if not new_methods:
                    return jsonify({
                        "success": False,
                        "message": "至少需要启用一种支付方式"
                    }), 400

                # === 改造：验证每个支付方式是否在 payment_methods_config 中定义 ===

                # 读取当前配置（用于后续保存 enabled_payment_methods）
                config = configparser.ConfigParser()
                config.read("config.ini", encoding="utf-8")

                # 从 payment_methods.json 文件获取所有已定义的支付方式
                # 调用 _read_payment_methods_config() 函数，该函数会自动处理异常情况
                methods_config = _read_payment_methods_config()
                # 获取所有已定义的支付方式代码（字典的键）
                available_methods = set(methods_config.keys())

                # 验证每个支付方式是否已定义
                invalid_methods = [
                    m for m in new_methods if m not in available_methods]
                if invalid_methods:
                    return jsonify({
                        "success": False,
                        "message": f"以下支付方式未定义，请先在支付方式管理中添加：{', '.join(invalid_methods)}"
                    }), 400

                # 获取旧的配置（用于日志记录）
                old_methods_str = config.get(
                    "Rainbow_YiPay",
                    "enabled_payment_methods",
                    fallback="alipay,wxpay"
                )

                # 更新配置
                # 将列表转换为逗号分隔的字符串
                new_methods_str = ",".join(new_methods)

                # 确保配置节存在
                if not config.has_section("Rainbow_YiPay"):
                    config.add_section("Rainbow_YiPay")

                # 设置新的配置值
                config.set("Rainbow_YiPay",
                           "enabled_payment_methods", new_methods_str)

                # 保存配置文件
                # 使用 _write_config_with_comments() 函数保持注释
                _write_config_with_comments(config, "config.ini")

                # 记录信息日志：配置已更新
                logging.info(
                    f"[支付配置] 管理员更新支付方式配置 - "
                    f"操作者: {g.user}, 旧配置: {old_methods_str}, 新配置: {new_methods_str}"
                )

                # ========== 写入支付操作日志（配置修改） ==========
                # 记录管理员修改支付方式配置的操作，用于审计和追溯
                # 支付方式配置的修改会直接影响用户可用的支付选项，属于敏感操作
                _write_payment_log(
                    user_id=g.user,                     # 操作管理员的用户名
                    order_id="",                        # 配置操作无订单号，使用空字符串
                    action="admin_update_payment_config",  # 操作类型：管理员更新支付配置
                    log_data={
                        # 配置变更信息
                        "old_config": old_methods_str,           # 修改前的配置
                        "new_config": new_methods_str,           # 修改后的配置
                        "enabled_methods": new_methods,          # 启用的支付方式列表
                        # 操作结果
                        "success": True,                         # 操作成功
                        "message": "支付方式配置更新成功"         # 操作消息
                    }
                )

                # 构造中文名称列表用于返回消息
                # 从 payment_methods_config 中获取名称
                method_names = []
                for m in new_methods:
                    if m in methods_config:
                        method_names.append(methods_config[m].get('name', m))
                    elif m in all_methods:
                        method_names.append(all_methods[m])
                    else:
                        method_names.append(m)
                method_names_str = "、".join(method_names)

                # 返回成功响应
                return jsonify({
                    "success": True,
                    "message": f"支付方式配置已更新：{method_names_str}"
                })

        except Exception as e:
            # 捕获所有异常
            logging.error(f"[支付配置] 管理支付配置接口异常: {str(e)}")
            logging.error(traceback.format_exc())
            return jsonify({
                "success": False,
                "message": f"操作失败：{str(e)}"
            }), 500

    @app.route("/api/admin/payment_methods", methods=["POST"])
    @login_required
    def add_payment_method():
        """
        添加新的支付方式接口（管理员专用）

        请求方法：POST
        权限要求：modify_config权限

        请求参数（JSON格式）：
            - code (str): 支付方式代码（必填），例如：alipay, wxpay
            - name (str): 显示名称（必填），例如：支付宝支付
            - icon (str): Logo类型（必填），可选值：svg, image
            - svg (str): SVG代码（当icon为svg时必填）
            - image (str): 图片URL（当icon为image时必填）
            - description (str): 描述信息（可选）
            - borderColor (str): 边框颜色CSS类（可选），例如：hover:border-sky-500
            - textColor (str): 文字颜色CSS类（可选），例如：text-sky-600

        返回数据（JSON格式）：
            - success (bool): 是否成功
            - message (str): 操作结果信息

        功能说明：
        - 将新的支付方式添加到 payment_methods_config（JSON配置）
        - 支付方式代码必须唯一，不能与现有支付方式重复
        - 配置立即保存到 config.ini 文件
        """
        try:
            # === 权限检查 ===
            # 需要 modify_config 权限才能添加支付方式
            if not auth_system.check_permission(g.user, "modify_config"):
                return jsonify({
                    "success": False,
                    "message": "权限不足，需要修改配置权限（modify_config）"
                }), 403

            # === 获取并验证请求数据 ===
            data = request.get_json() or {}

            # 验证必填字段：支付方式代码
            code = data.get("code", "").strip()
            if not code:
                return jsonify({
                    "success": False,
                    "message": "支付方式代码不能为空"
                }), 400

            # 验证代码格式：只允许字母、数字和下划线
            # import re
            if not re.match(r'^[a-zA-Z0-9_]+$', code):
                return jsonify({
                    "success": False,
                    "message": "支付方式代码只能包含字母、数字和下划线"
                }), 400

            # 验证必填字段：显示名称
            name = data.get("name", "").strip()
            if not name:
                return jsonify({
                    "success": False,
                    "message": "显示名称不能为空"
                }), 400

            # 验证必填字段：Logo类型
            icon = data.get("icon", "").strip()
            if icon not in ["svg", "image"]:
                return jsonify({
                    "success": False,
                    "message": "Logo类型必须是 svg 或 image"
                }), 400

            # 验证Logo内容
            svg = data.get("svg", "").strip()
            image = data.get("image", "").strip()

            if icon == "svg" and not svg:
                return jsonify({
                    "success": False,
                    "message": "选择SVG类型时，SVG代码不能为空"
                }), 400

            if icon == "image" and not image:
                return jsonify({
                    "success": False,
                    "message": "选择图片类型时，图片URL不能为空"
                }), 400

            # 获取可选字段
            description = data.get("description", "").strip()
            border_color = data.get(
                "borderColor", "hover:border-sky-500").strip()
            text_color = data.get("textColor", "text-sky-600").strip()

            # === 读取当前配置 ===
            # 从 payment_methods.json 文件读取现有的支付方式配置
            # _read_payment_methods_config() 会自动处理文件不存在、格式错误等情况
            methods_config = _read_payment_methods_config()

            # === 检查支付方式代码是否已存在 ===
            # 遍历已有的支付方式字典，检查新代码是否与现有代码冲突
            if code in methods_config:
                # 代码已存在，返回错误提示
                return jsonify({
                    "success": False,
                    "message": f"支付方式代码 '{code}' 已存在，请使用其他代码或编辑现有支付方式"
                }), 400

            # === 构建新支付方式配置 ===
            # 创建一个字典，包含新支付方式的所有配置信息
            new_method = {
                "name": name,  # 支付方式的显示名称
                "icon": icon,  # 图标类型（svg 或 image）
                "svg": svg if icon == "svg" else "",  # 如果使用SVG图标，保存SVG代码
                "image": image if icon == "image" else "",  # 如果使用图片，保存图片URL
                "description": description,  # 支付方式描述
                "borderColor": border_color,  # 边框颜色CSS类
                "textColor": text_color  # 文字颜色CSS类
            }

            # 将新支付方式添加到配置字典中
            # 使用支付方式代码作为键，配置信息作为值
            methods_config[code] = new_method

            # === 保存配置 ===
            # 调用 _write_payment_methods_config() 函数将更新后的配置写入 JSON 文件
            # 此函数会自动处理文件写入、格式化等操作
            _write_payment_methods_config(methods_config)

            # === 记录日志 ===
            logging.info(
                f"[支付方式管理] 管理员添加新支付方式 - "
                f"操作者: {g.user}, 代码: {code}, 名称: {name}"
            )

            # 返回成功响应
            return jsonify({
                "success": True,
                "message": f"支付方式 '{name}' 已成功添加"
            })

        except Exception as e:
            # 捕获所有异常
            logging.error(f"[支付方式管理] 添加支付方式失败: {str(e)}")
            logging.error(traceback.format_exc())
            return jsonify({
                "success": False,
                "message": f"添加失败：{str(e)}"
            }), 500

    @app.route("/api/admin/payment_methods/<code>", methods=["PUT", "DELETE"])
    @login_required
    def manage_payment_method(code):
        """
        更新或删除支付方式接口（管理员专用）

        请求方法：PUT（更新）、DELETE（删除）
        权限要求：modify_config权限

        URL参数：
            - code (str): 支付方式代码

        PUT请求参数（JSON格式）：
            - name (str): 显示名称（必填）
            - icon (str): Logo类型（必填），可选值：svg, image
            - svg (str): SVG代码（当icon为svg时必填）
            - image (str): 图片URL（当icon为image时必填）
            - description (str): 描述信息（可选）
            - borderColor (str): 边框颜色CSS类（可选）
            - textColor (str): 文字颜色CSS类（可选）

        返回数据（JSON格式）：
            - success (bool): 是否成功
            - message (str): 操作结果信息
        """
        try:
            # === 权限检查 ===
            if not auth_system.check_permission(g.user, "modify_config"):
                return jsonify({
                    "success": False,
                    "message": "权限不足，需要修改配置权限（modify_config）"
                }), 403

            # === 读取当前配置 ===
            # 从 payment_methods.json 文件读取现有的支付方式配置
            # _read_payment_methods_config() 会自动处理文件不存在、格式错误等情况
            methods_config = _read_payment_methods_config()

            # === 检查支付方式是否存在 ===
            # 检查要操作的支付方式代码是否在配置字典中
            if code not in methods_config:
                # 支付方式不存在，返回404错误
                return jsonify({
                    "success": False,
                    "message": f"支付方式 '{code}' 不存在"
                }), 404

            if request.method == "PUT":
                # ========== 处理PUT请求：更新支付方式 ==========

                # 获取并验证请求数据
                data = request.get_json() or {}

                # 验证必填字段：显示名称
                name = data.get("name", "").strip()
                if not name:
                    return jsonify({
                        "success": False,
                        "message": "显示名称不能为空"
                    }), 400

                # 验证必填字段：Logo类型
                icon = data.get("icon", "").strip()
                if icon not in ["svg", "image"]:
                    return jsonify({
                        "success": False,
                        "message": "Logo类型必须是 svg 或 image"
                    }), 400

                # 验证Logo内容
                svg = data.get("svg", "").strip()
                image = data.get("image", "").strip()

                if icon == "svg" and not svg:
                    return jsonify({
                        "success": False,
                        "message": "选择SVG类型时，SVG代码不能为空"
                    }), 400

                if icon == "image" and not image:
                    return jsonify({
                        "success": False,
                        "message": "选择图片类型时，图片URL不能为空"
                    }), 400

                # 获取可选字段
                description = data.get("description", "").strip()
                border_color = data.get(
                    "borderColor", "hover:border-sky-500").strip()
                text_color = data.get("textColor", "text-sky-600").strip()

                # 更新支付方式配置
                # 使用提供的新值更新指定支付方式的所有配置项
                methods_config[code] = {
                    "name": name,  # 更新显示名称
                    "icon": icon,  # 更新图标类型
                    "svg": svg if icon == "svg" else "",  # 更新SVG代码（如果适用）
                    "image": image if icon == "image" else "",  # 更新图片URL（如果适用）
                    "description": description,  # 更新描述信息
                    "borderColor": border_color,  # 更新边框颜色
                    "textColor": text_color  # 更新文字颜色
                }

                # 保存配置到 JSON 文件
                # 调用 _write_payment_methods_config() 函数写入文件
                _write_payment_methods_config(methods_config)

                # 记录日志
                logging.info(
                    f"[支付方式管理] 管理员更新支付方式 - "
                    f"操作者: {g.user}, 代码: {code}, 名称: {name}"
                )

                return jsonify({
                    "success": True,
                    "message": f"支付方式 '{name}' 已成功更新"
                })

            elif request.method == "DELETE":
                # ========== 处理DELETE请求：删除支付方式 ==========

                # 获取支付方式名称（用于日志和返回消息）
                # 如果配置中有name字段则使用，否则使用代码作为名称
                method_name = methods_config[code].get("name", code)

                # 从配置字典中删除该支付方式
                # 使用 del 关键字删除指定键值对
                del methods_config[code]

                # 保存更新后的配置到 JSON 文件
                # 调用 _write_payment_methods_config() 函数写入文件
                _write_payment_methods_config(methods_config)

                # 同时从 enabled_payment_methods 中移除该支付方式
                # 避免启用列表中包含已删除的支付方式
                # 这需要读取和修改 config.ini 文件
                config = configparser.ConfigParser()
                config.read("config.ini", encoding="utf-8")

                # 读取当前启用的支付方式列表
                enabled_methods_str = config.get(
                    "Rainbow_YiPay",
                    "enabled_payment_methods",
                    fallback=""
                )
                # 将逗号分隔的字符串转换为列表，去除空白
                enabled_methods = [
                    m.strip() for m in enabled_methods_str.split(",") if m.strip()
                ]

                # 如果启用列表中包含该支付方式，移除它
                if code in enabled_methods:
                    enabled_methods.remove(code)  # 从列表中删除
                    new_enabled_str = ",".join(enabled_methods)  # 重新组合为字符串
                    # 确保配置节存在
                    if not config.has_section("Rainbow_YiPay"):
                        config.add_section("Rainbow_YiPay")
                    # 更新配置项
                    config.set("Rainbow_YiPay",
                               "enabled_payment_methods", new_enabled_str)
                    # 保存配置文件（保持注释）
                    _write_config_with_comments(config, "config.ini")

                # 记录日志
                logging.info(
                    f"[支付方式管理] 管理员删除支付方式 - "
                    f"操作者: {g.user}, 代码: {code}, 名称: {method_name}"
                )

                return jsonify({
                    "success": True,
                    "message": f"支付方式 '{method_name}' 已成功删除"
                })

        except Exception as e:
            # 捕获所有异常
            logging.error(f"[支付方式管理] 管理支付方式失败: {str(e)}")
            logging.error(traceback.format_exc())
            return jsonify({
                "success": False,
                "message": f"操作失败：{str(e)}"
            }), 500

    @app.route("/api/admin/pricing_config", methods=["GET", "PUT"])
    @login_required  # 只需要登录即可，细粒度权限在函数内部检查
    def admin_pricing_config():
        """
        获取或更新价格配置接口（管理员专用）

        请求方法：GET（获取配置）、PUT（更新配置）
        权限要求：modify_config权限

        GET请求 - 获取当前价格配置：
        返回数据（JSON格式）：
            - success (bool): 是否成功
            - config (dict): 当前价格配置
                - require_payment (bool): 是否需要付费
                - per_run_cost (float): 单次跑步费用（元）
                - default_available_runs (int): 新用户默认免费次数

        PUT请求 - 更新价格配置：
        请求参数（JSON格式）：
            - require_payment (bool): 是否需要付费
            - per_run_cost (float): 单次跑步费用（元）
            - default_available_runs (int): 新用户默认免费次数

        返回数据（JSON格式）：
            - success (bool): 是否成功
            - message (str): 操作结果信息

        功能说明：
        这个接口允许管理员动态配置系统的价格策略，包括是否启用付费模式、单次费用和新用户免费次数。
        配置会立即生效，影响后续创建的所有用户和订单。

        使用场景：
        - 管理员在后台管理面板配置价格策略
        - 根据运营策略调整费用标准
        - 控制新用户的免费试用次数

        安全措施：
        - 需要modify_config权限
        - 验证输入参数的有效性
        - 记录配置变更日志
        """
        try:
            # 检查细粒度权限：修改配置权限
            # modify_config 权限允许修改价格配置
            # 价格配置影响系统的收费模式和用户权益，需要谨慎管理
            if not auth_system.check_permission(g.user, "modify_config"):
                return jsonify({"success": False, "message": "权限不足，需要修改配置权限（modify_config）"}), 403

            if request.method == "GET":
                # ========== 处理GET请求：获取当前配置 ==========

                # 读取配置文件
                # 使用 configparser 从 config.ini 文件读取配置项
                config = configparser.ConfigParser()
                config.read("config.ini", encoding="utf-8")

                # 从 Payment_Settings 节读取价格相关配置
                # 使用 fallback 参数提供默认值，确保即使配置文件缺失也能正常工作

                # 读取是否需要付费的配置（布尔值）
                # getboolean() 方法会自动将字符串 "true"/"false" 转换为 Python 的 bool 类型
                require_payment = config.getboolean(
                    "Payment_Settings",
                    "require_payment",
                    fallback=True  # 默认值：需要付费
                )

                # 读取单次跑步费用的配置（浮点数）
                # getfloat() 方法会自动将字符串转换为 Python 的 float 类型
                per_run_cost = config.getfloat(
                    "Payment_Settings",
                    "single_run_cost",  # 注意：配置文件中的键名是 single_run_cost
                    fallback=1.0  # 默认值：1.0元/次
                )

                # 读取新用户默认免费次数的配置（整数）
                # getint() 方法会自动将字符串转换为 Python 的 int 类型
                default_available_runs = config.getint(
                    "Payment_Settings",
                    "default_available_runs",
                    fallback=10  # 默认值：10次
                )

                # ========== [修复] 读取UI显示配置字段 ==========
                # 这4个配置项之前在GET响应中缺失，导致前端无法正确加载配置

                # 从 Profile_Display 节读取"是否在个人资料页显示剩余次数"配置（布尔值）
                # 用于控制用户个人资料页面是否显示剩余跑步次数
                show_available_runs = config.getboolean(
                    "Profile_Display",
                    "show_available_runs",
                    fallback=True  # 默认值：显示
                )

                # 从 Profile_Display 节读取"剩余次数显示格式"配置（字符串）
                # {available_runs} 是占位符，会被替换为实际的剩余次数
                available_runs_format = config.get(
                    "Profile_Display",
                    "available_runs_format",
                    fallback="剩余免费次数：{available_runs} 次"  # 默认格式模板
                )

                # 从 Registration_Display 节读取"是否在注册页显示免费次数提示"配置（布尔值）
                # 用于控制用户注册页面是否显示免费次数提示信息
                show_available_runs_on_register = config.getboolean(
                    "Registration_Display",
                    "show_available_runs_on_register",
                    fallback=True  # 默认值：显示
                )

                # 从 Registration_Display 节读取"注册页提示文本"配置（字符串）
                # {available_runs} 是占位符，会被替换为实际的免费次数
                register_available_runs_hint = config.get(
                    "Registration_Display",
                    "register_available_runs_hint",
                    fallback="注册即可得 {available_runs} 次校园跑"  # 默认提示文本
                )

                # 构造返回数据
                # 将读取到的配置以 JSON 格式返回给前端
                # [修复] 添加了4个UI显示配置字段，确保前端能正确加载所有配置
                return jsonify({
                    "success": True,
                    "config": {
                        # 基础支付配置
                        "require_payment": require_payment,  # 是否需要付费
                        "per_run_cost": per_run_cost,  # 单次跑步费用
                        "default_available_runs": default_available_runs,  # 新用户默认免费次数
                        # [修复新增] UI显示配置 - Profile_Display 节
                        "show_available_runs": show_available_runs,  # 是否在个人资料页显示剩余次数
                        "available_runs_format": available_runs_format,  # 剩余次数显示格式模板
                        # [修复新增] UI显示配置 - Registration_Display 节
                        "show_available_runs_on_register": show_available_runs_on_register,  # 是否在注册页显示提示
                        "register_available_runs_hint": register_available_runs_hint  # 注册页提示文本模板
                    }
                })

            elif request.method == "PUT":
                # ========== 处理PUT请求：更新配置 ==========

                # 获取请求数据
                # 从前端传来的 JSON 数据中提取配置参数
                data = request.get_json() or {}

                # 提取新的配置值
                # 使用 .get() 方法获取参数，如果参数不存在则使用当前配置值作为默认值

                # 读取当前配置作为默认值
                config = configparser.ConfigParser()
                config.read("config.ini", encoding="utf-8")

                # 获取新的 require_payment 值（布尔类型）
                new_require_payment = data.get(
                    "require_payment",
                    config.getboolean("Payment_Settings",
                                      "require_payment", fallback=True)
                )

                # 获取新的 per_run_cost 值（浮点类型）
                new_per_run_cost = data.get(
                    "per_run_cost",
                    config.getfloat("Payment_Settings",
                                    "single_run_cost", fallback=1.0)
                )

                # 获取新的 default_available_runs 值（整数类型）
                new_default_available_runs = data.get(
                    "default_available_runs",
                    config.getint("Payment_Settings",
                                  "default_available_runs", fallback=10)
                )

                # ========== 获取UI显示配置的值 ==========

                # 获取新的 show_available_runs 值（布尔类型）
                # 控制是否在个人资料页面显示剩余次数
                new_show_available_runs = data.get(
                    "show_available_runs",
                    config.getboolean("Profile_Display",
                                      "show_available_runs", fallback=True)
                )

                # 获取新的 available_runs_format 值（字符串类型）
                # 剩余次数的显示格式模板
                new_available_runs_format = data.get(
                    "available_runs_format",
                    config.get("Profile_Display", "available_runs_format",
                               fallback="剩余免费次数：{available_runs} 次")
                )

                # 获取新的 show_available_runs_on_register 值（布尔类型）
                # 控制是否在注册页面显示免费次数提示
                new_show_available_runs_on_register = data.get(
                    "show_available_runs_on_register",
                    config.getboolean(
                        "Registration_Display", "show_available_runs_on_register", fallback=True)
                )

                # 获取新的 register_available_runs_hint 值（字符串类型）
                # 注册页面的免费次数提示文本模板
                new_register_available_runs_hint = data.get(
                    "register_available_runs_hint",
                    config.get("Registration_Display", "register_available_runs_hint",
                               fallback="注册即可得 {available_runs} 次校园跑")
                )

                # ========== 验证参数的有效性 ==========

                # 验证 require_payment 是否为布尔类型
                if not isinstance(new_require_payment, bool):
                    return jsonify({
                        "success": False,
                        "message": "require_payment 必须是布尔值（true/false）"
                    }), 400

                # 验证 per_run_cost 是否为数字类型
                # 检查是否为 int 或 float 类型
                if not isinstance(new_per_run_cost, (int, float)):
                    return jsonify({
                        "success": False,
                        "message": "per_run_cost 必须是数字"
                    }), 400

                # 验证 per_run_cost 是否为非负数
                # 费用不能为负数，但可以为 0（表示免费）
                if new_per_run_cost < 0:
                    return jsonify({
                        "success": False,
                        "message": "per_run_cost 不能为负数"
                    }), 400

                # 验证 default_available_runs 是否为整数类型
                if not isinstance(new_default_available_runs, int):
                    return jsonify({
                        "success": False,
                        "message": "default_available_runs 必须是整数"
                    }), 400

                # 验证 default_available_runs 是否为非负数
                # 免费次数不能为负数，但可以为 0（表示新用户无免费次数）
                if new_default_available_runs < 0:
                    return jsonify({
                        "success": False,
                        "message": "default_available_runs 不能为负数"
                    }), 400

                # ========== 验证UI显示配置字段的有效性 ==========

                # 验证 show_available_runs 是否为布尔类型
                if not isinstance(new_show_available_runs, bool):
                    return jsonify({
                        "success": False,
                        "message": "show_available_runs 必须是布尔值（true/false）"
                    }), 400

                # 验证 available_runs_format 是否为字符串类型
                if not isinstance(new_available_runs_format, str):
                    return jsonify({
                        "success": False,
                        "message": "available_runs_format 必须是字符串"
                    }), 400

                # 验证 available_runs_format 不能为空
                if not new_available_runs_format.strip():
                    return jsonify({
                        "success": False,
                        "message": "available_runs_format 不能为空"
                    }), 400

                # 验证 show_available_runs_on_register 是否为布尔类型
                if not isinstance(new_show_available_runs_on_register, bool):
                    return jsonify({
                        "success": False,
                        "message": "show_available_runs_on_register 必须是布尔值（true/false）"
                    }), 400

                # 验证 register_available_runs_hint 是否为字符串类型
                if not isinstance(new_register_available_runs_hint, str):
                    return jsonify({
                        "success": False,
                        "message": "register_available_runs_hint 必须是字符串"
                    }), 400

                # 验证 register_available_runs_hint 不能为空
                if not new_register_available_runs_hint.strip():
                    return jsonify({
                        "success": False,
                        "message": "register_available_runs_hint 不能为空"
                    }), 400

                # ========== 保存旧配置用于日志记录 ==========
                old_require_payment = config.getboolean(
                    "Payment_Settings", "require_payment", fallback=True)
                old_per_run_cost = config.getfloat(
                    "Payment_Settings", "single_run_cost", fallback=1.0)
                old_default_available_runs = config.getint(
                    "Payment_Settings", "default_available_runs", fallback=10)

                # 保存UI显示配置的旧值，用于日志记录
                old_show_available_runs = config.getboolean(
                    "Profile_Display", "show_available_runs", fallback=True)
                old_available_runs_format = config.get(
                    "Profile_Display", "available_runs_format", fallback="剩余免费次数：{available_runs} 次")
                old_show_available_runs_on_register = config.getboolean(
                    "Registration_Display", "show_available_runs_on_register", fallback=True)
                old_register_available_runs_hint = config.get(
                    "Registration_Display", "register_available_runs_hint", fallback="注册即可得 {available_runs} 次校园跑")

                # ========== 更新配置 ==========

                # 确保 Payment_Settings 配置节存在
                # 如果配置节不存在，则创建它
                if not config.has_section("Payment_Settings"):
                    config.add_section("Payment_Settings")

                # 设置新的配置值
                # 注意：configparser 保存时会将所有值转换为字符串
                # 布尔值转换为 "true"/"false"，数字转换为字符串形式
                config.set("Payment_Settings", "require_payment",
                           str(new_require_payment).lower())
                config.set("Payment_Settings", "single_run_cost",
                           str(new_per_run_cost))
                config.set("Payment_Settings", "default_available_runs",
                           str(new_default_available_runs))

                # ========== 更新UI显示配置 ==========

                # 确保 Profile_Display 配置节存在
                if not config.has_section("Profile_Display"):
                    config.add_section("Profile_Display")

                # 设置个人资料页显示配置
                # show_available_runs: 是否显示剩余次数
                config.set("Profile_Display", "show_available_runs",
                           str(new_show_available_runs).lower())
                # available_runs_format: 剩余次数的显示格式模板
                config.set("Profile_Display", "available_runs_format",
                           new_available_runs_format)

                # 确保 Registration_Display 配置节存在
                if not config.has_section("Registration_Display"):
                    config.add_section("Registration_Display")

                # 设置注册页面显示配置
                # show_available_runs_on_register: 是否在注册页显示提示
                config.set("Registration_Display", "show_available_runs_on_register", str(
                    new_show_available_runs_on_register).lower())
                # register_available_runs_hint: 注册页提示文本模板
                config.set("Registration_Display", "register_available_runs_hint",
                           new_register_available_runs_hint)

                # 保存配置文件
                # 使用 _write_config_with_comments() 函数保持配置文件中的注释
                # 这样可以避免覆盖配置文件时丢失注释信息
                _write_config_with_comments(config, "config.ini")

                # ========== 记录信息日志 ==========
                # 记录配置变更，便于审计和问题追踪
                logging.info(
                    f"[价格配置] 管理员更新价格配置 - "
                    f"操作者: {g.user}, "
                    f"require_payment: {old_require_payment} -> {new_require_payment}, "
                    f"per_run_cost: {old_per_run_cost} -> {new_per_run_cost}, "
                    f"default_available_runs: {old_default_available_runs} -> {new_default_available_runs}, "
                    f"show_available_runs: {old_show_available_runs} -> {new_show_available_runs}, "
                    f"available_runs_format: '{old_available_runs_format}' -> '{new_available_runs_format}', "
                    f"show_available_runs_on_register: {old_show_available_runs_on_register} -> {new_show_available_runs_on_register}, "
                    f"register_available_runs_hint: '{old_register_available_runs_hint}' -> '{new_register_available_runs_hint}'"
                )

                # ========== 写入支付操作日志（价格配置修改） ==========
                # 记录管理员修改价格配置的操作，用于审计和追溯
                # 价格配置的修改会直接影响所有用户的付费行为和免费次数
                # 这是敏感的业务配置，必须详细记录每次修改
                _write_payment_log(
                    user_id=g.user,                          # 操作管理员的用户名
                    order_id="",                             # 配置操作无订单号，使用空字符串
                    action="admin_update_pricing_config",    # 操作类型：管理员更新价格配置
                    log_data={
                        # 支付设置变更详情
                        "require_payment": {                 # 是否需要付费
                            "old": old_require_payment,
                            "new": new_require_payment
                        },
                        "per_run_cost": {                    # 单次跑步费用
                            "old": old_per_run_cost,
                            "new": new_per_run_cost
                        },
                        "default_available_runs": {          # 新用户默认免费次数
                            "old": old_default_available_runs,
                            "new": new_default_available_runs
                        },
                        # UI显示配置变更详情
                        "show_available_runs": {             # 是否在个人资料页显示剩余次数
                            "old": old_show_available_runs,
                            "new": new_show_available_runs
                        },
                        "available_runs_format": {           # 剩余次数显示格式
                            "old": old_available_runs_format,
                            "new": new_available_runs_format
                        },
                        "show_available_runs_on_register": {  # 是否在注册页显示提示
                            "old": old_show_available_runs_on_register,
                            "new": new_show_available_runs_on_register
                        },
                        "register_available_runs_hint": {    # 注册页提示文本
                            "old": old_register_available_runs_hint,
                            "new": new_register_available_runs_hint
                        },
                        # 操作结果
                        "success": True,                     # 操作成功
                        "message": "价格配置更新成功"         # 操作消息
                    }
                )

                # ========== 返回成功响应 ==========
                return jsonify({
                    "success": True,
                    "message": "价格配置已成功更新"
                })

        except Exception as e:
            # 捕获所有异常
            # 记录错误日志，包括详细的堆栈跟踪信息
            logging.error(f"[价格配置] 管理价格配置接口异常: {str(e)}")
            logging.error(traceback.format_exc())
            # 返回 500 错误响应
            return jsonify({
                "success": False,
                "message": f"操作失败：{str(e)}"
            }), 500

    @app.route("/api/admin/yipay_config", methods=["GET", "PUT"])
    @login_required  # 只需要登录即可，细粒度权限在函数内部检查
    def admin_yipay_config():
        """
        获取或更新易支付配置接口（管理员专用）

        请求方法：GET（获取配置）、PUT（更新配置）
        权限要求：modify_config权限（必须）+ 超级管理员或管理员用户组

        GET请求 - 获取当前易支付配置：
        返回数据（JSON格式）：
            - success (bool): 是否成功
            - config (dict): 当前易支付配置
                - host (str): 易支付接口域名
                - pid (str): 商户ID
                - key (str): 商户密钥（完整显示，不脱敏）
                - enabled_payment_methods (str): 启用的支付方式
                - payment_method (str): 支付接口类型

        PUT请求 - 更新易支付配置：
        请求参数（JSON格式）：
            - host (str): 易支付接口域名
            - pid (str): 商户ID
            - key (str): 商户密钥
            - enabled_payment_methods (str): 启用的支付方式
            - payment_method (str): 支付接口类型

        返回数据（JSON格式）：
            - success (bool): 是否成功
            - message (str): 操作结果信息

        功能说明：
        这个接口允许管理员动态配置易支付平台的接入参数，无需重启服务器。
        配置会立即生效，影响后续创建的所有订单。

        使用场景：
        - 管理员在后台管理面板配置易支付参数
        - 更换易支付平台或商户账号
        - 调整支付接口类型和启用的支付方式

        安全措施（已强化）：
        - 需要modify_config权限（第一层权限检查）
        - 必须是管理员（admin）或超级管理员（super_admin）用户组（第二层权限检查）
        - 商户密钥完整显示，不脱敏（便于配置管理）
        - 验证输入参数的有效性
        - 记录配置变更日志（包含操作者信息）
        - IP地址记录和审计日志
        """
        try:
            # ========== 第一层权限检查：细粒度权限 ==========
            # 检查用户是否具有 modify_config 权限
            # modify_config 权限允许修改系统配置，包括易支付配置
            # 易支付配置包含敏感信息（商户密钥），需要严格的权限控制
            ip_for_pay = request.environ.get(
                "REMOTE_ADDR") or request.remote_addr
            if not auth_system.check_permission(g.user, "modify_config"):
                # 记录权限不足的访问尝试
                logging.warning(
                    f"[易支付配置-权限拒绝] 用户 {g.user} 尝试访问易支付配置接口，但缺少 modify_config 权限 - "
                    f"IP: {ip_for_pay}, 方法: {request.method}"
                )
                return jsonify({"success": False, "message": "权限不足，需要修改配置权限（modify_config）"}), 403

            # ========== 第二层权限检查：用户组验证（强化安全性）==========
            # 即使用户具有 modify_config 权限，也必须是管理员或超级管理员用户组
            # 这样可以防止普通用户通过自定义权限配置访问敏感的易支付配置
            # 商户密钥是高度敏感的信息，只有真正的管理员才能查看和修改
            user_data = auth_system.get_user_details(g.user)
            if not user_data:
                logging.error(f"[易支付配置-权限拒绝] 无法获取用户 {g.user} 的数据")
                return jsonify({"success": False, "message": "用户数据异常"}), 500

            user_group = user_data.get("group", "user")

            # 只允许 admin（管理员）和 super_admin（超级管理员）访问
            # 这是第二层安全防护，确保只有管理员组成员才能操作易支付配置
            if user_group not in ["admin", "super_admin"]:
                logging.warning(
                    f"[易支付配置-权限拒绝] 用户 {g.user}（用户组：{user_group}）尝试访问易支付配置接口，"
                    f"但不是管理员组成员 - IP: {ip_for_pay}, 方法: {request.method}"
                )
                return jsonify({
                    "success": False,
                    "message": "权限不足，只有管理员和超级管理员才能管理易支付配置"
                }), 403

            # 记录合法的访问（用于审计）
            logging.info(
                f"[易支付配置-访问] 管理员 {g.user}（用户组：{user_group}）正在访问易支付配置接口 - "
                f"IP: {ip_for_pay}, 方法: {request.method}"
            )

            if request.method == "GET":
                # ========== 处理GET请求：获取当前配置 ==========

                # 读取配置文件
                # 使用 configparser 从 config.ini 文件读取配置项
                config = configparser.ConfigParser()
                config.read("config.ini", encoding="utf-8")

                # 从 Rainbow_YiPay 节读取易支付相关配置
                # 使用 fallback 参数提供默认值，确保即使配置文件缺失也能正常工作

                # 读取易支付接口域名
                host = config.get(
                    "Rainbow_YiPay",
                    "host",
                    fallback=""  # 默认值：空字符串
                )

                # 读取商户ID（PID）
                pid = config.get(
                    "Rainbow_YiPay",
                    "pid",
                    fallback=""
                )

                # 读取商户密钥（KEY）
                # 注意：密钥是敏感信息，但由于已进行双重权限验证（modify_config权限 + 管理员用户组）
                # 因此直接返回完整密钥，便于管理员进行配置管理
                # 安全性由权限系统保障：只有真正的管理员才能访问此接口
                key = config.get(
                    "Rainbow_YiPay",
                    "key",
                    fallback=""
                )

                # 读取启用的支付方式
                # 这是一个逗号分隔的字符串，例如 "alipay,wxpay"
                enabled_payment_methods = config.get(
                    "Rainbow_YiPay",
                    "enabled_payment_methods",
                    fallback="alipay,wxpay"  # 默认值：启用支付宝和微信支付
                )

                # # 读取支付接口类型
                # # 可选值：web、jump、jsapi、app、scan、applet
                # payment_method = "web"

                product_id = config.get(
                    "Rainbow_YiPay", "product_id", fallback="1001"
                )

                # 读取app_host（应用域名地址）
                # app_host用于自动设置回调地址的域名前缀
                app_host = config.get(
                    "Rainbow_YiPay",
                    "app_host",
                    fallback=""  # 默认值：空字符串
                )

                # 读取pubc_key（平台公钥）
                # pubc_key是彩虹易支付平台的RSA公钥，用于验证支付回调通知
                pubc_key = config.get(
                    "Rainbow_YiPay",
                    "pubc_key",
                    fallback=""  # 默认值：空字符串
                )

                # 读取payment_timeout_minutes（支付超时时间）
                # 单位：秒，表示订单创建后多长时间内未支付视为超时
                payment_timeout_minutes = config.get(
                    "Rainbow_YiPay",
                    "payment_timeout_minutes",
                    fallback="30"  # 默认值：30秒
                )

                # 构造返回数据
                # 将读取到的配置以 JSON 格式返回给前端
                # 注意：返回完整的商户密钥（已通过双重权限验证，安全可控）
                return jsonify({
                    "success": True,
                    "config": {
                        "host": host,
                        "pid": pid,
                        "key": key,  # 完整的商户密钥（不脱敏）
                        "product_id": product_id,  # 返回商品ID
                        "app_host": app_host,  # 返回应用域名地址
                        "pubc_key": pubc_key,  # 返回平台公钥
                        # 返回支付超时时间
                        "payment_timeout_minutes": payment_timeout_minutes,
                        "enabled_payment_methods": enabled_payment_methods,
                        # "payment_method": payment_method
                    }
                })

            elif request.method == "PUT":
                # ========== 处理PUT请求：更新配置 ==========

                # 获取请求数据
                # 从前端传来的 JSON 数据中提取配置参数
                data = request.get_json() or {}

                # 读取当前配置作为默认值
                config = configparser.ConfigParser()
                config.read("config.ini", encoding="utf-8")

                # 提取新的配置值
                # 使用 .get() 方法获取参数，如果参数不存在则使用当前配置值作为默认值

                # 获取新的 host 值
                new_host = data.get(
                    "host",
                    config.get("Rainbow_YiPay", "host", fallback="")
                ).strip()  # 去除首尾空格

                # 获取新的 pid 值
                new_pid = data.get(
                    "pid",
                    config.get("Rainbow_YiPay", "pid", fallback="")
                ).strip()

                # 获取新的 key 值
                # 由于不再对密钥进行脱敏处理，前端传来的密钥就是完整的密钥
                new_key = data.get(
                    "key",
                    config.get("Rainbow_YiPay", "key", fallback="")
                ).strip()

                # 获取新的 enabled_payment_methods 值
                new_enabled_payment_methods = data.get(
                    "enabled_payment_methods",
                    config.get(
                        "Rainbow_YiPay", "enabled_payment_methods", fallback="alipay,wxpay")
                ).strip()

                # # 获取新的 payment_method 值
                # new_payment_method = data.get(
                #     "payment_method",
                #     config.get("Rainbow_YiPay",
                #                "payment_method", fallback="web")
                # ).strip()

                # 获取新的 product_id 值
                new_product_id = data.get(
                    "product_id", config.get(
                        "Rainbow_YiPay", "product_id", fallback="1001")
                ).strip()

                # 获取新的 app_host 值（应用域名地址）
                # app_host用于自动设置回调地址的域名前缀
                # 从请求数据中获取，如果不存在则使用当前配置值，默认为空字符串
                new_app_host = data.get(
                    "app_host",
                    config.get("Rainbow_YiPay", "app_host", fallback="")
                ).strip()

                # 获取新的 pubc_key 值（平台公钥）
                # pubc_key是彩虹易支付平台的RSA公钥，用于验证支付回调通知
                # 从请求数据中获取，如果不存在则使用当前配置值，默认为空字符串
                new_pubc_key = data.get(
                    "pubc_key",
                    config.get("Rainbow_YiPay", "pubc_key", fallback="")
                ).strip()

                # 获取新的 payment_timeout_minutes 值（支付超时时间）
                # 单位：秒，表示订单创建后多长时间内未支付视为超时
                # 从请求数据中获取，如果不存在则使用当前配置值，默认为30秒
                new_payment_timeout_minutes = data.get(
                    "payment_timeout_minutes",
                    config.get("Rainbow_YiPay",
                               "payment_timeout_minutes", fallback="30")
                ).strip()

                # ========== 验证参数的有效性 ==========

                # 验证 host 不能为空
                if not new_host:
                    return jsonify({
                        "success": False,
                        "message": "易支付接口域名不能为空"
                    }), 400

                # 验证 host 必须以 http:// 或 https:// 开头
                if not new_host.startswith(("http://", "https://")):
                    return jsonify({
                        "success": False,
                        "message": "易支付接口域名必须以 http:// 或 https:// 开头"
                    }), 400

                # 验证 pid 不能为空
                if not new_pid:
                    return jsonify({
                        "success": False,
                        "message": "商户ID不能为空"
                    }), 400

                # 验证 key 不能为空
                if not new_key:
                    return jsonify({
                        "success": False,
                        "message": "商户密钥不能为空"
                    }), 400

                # # 验证 payment_method 的有效性
                # # 只允许特定的支付接口类型
                # valid_payment_methods = ["web", "jump",
                #                          "jsapi", "app", "scan", "applet"]
                # if new_payment_method not in valid_payment_methods:
                #     return jsonify({
                #         "success": False,
                #         "message": f"支付接口类型无效，可选值：{', '.join(valid_payment_methods)}"
                #     }), 400

                # 验证 pubc_key 不能为空（必填项）
                # pubc_key是平台公钥，用于验证支付回调通知，必须提供
                if not new_pubc_key:
                    return jsonify({
                        "success": False,
                        "message": "平台公钥不能为空"
                    }), 400

                # 验证 payment_timeout_minutes 的有效性
                # 必须是数字类型且在合理范围内（10-3600秒）
                try:
                    # 尝试将字符串转换为整数
                    timeout_value = int(new_payment_timeout_minutes)
                    # 检查数字范围：10秒到3600秒（1小时）
                    if timeout_value < 10 or timeout_value > 3600:
                        return jsonify({
                            "success": False,
                            "message": "支付超时时间必须在10-3600秒之间"
                        }), 400
                except ValueError:
                    # 如果无法转换为整数，说明不是有效的数字
                    return jsonify({
                        "success": False,
                        "message": "支付超时时间必须是有效的数字"
                    }), 400

                # ========== 保存旧配置用于日志记录 ==========
                # 【重要】在执行 config.set() 之前保存所有旧值
                # 这样才能正确比较新旧值，记录准确的变更日志
                old_host = config.get("Rainbow_YiPay", "host", fallback="")
                old_pid = config.get("Rainbow_YiPay", "pid", fallback="")
                # 保存旧的密钥值，用于后续判断密钥是否被修改
                # 必须在 config.set("Rainbow_YiPay", "key", new_key) 之前获取
                old_key = config.get("Rainbow_YiPay", "key", fallback="")
                old_enabled_payment_methods = config.get(
                    "Rainbow_YiPay", "enabled_payment_methods", fallback="")
                # old_payment_method = config.get(
                #     "Rainbow_YiPay", "payment_method", fallback="")
                # 保存旧的product_id值
                old_product_id = config.get(
                    "Rainbow_YiPay", "product_id", fallback="")
                # 保存旧的app_host值（应用域名地址）
                old_app_host = config.get(
                    "Rainbow_YiPay", "app_host", fallback="")
                # 保存旧的pubc_key值（平台公钥）
                old_pubc_key = config.get(
                    "Rainbow_YiPay", "pubc_key", fallback="")
                # 保存旧的payment_timeout_minutes值（支付超时时间）
                old_payment_timeout_minutes = config.get(
                    "Rainbow_YiPay", "payment_timeout_minutes", fallback="")

                # ========== 更新配置 ==========

                # 确保 Rainbow_YiPay 配置节存在
                # 如果配置节不存在，则创建它
                if not config.has_section("Rainbow_YiPay"):
                    config.add_section("Rainbow_YiPay")

                # 设置新的配置值
                config.set("Rainbow_YiPay", "host", new_host)
                config.set("Rainbow_YiPay", "pid", new_pid)
                config.set("Rainbow_YiPay", "key", new_key)
                config.set("Rainbow_YiPay", "enabled_payment_methods",
                           new_enabled_payment_methods)
                # config.set("Rainbow_YiPay", "payment_method",
                #            new_payment_method)
                config.set("Rainbow_YiPay", "product_id",
                           new_product_id)  # 保存商品ID
                # 设置app_host（应用域名地址）
                config.set("Rainbow_YiPay", "app_host", new_app_host)
                # 设置pubc_key（平台公钥）
                config.set("Rainbow_YiPay", "pubc_key", new_pubc_key)
                # 设置payment_timeout_minutes（支付超时时间）
                config.set("Rainbow_YiPay", "payment_timeout_minutes",
                           new_payment_timeout_minutes)

                # 保存配置文件
                # 使用 _write_config_with_comments() 函数保持配置文件中的注释
                # 这样可以避免覆盖配置文件时丢失注释信息
                _write_config_with_comments(config, "config.ini")

                # ========== 记录信息日志 ==========
                # 记录配置变更，便于审计和问题追踪
                # 注意：不记录完整的密钥和公钥，只记录是否修改了它们
                # 使用 old_key 与 new_key 比较，而不是从已更新的config中读取
                # 因为在此之前已经执行了 config.set("Rainbow_YiPay", "key", new_key)
                # 所以必须使用预先保存的 old_key 变量进行比较
                key_changed = (new_key != old_key)
                # 判断pubc_key是否被修改
                pubc_key_changed = (new_pubc_key != old_pubc_key)
                logging.info(
                    f"[易支付配置] 管理员更新易支付配置 - "
                    f"操作者: {g.user}, "
                    f"host: {old_host} -> {new_host}, "
                    f"pid: {old_pid} -> {new_pid}, "
                    f"key: {'已修改' if key_changed else '未修改'}, "
                    f"product_id: {old_product_id} -> {new_product_id}, "
                    f"app_host: {old_app_host} -> {new_app_host}, "
                    f"pubc_key: {'已修改' if pubc_key_changed else '未修改'}, "
                    f"payment_timeout_minutes: {old_payment_timeout_minutes} -> {new_payment_timeout_minutes}, "
                    f"enabled_payment_methods: {old_enabled_payment_methods} -> {new_enabled_payment_methods}, "
                    # f"payment_method: {old_payment_method} -> {new_payment_method}"
                )

                # ========== 写入支付操作日志（易支付配置修改） ==========
                # 记录管理员修改易支付配置的操作，用于审计和追溯
                # 易支付配置包含敏感的商户密钥和公钥，修改这些配置会直接影响支付功能
                # 必须详细记录每次修改操作，包括修改前后的值，便于问题排查和安全审计
                _write_payment_log(
                    user_id=g.user,                          # 操作管理员的用户名
                    order_id="",                             # 配置操作无订单号，使用空字符串
                    action="admin_update_yipay_config",      # 操作类型：管理员更新易支付配置
                    log_data={
                        # 配置变更详情（记录新旧值对比）
                        "host": {                            # 易支付接口域名
                            "old": old_host,                 # 修改前的值
                            "new": new_host                  # 修改后的值
                        },
                        "pid": {                             # 商户ID
                            "old": old_pid,
                            "new": new_pid
                        },
                        "key_changed": key_changed,          # 商户密钥是否被修改（不记录密钥本身）
                        "product_id": {                      # 商品ID
                            "old": old_product_id,
                            "new": new_product_id
                        },
                        "app_host": {                        # 应用域名地址
                            "old": old_app_host,
                            "new": new_app_host
                        },
                        "pubc_key_changed": pubc_key_changed,  # 平台公钥是否被修改（不记录公钥本身）
                        "payment_timeout_minutes": {         # 支付超时时间
                            "old": old_payment_timeout_minutes,
                            "new": new_payment_timeout_minutes
                        },
                        "enabled_payment_methods": {         # 启用的支付方式
                            "old": old_enabled_payment_methods,
                            "new": new_enabled_payment_methods
                        },
                        # 操作结果
                        "success": True,                     # 操作成功
                        "message": "易支付配置更新成功"       # 操作消息
                    }
                )

                # ========== 返回成功响应 ==========
                return jsonify({
                    "success": True,
                    "message": "易支付配置已成功更新"
                })

        except Exception as e:
            # 捕获所有异常
            # 记录错误日志，包括详细的堆栈跟踪信息
            logging.error(f"[易支付配置] 管理易支付配置接口异常: {str(e)}")
            logging.error(traceback.format_exc())
            # 返回 500 错误响应
            return jsonify({
                "success": False,
                "message": f"操作失败：{str(e)}"
            }), 500

    @app.route("/api/payment_logs", methods=["GET"])
    @login_required
    def user_payment_logs():
        """
        获取当前用户的支付日志列表接口

        功能说明：
        用户查看自己的支付操作日志，自动根据登录状态识别用户身份。
        - 如果是注册用户，使用username作为user_id
        - 如果是游客会话，使用session UUID作为user_id

        请求方法：GET
        权限要求：登录用户（login_required装饰器）

        权限说明：
        1. 如果用户是管理员（admin/super_admin）：可以访问，返回自己的日志
           （管理员查看所有用户日志请使用 /api/admin/payment_logs 接口）
        2. 如果用户不是管理员：
           - 如果 require_payment = true（启用付费）：可以访问，只返回自己的日志
           - 如果 require_payment = false（免费模式）：拒绝访问（返回403错误）

        查询参数（URL参数）：
            - action (str, 可选): 按操作类型筛选
                - "create_order": 创建订单
                - "query_order": 查询订单
                - "payment_success": 支付成功
                - "payment_fail": 支付失败
            - start_date (str, 可选): 开始日期（格式：YYYY-MM-DD）
            - end_date (str, 可选): 结束日期（格式：YYYY-MM-DD）
            - page (int, 可选): 页码，默认1
            - per_page (int, 可选): 每页数量，默认20（最大100）

        返回数据（JSON格式）：
            - success (bool): 是否成功
            - logs (list): 日志列表（按时间倒序）
                每条日志包含：
                - order_id: 订单号
                - action: 操作类型
                - datetime: 操作时间（可读格式）
                - 以及其他操作特定的数据
            - total (int): 符合条件的总日志数
            - page (int): 当前页码
            - per_page (int): 每页数量

        功能说明：
        用户可以查看自己的支付操作日志，支持按操作类型、日期范围筛选和分页。
        日志按时间倒序排列，最新的日志在最前面。

        使用场景：
        - 查看自己的订单历史
        - 追踪支付状态
        - 查询支付问题
        """
        try:
            # ========== 步骤1：获取当前用户信息并检查管理员权限 ==========

            # 获取当前登录用户的用户名
            # g.user 由 @login_required 装饰器设置，保证此时用户已经登录
            current_user = g.user

            # 初始化管理员标志为 False（默认假设用户不是管理员）
            is_admin = False

            # 如果当前用户存在（已登录），检查其是否具有管理员权限
            if current_user:
                # 调用 auth_manager 的 get_user_group() 方法获取用户所属的权限组
                # 返回值可能是："guest"（游客）、"user"（普通用户）、"admin"（管理员）、"super_admin"（超级管理员）
                user_group = auth_system.get_user_group(current_user)

                # 判断用户是否属于管理员组
                # 只有 "admin" 或 "super_admin" 才被认为是管理员
                is_admin = user_group in ["admin", "super_admin"]

                # [调试日志] 记录用户权限检查结果，便于追踪权限问题
                logging.info(
                    f"[用户支付日志] 权限检查 - 用户: {current_user}, "
                    f"组别: {user_group}, 是否管理员: {is_admin}"
                )

            # ========== 步骤2：权限控制检查 ==========
            # 如果用户不是管理员，需要额外检查系统是否启用了付费功能
            # 只有在启用付费功能时，普通用户才被允许查看自己的支付日志
            if not is_admin:
                # 读取配置文件中的 require_payment 配置项
                # getboolean() 方法会自动将字符串 "true"/"false" 转换为 Python 的 bool 类型
                # fallback=True 表示如果配置项不存在，默认值为 True（需要付费）
                config = configparser.ConfigParser()
                config.read("config.ini", encoding="utf-8")
                require_payment = config.getboolean(
                    "Payment_Settings", "require_payment", fallback=True)

                # 如果系统未启用付费功能（免费模式），拒绝普通用户访问
                # 原因：免费模式下，普通用户无需关注支付日志，只有管理员才需要查看历史记录
                if not require_payment:
                    # [安全日志] 记录访问被拒绝的情况，用于安全审计
                    logging.warning(
                        f"[用户支付日志] 访问被拒绝 - 用户 {current_user} 不是管理员且系统未启用付费功能 "
                        f"(require_payment={require_payment})"
                    )

                    # 返回 HTTP 403 Forbidden 错误，表示权限不足
                    # 这是一个标准的权限拒绝响应码
                    return jsonify({
                        "success": False,
                        "message": "当前系统未启用付费功能，普通用户无法访问支付日志"
                    }), 403

                # [调试日志] 记录权限检查通过（普通用户在付费模式下）
                logging.info(
                    f"[用户支付日志] 权限检查通过 - 用户 {current_user} 为普通用户，"
                    f"系统已启用付费功能 (require_payment={require_payment})"
                )
            else:
                # [调试日志] 记录管理员访问（管理员无需检查 require_payment 配置）
                logging.info(
                    f"[用户支付日志] 权限检查通过 - 用户 {current_user} 为管理员，无条件允许访问"
                )

            # ========== 步骤3：确定当前用户的用户ID ==========
            # 权限检查通过后，继续处理支付日志查询逻辑

            # 确定用户ID
            # 如果g.user不为None，说明是注册用户，使用username
            # 否则，使用session中的UUID（游客会话）
            if current_user:
                user_id = current_user
            else:
                # 游客用户，使用session UUID
                # session UUID应该在login_required装饰器中已经设置
                user_id = session.get("uuid", "")
                if not user_id:
                    return jsonify({
                        "success": False,
                        "message": "无法识别用户身份，请重新登录"
                    }), 401

            # ========== 步骤4：获取查询参数 ==========

            # 操作类型筛选（可选）
            action_filter = request.args.get("action", "").strip()

            # 日期范围筛选（可选）
            start_date_str = request.args.get("start_date", "").strip()
            end_date_str = request.args.get("end_date", "").strip()

            # 分页参数
            try:
                page = int(request.args.get("page", "1"))
                per_page = int(request.args.get("per_page", "20"))
            except ValueError:
                page = 1
                per_page = 20

            # 验证分页参数
            if page < 1:
                page = 1
            if per_page < 1 or per_page > 100:
                per_page = 20

            # 解析日期范围
            start_timestamp = None
            end_timestamp = None

            if start_date_str:
                try:
                    # 将日期字符串转换为时间戳
                    # 格式：YYYY-MM-DD -> Unix时间戳（当天00:00:00）
                    # from datetime import datetime
                    start_dt = datetime.datetime.strptime(start_date_str, "%Y-%m-%d")
                    start_timestamp = start_dt.timestamp()
                except ValueError:
                    # 日期格式不正确，忽略此筛选条件
                    app.logger.warning(f"[用户支付日志] 日期格式不正确: {start_date_str}")

            if end_date_str:
                try:
                    # 将日期字符串转换为时间戳
                    # 格式：YYYY-MM-DD -> Unix时间戳（当天23:59:59）
                    # from datetime import datetime
                    end_dt = datetime.datetime.strptime(end_date_str, "%Y-%m-%d")
                    # 加上一天的秒数，使其包含整个结束日期
                    end_timestamp = end_dt.timestamp() + 86400 - 1
                except ValueError:
                    app.logger.warning(f"[用户支付日志] 日期格式不正确: {end_date_str}")

            # ========== 步骤5：读取当前用户的支付日志文件 ==========

            logs = []

            # 构建日志目录路径（所有日志统一在根目录）
            log_dir = PAYMENT_LOGS_DIR

            # 检查日志目录是否存在
            if os.path.exists(log_dir) and os.path.isdir(log_dir):
                # 遍历日志目录下的所有JSON文件
                for filename in os.listdir(log_dir):
                    # 只处理JSON文件
                    if not filename.endswith('.json'):
                        continue

                    # 新的日志文件命名格式：{timestamp}_{user_id}_{order_id}.json
                    # 我们需要检查文件名中是否包含当前用户的user_id
                    # 解析文件名格式：yyyymmdd_HHMMSS_user_id_order_id.json
                    parts = filename.rsplit('_', 2)  # 从右往左分割，最多分割2次
                    # parts可能是：['20231201_120530_admin', 'ORDER123', '.json']
                    # 或者：['20231201_120530', 'guestid', 'ORDER123.json']

                    # 为了兼容性，我们直接读取文件并检查user_id字段
                    file_path = os.path.join(log_dir, filename)

                    try:
                        # 读取日志文件
                        with open(file_path, 'r', encoding='utf-8') as f:
                            log_entry = json.load(f)

                        # 检查日志的user_id是否匹配当前用户
                        log_user_id = log_entry.get('user_id', '')
                        if log_user_id != user_id:
                            # 不是当前用户的日志，跳过
                            continue

                        # ========== 应用筛选条件 ==========

                        # 筛选条件1：操作类型
                        if action_filter and log_entry.get('action') != action_filter:
                            continue

                        # 筛选条件2：开始日期
                        if start_timestamp is not None:
                            log_timestamp = log_entry.get('timestamp', 0)
                            if log_timestamp < start_timestamp:
                                continue

                        # 筛选条件3：结束日期
                        if end_timestamp is not None:
                            log_timestamp = log_entry.get('timestamp', 0)
                            if log_timestamp > end_timestamp:
                                continue

                        # 添加log_id字段到日志数据
                        # log_id是日志文件名（不含.json后缀），用于后续查询日志详情
                        # 例如：20231201_120530_admin_ORDER20231201120530123456
                        log_entry["log_id"] = filename[:-5]  # 去掉.json后缀（5个字符）

                        # 通过筛选，添加到结果列表
                        logs.append(log_entry)

                    except Exception as e:
                        # 读取或解析单个文件失败，记录警告但继续处理其他文件
                        app.logger.warning(
                            f"[用户支付日志] 读取文件失败: {file_path}, 错误: {str(e)}")
                        continue

            # ========== 步骤6：排序和分页 ==========

            # 按时间戳倒序排序（最新的在前面）
            logs.sort(key=lambda x: x.get('timestamp', 0), reverse=True)

            # 计算总数
            total = len(logs)

            # 计算分页
            start_index = (page - 1) * per_page
            end_index = start_index + per_page

            # 获取当前页的数据
            page_logs = logs[start_index:end_index]

            # ========== 步骤7：返回结果 ==========

            return jsonify({
                "success": True,
                "logs": page_logs,
                "total": total,
                "page": page,
                "per_page": per_page,
                "user_id": user_id  # 返回用户ID，便于前端确认
            })

        except Exception as e:
            # 处理异常
            app.logger.error(f"[用户支付日志] 处理失败: {str(e)}", exc_info=True)
            return jsonify({
                "success": False,
                "message": f"获取支付日志失败: {str(e)}"
            }), 500

    @app.route("/api/admin/payment_logs", methods=["GET"])
    @login_required  # 只需要登录即可，细粒度权限在函数内部检查
    def admin_payment_logs():
        """
        获取支付日志列表接口（管理员专用）

        请求方法：GET
        权限要求：审计日志查看权限（view_audit_logs）

        查询参数（URL参数）：
            - user_id (str, 可选): 按用户ID筛选（支持模糊匹配）
            - action (str, 可选): 按操作类型筛选
                - "create_order": 创建订单
                - "query_order": 查询订单
                - "payment_success_notify": 支付成功通知
                - 等等
            - start_date (str, 可选): 开始日期（格式：YYYY-MM-DD）
            - end_date (str, 可选): 结束日期（格式：YYYY-MM-DD）
            - page (int, 可选): 页码，默认1
            - per_page (int, 可选): 每页数量，默认20（最大100）

        返回数据（JSON格式）：
            - success (bool): 是否成功
            - logs (list): 日志列表（按时间倒序）
                每条日志包含：
                - user_id: 用户标识
                - order_id: 订单号
                - action: 操作类型
                - datetime: 操作时间（可读格式）
                - 以及其他操作特定的数据
            - total (int): 符合条件的总日志数
            - page (int): 当前页码
            - per_page (int): 每页数量
            - users (list): 所有有支付记录的用户列表（用于筛选）

        功能说明：
        管理员可以查看所有用户的支付操作日志，支持多维度筛选和分页。
        日志按时间倒序排列，最新的日志在最前面。

        使用场景：
        - 审计：查看所有支付操作记录
        - 调试：分析支付问题的完整流程
        - 统计：分析用户支付行为
        - 安全：发现异常支付操作
        """
        try:
            # 细粒度权限检查：需要 'view_audit_logs' 权限
            # view_audit_logs 权限允许查看支付日志
            # 支付日志包含用户的交易信息，是重要的审计数据
            if not auth_system.check_permission(g.user, "view_audit_logs"):
                return jsonify({
                    "success": False,
                    "message": "权限不足，需要审计日志查看权限（view_audit_logs）"
                }), 403

            # ========== 获取查询参数 ==========

            # 用户ID筛选（可选）
            user_filter = request.args.get("user_id", "").strip()

            # 操作类型筛选（可选）
            action_filter = request.args.get("action", "").strip()

            # 日期范围筛选（可选）
            start_date_str = request.args.get("start_date", "").strip()
            end_date_str = request.args.get("end_date", "").strip()

            # 分页参数
            try:
                page = int(request.args.get("page", "1"))
                per_page = int(request.args.get("per_page", "20"))
            except ValueError:
                page = 1
                per_page = 20

            # 验证分页参数
            if page < 1:
                page = 1
            if per_page < 1 or per_page > 100:
                per_page = 20

            # 解析日期范围
            start_timestamp = None
            end_timestamp = None

            if start_date_str:
                try:
                    # 将日期字符串转换为时间戳
                    # 格式：YYYY-MM-DD -> Unix时间戳（当天00:00:00）
                    # from datetime import datetime
                    start_dt = datetime.datetime.strptime(start_date_str, "%Y-%m-%d")
                    start_timestamp = start_dt.timestamp()
                except ValueError:
                    # 日期格式不正确，忽略此筛选条件
                    logging.warning(f"[支付日志] 日期格式不正确: {start_date_str}")

            if end_date_str:
                try:
                    # 将日期字符串转换为时间戳
                    # 格式：YYYY-MM-DD -> Unix时间戳（当天23:59:59）
                    # from datetime import datetime
                    end_dt = datetime.datetime.strptime(end_date_str, "%Y-%m-%d")
                    # 加上一天的秒数，使其包含整个结束日期
                    end_timestamp = end_dt.timestamp() + 86400 - 1
                except ValueError:
                    logging.warning(f"[支付日志] 日期格式不正确: {end_date_str}")

            # ========== 读取所有支付日志文件 ==========

            logs = []
            users_set = set()  # 用于收集所有有支付记录的用户

            # 检查支付日志目录是否存在
            if not os.path.exists(PAYMENT_LOGS_DIR):
                # 目录不存在，返回空列表
                return jsonify({
                    "success": True,
                    "logs": [],
                    "total": 0,
                    "page": page,
                    "per_page": per_page,
                    "users": []
                })

            # 遍历所有日志文件（新结构：所有日志平铺在根目录）
            for log_filename in os.listdir(PAYMENT_LOGS_DIR):
                # 只处理.json文件
                if not log_filename.endswith(".json"):
                    continue

                # 构造日志文件完整路径
                log_filepath = os.path.join(PAYMENT_LOGS_DIR, log_filename)

                # 跳过非文件项（例如子目录）
                if not os.path.isfile(log_filepath):
                    continue

                try:
                    # 读取日志文件
                    with open(log_filepath, "r", encoding="utf-8") as f:
                        log_data = json.load(f)

                    # 提取用户ID并添加到用户集合
                    user_id = log_data.get("user_id", "")
                    if user_id:
                        users_set.add(user_id)

                    # ========== 应用筛选条件 ==========

                    # 用户ID筛选（如果设置了用户筛选）
                    if user_filter and user_filter not in user_id:
                        # 不匹配，跳过此日志
                        continue

                    # 操作类型筛选
                    if action_filter and log_data.get("action") != action_filter:
                        continue

                    # 日期范围筛选
                    log_timestamp = log_data.get("timestamp", 0)
                    if start_timestamp and log_timestamp < start_timestamp:
                        continue
                    if end_timestamp and log_timestamp > end_timestamp:
                        continue

                    # 添加log_id字段到日志数据
                    # log_id是日志文件名（不含.json后缀），用于后续查询日志详情
                    # 例如：20231201_120530_admin_ORDER20231201120530123456
                    log_data["log_id"] = log_filename[:-5]  # 去掉.json后缀（5个字符）

                    # 添加到日志列表
                    logs.append(log_data)

                except (json.JSONDecodeError, IOError) as e:
                    # 文件读取或解析失败，记录警告并跳过
                    logging.warning(
                        f"[支付日志] 读取日志文件失败: {log_filepath}, 错误: {str(e)}"
                    )
                    continue

            # ========== 排序和分页 ==========

            # 按时间戳倒序排列（最新的在前面）
            logs.sort(key=lambda x: x.get("timestamp", 0), reverse=True)

            # 分页
            total = len(logs)
            start = (page - 1) * per_page
            end = start + per_page
            logs_page = logs[start:end]

            # 转换用户集合为排序列表
            users_list = sorted(list(users_set))

            # 返回结果
            return jsonify({
                "success": True,
                "logs": logs_page,
                "total": total,
                "page": page,
                "per_page": per_page,
                "users": users_list  # 用于前端筛选下拉框
            })

        except Exception as e:
            # 捕获所有异常
            logging.error(f"[支付日志] 获取支付日志列表异常: {str(e)}")
            logging.error(traceback.format_exc())
            return jsonify({
                "success": False,
                "message": f"获取日志失败：{str(e)}"
            }), 500

    @app.route("/api/admin/payment/log_detail", methods=["POST"])
    @login_required  # 只需要登录即可，细粒度权限在函数内部检查
    def admin_get_payment_log_detail():
        """
        获取支付日志详情接口（管理员专用）

        功能说明：
        根据日志ID（即日志文件名）读取并返回完整的日志详细信息。
        用于支持前端点击"查看详情"按钮后显示日志的完整内容。

        请求方法：POST
        权限要求：审计日志查看权限（view_audit_logs）

        请求体（JSON格式）：
            {
                "log_id": "20231201_120530_admin_ORDER20231201120530123456"  # 日志ID（文件名，不含.json后缀）
            }

        返回数据（JSON格式）：
            {
                "success": true,
                "log_detail": {
                    "timestamp": 1701417930.123,            # Unix时间戳
                    "datetime": "2023-12-01 12:05:30",     # 可读时间格式
                    "action": "create_order",              # 操作类型
                    "user_id": "admin",                    # 用户标识
                    "order_id": "ORDER20231201120530123456", # 订单号
                    "client_ip": "192.168.1.100",          # 客户端IP地址
                    "user_agent": "Mozilla/5.0...",        # 浏览器User Agent
                    "amount": 10.00,                       # 金额（如果有）
                    "status": "success",                   # 状态（如果有）
                    # ... 其他日志中包含的字段
                }
            }

        使用场景：
        - 查看日志的完整详细信息，包括所有字段
        - 调试支付问题时查看完整的请求和响应数据
        - 审计时查看操作的详细过程
        """
        try:
            # ========== 步骤1：权限检查 ==========

            # 细粒度权限检查：需要 'view_audit_logs' 权限
            # 查看日志详情与查看日志列表需要相同的权限
            if not auth_system.check_permission(g.user, "view_audit_logs"):
                return jsonify({
                    "success": False,
                    "message": "权限不足，需要审计日志查看权限（view_audit_logs）"
                }), 403

            # ========== 步骤2：获取并验证请求参数 ==========

            # 从请求体中获取JSON数据
            # 使用 request.get_json() 自动解析JSON格式的请求体
            data = request.get_json() or {}

            # 提取日志ID参数
            # 日志ID即日志文件名（不含.json后缀）
            # 格式示例：20231201_120530_admin_ORDER20231201120530123456
            log_id = data.get("log_id", "").strip()

            # 验证日志ID是否为空
            if not log_id:
                # 日志ID为空，返回400错误（参数错误）
                return jsonify({
                    "success": False,
                    "message": "日志ID不能为空"
                }), 400

            # ========== 步骤3：构造日志文件路径 ==========

            # 构造日志文件的完整路径
            # 日志文件存储在 PAYMENT_LOGS_DIR 目录下
            # 文件名格式：{log_id}.json
            log_filepath = os.path.join(PAYMENT_LOGS_DIR, f"{log_id}.json")

            # 安全性检查：防止路径遍历攻击
            # 例如：log_id = "../../../etc/passwd" 这样的恶意输入
            # 确保构造的路径必须在 PAYMENT_LOGS_DIR 目录内
            real_log_dir = os.path.realpath(PAYMENT_LOGS_DIR)
            real_log_path = os.path.realpath(log_filepath)

            # 检查real_log_path是否以real_log_dir开头
            # 如果不是，说明有路径遍历企图，拒绝访问
            if not real_log_path.startswith(real_log_dir):
                logging.warning(
                    f"[支付日志详情] 检测到路径遍历企图 - 用户: {g.user}, "
                    f"log_id: {log_id}, real_path: {real_log_path}"
                )
                return jsonify({
                    "success": False,
                    "message": "无效的日志ID"
                }), 400

            # ========== 步骤4：检查日志文件是否存在 ==========

            # 检查日志文件是否真实存在
            if not os.path.exists(log_filepath):
                # 文件不存在，可能是：
                # 1. 日志ID输入错误
                # 2. 日志文件已被删除
                # 3. 日志还未生成
                logging.warning(
                    f"[支付日志详情] 日志文件不存在 - 用户: {g.user}, "
                    f"log_id: {log_id}, filepath: {log_filepath}"
                )
                return jsonify({
                    "success": False,
                    "message": "日志文件不存在，可能已被删除"
                }), 404

            # ========== 步骤5：读取日志文件内容 ==========

            try:
                # 打开并读取日志JSON文件
                # 使用UTF-8编码确保中文内容正确显示
                with open(log_filepath, "r", encoding="utf-8") as f:
                    log_detail = json.load(f)

                # 记录操作日志（用于审计）
                # 记录谁在什么时候查看了哪条日志
                logging.info(
                    f"[支付日志详情] 管理员查看日志详情 - "
                    f"用户: {g.user}, log_id: {log_id}"
                )

                # 返回成功响应，包含完整的日志详情
                return jsonify({
                    "success": True,
                    "log_detail": log_detail
                })

            except json.JSONDecodeError as e:
                # JSON解析失败，可能是文件损坏
                logging.error(
                    f"[支付日志详情] JSON解析失败 - "
                    f"log_id: {log_id}, 错误: {str(e)}"
                )
                return jsonify({
                    "success": False,
                    "message": "日志文件格式错误，无法解析"
                }), 500
            except Exception as e:
                # 读取文件时的其他异常
                logging.error(
                    f"[支付日志详情] 读取日志文件失败 - "
                    f"log_id: {log_id}, 错误: {str(e)}"
                )
                return jsonify({
                    "success": False,
                    "message": f"读取日志文件失败：{str(e)}"
                }), 500

        except Exception as e:
            # 捕获所有未预期的异常
            # 记录详细的错误日志（包含堆栈跟踪）
            logging.error(f"[支付日志详情] 获取日志详情异常: {str(e)}")
            logging.error(traceback.format_exc())
            return jsonify({
                "success": False,
                "message": f"获取日志详情失败：{str(e)}"
            }), 500

    @app.route("/api/admin/payment/notify_stats", methods=["GET"])
    @login_required  # 只需要登录即可，细粒度权限在函数内部检查
    def admin_payment_notify_stats():
        """
        获取支付通知统计信息接口（管理员专用）

        请求方法：GET
        权限要求：需要日志查看权限（view_logs）

        功能说明：
        这个接口用于监控支付通知系统的运行状况，统计重复通知的情况。
        可以帮助管理员发现：
        - 哪些订单收到了重复通知
        - 重复通知的频率
        - 是否存在异常的重复通知模式

        返回数据（JSON格式）：
            - success (bool): 是否成功
            - stats (dict): 统计信息
                - total_orders (int): 总订单数
                - repeat_notifies (int): 重复通知总次数（不包括首次通知）
                - max_repeat_count (int): 单个订单的最大通知次数
                - orders_with_repeats (list): 有重复通知的订单列表
                    每个订单包含：
                    - order_id (str): 订单号
                    - notify_count (int): 收到通知的总次数
                    - last_notify_time (str): 最后一次通知时间
                    - username (str): 订单所有者
                    - amount (str): 订单金额
                    - status (str): 订单状态

        使用场景：
        - 监控：实时监控支付系统的通知重试情况
        - 告警：发现异常的重复通知模式（例如某订单被通知了上百次）
        - 优化：分析通知重试的原因，优化幂等性处理机制
        - 调试：排查支付通知相关的问题
        """
        # 获取当前登录用户（由@login_required装饰器设置到g.user）
        auth_username = g.user

        # 检查细粒度权限：日志查看权限
        # view_logs 权限允许管理员查看系统日志和统计信息
        # 支付通知统计属于系统运行状态的监控数据，使用view_logs权限
        # 这是一个只读的查询操作，不涉及数据修改
        if not auth_system.check_permission(auth_username, 'view_logs'):
            return jsonify({
                "success": False,
                "message": "权限不足，需要日志查看权限（view_logs）"
            }), 403

        try:
            # ========== 初始化统计数据结构 ==========

            stats = {
                "total_orders": 0,              # 总订单数
                "paid_orders": 0,               # 已支付订单数
                "repeat_notifies": 0,           # 重复通知总次数（不包括首次）
                "max_repeat_count": 0,          # 单个订单的最大通知次数
                "orders_with_repeats": []       # 有重复通知的订单详情列表
            }

            # ========== 遍历所有订单文件，收集统计信息 ==========

            # 检查订单目录是否存在
            if not os.path.exists(PAYMENT_ORDERS_DIR):
                # 订单目录不存在，返回空统计
                return jsonify({
                    "success": True,
                    "stats": stats,
                    "message": "订单目录不存在，统计为空"
                })

            # 遍历订单目录中的所有JSON文件
            for filename in os.listdir(PAYMENT_ORDERS_DIR):
                # 只处理JSON文件
                if not filename.endswith(".json"):
                    continue

                # 构造完整的文件路径
                filepath = os.path.join(PAYMENT_ORDERS_DIR, filename)

                try:
                    # 读取订单数据
                    with open(filepath, "r", encoding="utf-8") as f:
                        order_data = json.load(f)

                    # 统计总订单数
                    stats["total_orders"] += 1

                    # 统计已支付订单数（包括已支付、已部分退款、已全额退款）
                    if order_data.get("status") in (ORDER_STATUS_PAID, ORDER_STATUS_REFUNDED_PARTIAL, ORDER_STATUS_REFUNDED_FULL):
                        stats["paid_orders"] += 1

                    # 获取通知计数（notify_count字段）
                    # 注意：对于旧订单（在添加计数功能之前创建的），notify_count字段不存在
                    # 我们将其默认为0，这样它们不会被计入重复通知统计
                    # 这是合理的，因为我们无法得知旧订单收到过多少次通知
                    # 只有在添加此功能之后创建的订单才会有准确的统计数据
                    notify_count = order_data.get("notify_count", 0)

                    # 如果收到过通知（notify_count > 0）
                    if notify_count > 0:
                        # 更新最大通知次数
                        stats["max_repeat_count"] = max(
                            stats["max_repeat_count"], notify_count)

                        # 如果通知次数大于1，说明有重复通知
                        if notify_count > 1:
                            # 累加重复通知次数（不包括首次通知）
                            stats["repeat_notifies"] += (notify_count - 1)

                            # 将这个订单添加到重复通知列表
                            stats["orders_with_repeats"].append({
                                "order_id": order_data.get("order_id", filename.replace(".json", "")),
                                "notify_count": notify_count,                           # 通知总次数
                                # 最后通知时间
                                "last_notify_time": order_data.get("last_notify_time", "未知"),
                                # 最后通知时间戳
                                "last_notify_at": order_data.get("last_notify_at", 0),
                                # 首次通知时间
                                "first_notify_time": order_data.get("paid_time", "未知"),
                                # 订单所有者
                                "username": order_data.get("username", "未知"),
                                # 订单金额
                                "amount": order_data.get("amount", "0"),
                                # 订单状态
                                "status": order_data.get("status", "unknown"),
                                # 商品名称
                                "product_name": order_data.get("product_name", "未知")
                            })

                except Exception as e:
                    # 读取单个订单文件失败，记录日志但继续处理其他订单
                    logging.error(f"[通知统计] 读取订单文件失败: {filename}, 错误: {str(e)}")
                    continue

            # ========== 对重复通知列表排序 ==========
            # 按通知次数降序排列，通知次数最多的订单排在最前面
            stats["orders_with_repeats"].sort(
                key=lambda x: x["notify_count"], reverse=True)

            # ========== 返回统计结果 ==========

            return jsonify({
                "success": True,
                "stats": stats,
                "message": "统计完成"
            })

        except Exception as e:
            # 捕获所有异常
            logging.error(f"[通知统计] 获取统计信息失败: {str(e)}")
            logging.error(traceback.format_exc())
            return jsonify({
                "success": False,
                "message": f"获取统计信息失败: {str(e)}"
            }), 500

    # ==============================================================================
    # 新增：管理员查询单个订单接口（从易支付平台同步）
    # ==============================================================================

    @app.route("/api/admin/payment/query_order", methods=["POST"])
    @login_required
    @admin_required
    def admin_query_payment_order():
        """
        管理员查询单个订单详情接口（支持从易支付平台同步）
        """
        try:
            # ========== 第1步：获取并验证请求参数 ==========

            # 从请求体中获取JSON数据
            data = request.get_json() or {}

            # 提取订单标识参数
            order_id = str(data.get("order_id", "")).strip()       # 商户订单号
            trade_no = str(data.get("trade_no", "")).strip()       # 平台订单号

            # 验证必须提供至少一个订单标识
            if not order_id and not trade_no:
                logging.warning("[管理员查询订单] 参数错误：必须提供 order_id 或 trade_no")
                return jsonify({
                    "success": False,
                    "message": "参数错误：必须提供订单号"
                }), 400

            # 记录日志：收到查询请求
            logging.info(
                f"[管理员查询订单] 管理员 {g.user} 查询订单 - "
                f"order_id: {order_id or 'N/A'}, trade_no: {trade_no or 'N/A'}"
            )

            # ========== 第2步：尝试从本地文件读取订单 ==========

            order_data = None
            source = None

            # 如果提供了商户订单号，先尝试从本地读取
            if order_id:
                # 构造订单文件路径
                # 本地订单文件以商户订单号命名，存储在 PAYMENT_ORDERS_DIR 目录下
                # 文件格式：{order_id}.json（例如：ORDER20231201123456.json）
                order_file = os.path.join(
                    PAYMENT_ORDERS_DIR, f"{order_id}.json")

                # 检查订单文件是否存在
                if os.path.exists(order_file):
                    try:
                        # 读取本地订单数据
                        # 本地文件包含完整的订单信息，包括：
                        # - 基础订单信息（订单号、金额、商品名等）
                        # - 支付相关信息（支付URL、支付方式等）
                        # - 时间信息（创建时间、支付时间等）
                        # - 用户信息（用户名、IP、设备等）
                        # - 扩展信息（自定义参数、平台数据等）
                        with open(order_file, "r", encoding="utf-8") as f:
                            order_data = json.load(f)

                        source = "local"  # 数据来源：本地文件
                        logging.info(
                            f"[管理员查询订单] 从本地文件读取成功 - "
                            f"订单号: {order_id}, "
                            f"包含字段数: {len(order_data)}"
                        )

                    except Exception as e:
                        # 读取失败，记录警告但继续尝试从平台查询
                        # 这种情况可能是文件损坏或格式错误
                        logging.warning(
                            f"[管理员查询订单] 本地文件读取失败: {str(e)} - "
                            f"将尝试从平台查询"
                        )

            # ========== 第3步：如果本地没有，从易支付平台查询 ==========

            logging.info("[管理员查询订单] 从易支付平台查询")

            # 调用内部函数查询易支付平台
            query_result = _query_yipay_order(
                order_id=order_id, trade_no=trade_no)

            # 检查查询是否成功
            if query_result.get("success"):
                # 从平台获取到订单数据
                platform_order = query_result.get("data", {})

                # 提取商户订单号（用于保存到本地）
                out_trade_no = platform_order.get("out_trade_no", "")

                if not out_trade_no:
                    logging.error("[管理员查询订单] 平台返回的订单数据缺少 out_trade_no")
                    return jsonify({
                        "success": False,
                        "message": "平台返回的订单数据格式异常"
                    }), 500

                # ========== 第4步：将平台订单保存到本地 ==========

                # 构造本地订单数据结构
                # 转换易支付平台的字段到我们的订单格式
                # 这里会保存尽可能多的订单信息，确保数据完整性
                local_order_data = {
                    # ---------- 基础订单信息 ----------
                    # 商户订单号（系统订单号/out_trade_no）
                    "order_id": out_trade_no,
                    # 平台订单号（易支付平台生成的唯一订单号）
                    "trade_no": platform_order.get("trade_no", ""),
                    # 订单金额（单位：元，字符串格式）
                    "amount": platform_order.get("money", "0"),
                    # 商品名称（订单描述）
                    "product_name": platform_order.get("name", "未知商品"),
                    # 用户名（平台数据中通常没有此字段，默认为unknown）

                    # ---------- 时间信息 ----------
                    # 创建时间（订单创建时的时间戳或时间字符串）
                    "created_at": platform_order.get("addtime", ""),
                    # 支付时间（订单支付完成的时间）
                    "paid_time": platform_order.get("endtime", ""),
                    # 同步时间戳（从平台同步到本地的Unix时间戳）
                    "synced_at": time.time(),
                    # 同步时间（可读格式：YYYY-MM-DD HH:MM:SS）
                    "synced_time": time.strftime("%Y-%m-%d %H:%M:%S"),

                    # ---------- 扩展业务信息 ----------
                    # 业务扩展参数（创建订单时传入的自定义参数，可用于业务逻辑）
                    "param": platform_order.get("param", ""),
                    # 支付用户标识（买家的支付账号信息，如支付宝账号/微信openid）
                    "buyer": platform_order.get("buyer", ""),
                    # 支付用户IP（发起支付时的客户端IP地址）
                    "clientip": platform_order.get("clientip", ""),

                    # ---------- 支付渠道信息 ----------
                    # 接口订单号（第三方支付接口如支付宝/微信返回的订单号）
                    "api_trade_no": platform_order.get("api_trade_no", ""),
                    # 支付方式（alipay=支付宝, wxpay=微信支付等）
                    "pay_type": platform_order.get("type", ""),

                    # ---------- 退款信息 ----------
                    # 已退款金额（单位：元，累计退款的金额）
                    "refundmoney": platform_order.get("refundmoney", "0"),

                    # ---------- 订单状态 ----------
                    # 转换支付状态：将易支付平台的状态码转换为系统内部状态
                    # 易支付状态码说明：
                    #   0 = 未支付（订单已创建但未完成支付）
                    #   1 = 已支付（订单支付成功）
                    #   2 = 已退款（订单已发起退款，可能是部分或全额）
                    #   3 = 已冻结（订单被冻结，无法操作）
                    #   4 = 预授权（预授权订单，资金已冻结但未扣款）
                    "status": _convert_yipay_status(platform_order.get("status", 0)),

                    # ---------- 元数据标记 ----------
                    # 标记：此订单数据是从平台同步而来
                    "synced_from_platform": True,

                    # ---------- 完整平台数据 ----------
                    # 保存平台返回的完整原始数据，用于：
                    # 1. 调试和问题排查
                    # 2. 获取平台特有的字段
                    # 3. 数据追溯和审计
                    # 平台返回的完整订单对象（包含所有字段）
                    "platform_data": platform_order
                }

                if order_data is None:
                    local_order_data["username"] = "未知"
                else:
                    local_order_data["username"] = order_data.get(
                        "username", "未知")

                logging.info(
                    f"[管理员查询订单] 平台订单数据转换完成 - 单号: {local_order_data['order_id']}，数据：{local_order_data}")

                # ========== 修复退款状态判断逻辑 ==========
                #
                # 问题说明：
                # 易支付平台的status=2表示"已退款"，但没有区分部分退款和全额退款
                # 需要根据实际退款金额来判断是部分退款还是全额退款
                #
                # 判断逻辑：
                # 1. 如果平台状态是2（已退款）
                # 2. 比较退款金额(refundmoney)和订单金额(money)
                # 3. 如果退款金额 >= 订单金额，则为全额退款
                # 4. 如果退款金额 < 订单金额，则为部分退款

                platform_status = local_order_data["platform_data"].get(
                    "status", 0)
                logging.info(
                    f"[管理员查询订单] 订单退款状态检查 - "
                    f"单号: {out_trade_no}, "
                    f"平台状态: {platform_status}"
                )

                if platform_status == 2 or platform_status == '2':
                    # 平台返回的是退款状态，需要进一步判断退款类型

                    # 获取退款金额和订单金额（转换为浮点数进行计算）
                    refundmoney = float(
                        local_order_data["platform_data"].get("refundmoney", "0"))
                    order_amount = float(
                        local_order_data["platform_data"].get("money", "0"))

                    logging.info(
                        f"[管理员查询订单] 订单退款状态处理 - "
                        f"单号: {out_trade_no}, "
                        f"订单金额: {order_amount}, "
                        f"退款金额: {refundmoney}"
                    )

                    # 判断退款类型
                    # 使用 >= 比较（而不是 ==），因为某些情况下退款金额可能略大于订单金额（如退款手续费）
                    # 当退款金额 >= 订单金额时，视为全额退款
                    if refundmoney >= order_amount:
                        # 全额退款：退款金额等于或大于订单金额
                        local_order_data["status"] = ORDER_STATUS_REFUNDED_FULL
                        logging.info(f"[管理员查询订单] 订单全额退款 - 单号: {out_trade_no}")
                    else:
                        # 部分退款：退款金额小于订单金额
                        local_order_data["status"] = ORDER_STATUS_REFUNDED_PARTIAL
                        logging.info(f"[管理员查询订单] 订单部分退款 - 单号: {out_trade_no}")

                # ========== 检查订单状态变更（为overdue处理做准备）==========
                #
                # 目的：在保存新订单之前，记录旧订单的状态
                # 如果订单状态从pending变为paid，且包含overdue_accounts，需要处理欠费减少

                # 记录旧订单状态（如果本地已有订单）
                old_status = None
                if order_data is not None:
                    # 本地已有订单数据，记录其状态
                    old_status = order_data.get("status")

                # ========== 保存平台订单到本地文件 ==========
                #
                # 目的：
                # 1. 将从平台查询到的订单数据持久化到本地
                # 2. 下次查询时可以直接从本地读取，提高查询速度
                # 3. 即使平台服务不可用，仍可查询历史订单
                #
                # 保存的数据：
                # - 完整的订单信息（包含所有字段）
                # - 平台返回的原始数据（platform_data字段）
                # - 同步标记和时间戳

                # 保存到本地文件
                order_file = os.path.join(
                    PAYMENT_ORDERS_DIR, f"{out_trade_no}.json")

                # 确保订单目录存在
                os.makedirs(PAYMENT_ORDERS_DIR, exist_ok=True)

                order_data.update(local_order_data)  # 更新本地订单数据

                local_order_data = order_data  # 使用更新后的订单数据
                try:
                    # 写入订单文件（使用增量更新模式）
                    # 调用统一的订单文件保存函数
                    _save_order_file_incremental(
                        out_trade_no, local_order_data)

                    logging.info(
                        f"[管理员查询订单] 平台订单已保存到本地 - "
                        f"订单号: {out_trade_no}"
                    )

                    # 记录同步日志
                    _write_payment_log(
                        user_id=g.user,
                        order_id=out_trade_no,
                        action="sync_order_from_platform",
                        log_data={
                            "source": "admin_query",
                            "platform_data": platform_order,
                            "success": True
                        }
                    )

                    # ========== 处理订单状态变更时的overdue_accounts逻辑 ==========
                    #
                    # 检查订单状态是否从pending变为paid
                    # 如果是，且订单包含overdue_accounts字段，则需要减少对应账号的overdue_count

                    # 获取新订单状态（从平台获取的状态）
                    new_status = local_order_data.get("status", "")

                    logging.info(
                        f"[管理员从平台查询订单] 订单状态检查 - "
                        f"单号: {out_trade_no}, "
                        f"旧状态: {old_status}, "
                        f"新状态: {new_status}"
                    )

                    # 判断是否状态改变：
                    # 1. 旧状态为pending或None（订单不存在）
                    # 2. 新状态为paid
                    is_status_changed = (old_status in [ORDER_STATUS_PENDING, None]) and (
                        new_status == ORDER_STATUS_PAID)

                    # 如果状态改变，且订单包含overdue_accounts字段
                    if is_status_changed and "overdue_accounts" in local_order_data:
                        # 提取欠费账号列表
                        overdue_accounts = local_order_data.get(
                            "overdue_accounts", [])

                        # 验证overdue_accounts是否为有效的列表
                        if overdue_accounts and isinstance(overdue_accounts, list):
                            logging.info(
                                f"[订单状态变更] 订单 {out_trade_no} 状态从 {old_status} 变为 {new_status}，"
                                f"开始处理overdue_accounts"
                            )
                            auth_username = local_order_data["username"]
                            _process_overdue_payment_async(
                                overdue_accounts, auth_username, out_trade_no)

                except Exception as e:
                    # 保存失败，记录错误但仍然返回平台数据
                    # 注意：即使保存失败，也不影响返回订单信息给调用方
                    logging.error(
                        f"[管理员查询订单] 保存订单到本地失败: {str(e)} - "
                        f"订单号: {out_trade_no}"
                    )

                # ========== 使用转换后的本地订单数据 ==========
                #
                # 将平台数据转换为本地格式后，统一使用local_order_data返回
                # 这样可以确保：
                # 1. 返回的数据结构统一（无论是本地查询还是平台查询）
                # 2. 包含所有必要的字段（基础信息、时间、扩展参数、平台原始数据等）
                # 3. 字段命名符合系统规范
                if not order_data:
                    order_data = local_order_data
                else:
                    order_data.update(local_order_data)
                source = "platform"  # 数据来源：平台查询

            else:
                # 平台查询失败
                error_msg = query_result.get("message", "查询失败")
                logging.warning(f"[管理员查询订单] 平台查询失败: {error_msg}")
                return jsonify({
                    "success": False,
                    "message": f"订单不存在或查询失败：{error_msg}"
                }), 404

            # ========== 第5步：返回订单数据 ==========

            # 返回完整的订单数据
            # 注意：
            # 1. order_data包含订单的所有字段，不会主动过滤任何信息
            # 2. 本地订单和平台订单的字段可能有差异，但都会返回完整数据
            # 3. 平台订单会额外包含platform_data字段，存储平台返回的原始数据
            # 4. source字段标识数据来源：local（本地文件）或 platform（平台查询）

            return jsonify({
                "success": True,
                "order": order_data,              # 完整的订单数据（包含所有可用字段）
                "source": source,                 # 数据来源标识
                "message": "查询成功"
            })

        except Exception as e:
            # 捕获所有异常
            logging.error(f"[管理员查询订单] 处理失败: {str(e)}")
            logging.error(traceback.format_exc())
            return jsonify({
                "success": False,
                "message": f"查询失败：{str(e)}"
            }), 500

    @app.route("/api/admin/payment/order_detail", methods=["POST"])
    @login_required
    @admin_required
    def admin_get_order_detail():
        """
        管理员获取单个订单详情接口（仅从本地读取）

        功能说明:
            管理员专用接口，用于快速获取本地订单详情。
            与 query_order 不同，此接口仅读取本地文件，不会查询支付平台。

        请求参数（JSON）:
            - order_id (str, 必需): 商户订单号（out_trade_no）

        返回结果（JSON）:
            成功: {"success": True, "order": {...}}
            失败: {"success": False, "message": "错误信息"}

        权限要求:
            - 登录用户（@login_required）
            - 管理员权限（@admin_required）
        """
        try:
            # 获取并验证请求参数
            data = request.get_json() or {}
            order_id = str(data.get("order_id", "")).strip()

            if not order_id:
                logging.warning("[管理员获取订单详情] 参数错误：未提供 order_id")
                return jsonify({
                    "success": False,
                    "message": "参数错误：必须提供订单号"
                }), 400

            logging.info(
                f"[管理员获取订单详情] 管理员 {g.user} 查询订单 - order_id: {order_id}")

            # 从本地文件读取订单
            order_file = os.path.join(PAYMENT_ORDERS_DIR, f"{order_id}.json")

            if not os.path.exists(order_file):
                logging.warning(f"[管理员获取订单详情] 订单文件不存在: {order_id}")
                return jsonify({
                    "success": False,
                    "message": "订单不存在"
                }), 404

            try:
                with open(order_file, "r", encoding="utf-8") as f:
                    order_data = json.load(f)

                logging.info(f"[管理员获取订单详情] 成功读取订单 - 订单号: {order_id}")
                return jsonify({
                    "success": True,
                    "order": order_data
                })

            except Exception as e:
                logging.error(f"[管理员获取订单详情] 读取订单文件失败: {str(e)}")
                return jsonify({
                    "success": False,
                    "message": f"读取订单文件失败: {str(e)}"
                }), 500

        except Exception as e:
            logging.error(f"[管理员获取订单详情] 处理请求时发生错误: {str(e)}")
            return jsonify({
                "success": False,
                "message": f"服务器错误: {str(e)}"
            }), 500

    def _convert_yipay_status(status_code):
        """
        转换易支付状态码到本地订单状态常量（内部辅助函数）

        参数:
            status_code (int): 易支付状态码
                - 0: 未支付
                - 1: 已支付
                - 2: 已退款
                - 3: 已冻结
                - 4: 预授权

        返回:
            str: 本地订单状态常量
        """
        # 状态码映射表
        status_map = {
            0: ORDER_STATUS_PENDING,          # 未支付 -> pending
            1: ORDER_STATUS_PAID,             # 已支付 -> paid
            2: ORDER_STATUS_REFUNDED_FULL,    # 已退款 -> refunded_full
            3: ORDER_STATUS_FROZEN,           # 已冻结 -> frozen
            4: ORDER_STATUS_PREAUTH,          # 预授权 -> preauth
        }

        # 转换状态码，如果找不到则返回 pending
        return status_map.get(int(status_code), ORDER_STATUS_PENDING)

