    @app.route("/api/admin/payment/local_orders", methods=["GET"])
    @login_required
    @admin_required
    def admin_get_local_payment_orders():
        """
        获取本地支付订单列表接口（不查询平台）

        功能说明:
            管理员专用接口，用于获取本地已保存的所有支付订单。
            仅读取本地 payment_orders 目录下的订单文件，不查询平台。
            适用于订单列表展示和筛选功能。

        请求方式: GET

        返回结果（JSON）:
            成功: {
                "success": True,
                "orders": [
                    {
                        "order_id": "ORDER123",      # 系统订单号
                        "trade_no": "20231210...",   # 平台订单号
                        "api_trade_no": "wx123...",  # 接口订单号
                        "username": "user1",         # 用户名
                        "amount": "10.00",           # 金额
                        "pay_type": "alipay",        # 支付方式
                        "status": "paid",            # 订单状态
                        "created_at": "2023-12-10 10:00:00",  # 创建时间
                        "paid_time": "2023-12-10 10:05:00"    # 支付时间
                    },
                    ...
                ],
                "total": 100  # 订单总数
            }
            失败: {"success": False, "message": "错误信息"}

        权限要求:
            - 登录用户（@login_required）
            - 管理员权限（@admin_required）
        """
        try:
            # 记录日志：收到获取本地订单请求
            logging.info(f"[获取本地订单] 管理员 {g.user} 请求获取本地订单列表")

            # ========== 第1步：读取本地订单目录 ==========

            # 确保订单目录存在
            if not os.path.exists(PAYMENT_ORDERS_DIR):
                # 订单目录不存在，返回空列表
                logging.warning(f"[获取本地订单] 订单目录不存在: {PAYMENT_ORDERS_DIR}")
                return jsonify({
                    "success": True,
                    "orders": [],
                    "total": 0
                })

            # 获取订单目录下的所有JSON文件
            order_files = [f for f in os.listdir(
                PAYMENT_ORDERS_DIR) if f.endswith('.json')]

            logging.info(f"[获取本地订单] 找到 {len(order_files)} 个订单文件")

            # ========== 第2步：读取所有订单文件 ==========

            orders = []

            for order_file in order_files:
                try:
                    # 构造订单文件完整路径
                    order_file_path = os.path.join(
                        PAYMENT_ORDERS_DIR, order_file)

                    # 读取订单数据
                    with open(order_file_path, 'r', encoding='utf-8') as f:
                        order_data = json.load(f)

                    # 提取关键字段
                    order_summary = {
                        "order_id": order_data.get("order_id", ""),
                        "trade_no": order_data.get("trade_no", ""),
                        "api_trade_no": order_data.get("api_trade_no", ""),
                        "username": order_data.get("username", "未知"),
                        "amount": order_data.get("amount", "0"),
                        "pay_type": order_data.get("pay_type", "unknown"),
                        "status": order_data.get("status", "unknown"),
                        "created_at": order_data.get("created_at", ""),
                        "paid_time": order_data.get("paid_time", "")
                    }

                    orders.append(order_summary)

                except Exception as e:
                    # 单个订单文件读取失败，记录警告但继续处理其他订单
                    logging.warning(
                        f"[获取本地订单] 读取订单文件失败: {order_file}, 错误: {str(e)}")
                    continue

            # ========== 第3步：返回订单列表 ==========

            logging.info(f"[获取本地订单] 成功读取 {len(orders)} 个订单")

            return jsonify({
                "success": True,
                "orders": orders,
                "total": len(orders)
            })

        except Exception as e:
            # 处理异常
            logging.error(f"[获取本地订单] 处理失败: {str(e)}", exc_info=True)
            return jsonify({
                "success": False,
                "message": f"获取本地订单列表失败: {str(e)}"
            }), 500

    @app.route("/api/admin/payment/fetch_orders", methods=["POST"])
    @login_required
    @admin_required
    def admin_fetch_payment_orders():
        """
        管理员批量拉取订单列表接口（从易支付平台同步）

        功能说明:
            管理员专用接口，用于从易支付平台批量拉取订单并同步到本地。
            应用场景：
            1. 定期同步平台订单
            2. 订单数据丢失后的恢复
            3. 订单对账和数据校验

        请求参数（JSON）:
            - offset (int, 可选): 查询偏移量，从0开始（默认0）
            - limit (int, 可选): 每页条数，最大50（默认50）

        返回结果（JSON）:
            成功: {
                "success": True,
                "fetched": 10,              # 成功拉取的订单数
                "saved": 8,                 # 成功保存到本地的订单数
                "failed": 2,                # 保存失败的订单数
                "orders": [...]             # 订单列表（简要信息）
            }
            失败: {"success": False, "message": "错误信息"}

        权限要求:
            - 登录用户（@login_required）
            - 管理员权限（@admin_required）
        """
        try:
            # ========== 第1步：获取并验证请求参数 ==========

            # 从请求体中获取JSON数据
            data = request.get_json() or {}

            # 提取分页参数
            offset = data.get("offset", 0)
            limit = data.get("limit", 50)

            # 参数类型转换和验证
            try:
                offset = int(offset)
                limit = int(limit)
            except (ValueError, TypeError):
                offset = 0
                limit = 50

            # 参数范围验证
            if offset < 0:
                offset = 0
            if limit < 1 or limit > 50:
                limit = 50

            # 记录日志：收到拉取请求
            logging.info(
                f"[管理员拉取订单] 管理员 {g.user} 发起订单拉取 - "
                f"offset: {offset}, limit: {limit}"
            )

            # ========== 第2步：调用易支付平台获取订单列表 ==========

            fetch_result = _fetch_yipay_orders(offset=offset, limit=limit)

            # 检查查询是否成功
            if not fetch_result.get("success"):
                error_msg = fetch_result.get("message", "拉取失败")
                logging.error(f"[管理员拉取订单] 平台拉取失败: {error_msg}")
                return jsonify({
                    "success": False,
                    "message": f"从平台拉取订单失败：{error_msg}"
                }), 500

            # 获取订单列表
            platform_orders = fetch_result.get("data", [])

            logging.info(f"[管理员拉取订单] 从平台获取到 {len(platform_orders)} 个订单")

            # ========== 第3步：遍历订单列表，保存到本地 ==========

            # 统计变量
            saved_count = 0      # 成功保存的订单数
            failed_count = 0     # 保存失败的订单数
            order_summaries = []  # 订单简要信息列表（用于返回给前端）

            # 确保订单目录存在
            os.makedirs(PAYMENT_ORDERS_DIR, exist_ok=True)

            # 遍历每个订单
            for platform_order in platform_orders:
                try:
                    # 提取商户订单号
                    out_trade_no = platform_order.get("out_trade_no", "")

                    if not out_trade_no:
                        logging.warning("[管理员拉取订单] 跳过：订单数据缺少 out_trade_no")
                        failed_count += 1
                        continue

                    # 构造本地订单数据结构
                    # 转换易支付平台的字段到我们的订单格式
                    local_order_data = {
                        "order_id": out_trade_no,                                    # 商户订单号
                        # 平台订单号
                        "trade_no": platform_order.get("trade_no", ""),
                        # 订单金额
                        "amount": platform_order.get("money", "0"),
                        # 商品名称
                        "product_name": platform_order.get("name", "未知"),
                        "username": "未知",                                       # 用户名（平台数据中可能没有）
                        # 创建时间
                        "created_at": platform_order.get("addtime", ""),
                        # 支付时间
                        "paid_time": platform_order.get("endtime", ""),
                        # 业务扩展参数
                        "param": platform_order.get("param", ""),
                        # 支付用户标识
                        "buyer": platform_order.get("buyer", ""),
                        # 支付用户IP
                        "clientip": platform_order.get("clientip", ""),
                        # 接口订单号
                        "api_trade_no": platform_order.get("api_trade_no", ""),
                        # 支付方式
                        "pay_type": platform_order.get("type", ""),
                        # 已退款金额
                        "refundmoney": platform_order.get("refundmoney", "0"),
                        # 转换支付状态
                        "status": _convert_yipay_status(platform_order.get("status", 0)),
                        "synced_from_platform": True,                                 # 标记：从平台同步
                        "synced_at": time.time(),                                     # 同步时间戳
                        # 同步时间（可读）
                        "synced_time": time.strftime("%Y-%m-%d %H:%M:%S"),
                        "platform_data": platform_order                               # 保存完整的平台数据
                    }

                    # 修复退款状态判断逻辑
                    # 如果平台状态是退款(status=2)，需要根据退款金额判断是全额还是部分退款
                    platform_status = platform_order.get("status", 0)
                    if platform_status == 2 or platform_status == '2':
                        refundmoney = float(
                            platform_order.get("refundmoney", "0"))
                        order_amount = float(platform_order.get("money", "0"))
                        # 使用 >= 比较，而不是 ==
                        # 当退款金额 >= 订单金额时，才是全额退款
                        if refundmoney >= order_amount:
                            local_order_data["status"] = ORDER_STATUS_REFUNDED_FULL
                        else:
                            local_order_data["status"] = ORDER_STATUS_REFUNDED_PARTIAL

                    # 检查本地是否已存在该订单
                    order_file = os.path.join(
                        PAYMENT_ORDERS_DIR, f"{out_trade_no}.json")
                    is_update = os.path.exists(order_file)

                    # 记录旧订单状态（用于后续检查状态变更）
                    old_status = None

                    # 如果本地已存在，读取现有数据并合并
                    if is_update:
                        try:
                            with open(order_file, "r", encoding="utf-8") as f:
                                existing_order = json.load(f)

                            # 记录旧订单的状态
                            old_status = existing_order.get("status")

                            # 保留本地的一些字段（例如：username、notify_count等）
                            if "username" in existing_order and existing_order["username"] != "未知":
                                local_order_data["username"] = existing_order["username"]
                            if "notify_count" in existing_order:
                                local_order_data["notify_count"] = existing_order["notify_count"]
                            if "refund_count" in existing_order:
                                local_order_data["refund_count"] = existing_order["refund_count"]
                            if "refund_records" in existing_order:
                                local_order_data["refund_records"] = existing_order["refund_records"]

                            # 保留overdue_accounts字段（如果存在）
                            # 这个字段包含欠费账号列表，对于后续处理很重要
                            if "overdue_accounts" in existing_order:
                                local_order_data["overdue_accounts"] = existing_order["overdue_accounts"]

                            # 更新同步标记
                            local_order_data["updated_from_platform"] = True
                            local_order_data["last_synced_at"] = time.time()
                            local_order_data["last_synced_time"] = time.strftime(
                                "%Y-%m-%d %H:%M:%S")

                        except Exception as e:
                            logging.warning(
                                f"[管理员拉取订单] 读取现有订单失败: {out_trade_no}, 错误: {str(e)}")

                    # 保存订单到本地文件（使用增量更新模式）
                    # 调用统一的订单文件保存函数
                    _save_order_file_incremental(
                        out_trade_no, local_order_data)

                    # ========== 处理订单状态变更时的overdue_accounts逻辑 ==========
                    #
                    # 检查订单状态是否从pending变为paid
                    # 如果是，且订单包含overdue_accounts字段，则需要减少对应账号的overdue_count

                    # 获取新订单状态（从平台获取的状态）
                    new_status = local_order_data.get("status", "")

                    # 判断是否状态改变：
                    # 1. 旧状态为pending或None（订单不存在）
                    # 2. 新状态为paid
                    is_status_changed = (old_status in [ORDER_STATUS_PENDING, None]) and (
                        new_status == ORDER_STATUS_PAID)

                    # 如果状态改变，且订单包含overdue_accounts字段
                    if is_status_changed and "overdue_accounts" in local_order_data:
                        # 提取欠费账号列表
                        overdue_accounts = local_order_data.get(
                            "overdue_accounts", [])

                        # 验证overdue_accounts是否为有效的列表
                        if overdue_accounts and isinstance(overdue_accounts, list):
                            logging.info(
                                f"[订单状态变更] 订单 {out_trade_no} 状态从 {old_status} 变为 {new_status}，"
                                f"开始处理overdue_accounts"
                            )
                            auth_username = local_order_data["username"]

                            _process_overdue_payment_async(
                                overdue_accounts, auth_username, out_trade_no)

                    # 统计成功
                    saved_count += 1

                    # 添加到订单摘要列表
                    order_summaries.append({
                        "order_id": out_trade_no,
                        "trade_no": local_order_data.get("trade_no", ""),
                        "amount": local_order_data.get("amount", "0"),
                        "status": local_order_data.get("status", ""),
                        "action": "更新" if is_update else "新增"
                    })

                    logging.debug(
                        f"[管理员拉取订单] 订单已保存: {out_trade_no} ({'更新' if is_update else '新增'})")

                except Exception as e:
                    # 保存单个订单失败，记录错误但继续处理其他订单
                    failed_count += 1
                    logging.error(f"[管理员拉取订单] 保存订单失败: {str(e)}")
                    continue

            # ========== 第4步：记录同步日志 ==========

            _write_payment_log(
                user_id=g.user,
                order_id="batch_fetch",
                action="fetch_orders_from_platform",
                log_data={
                    "offset": offset,
                    "limit": limit,
                    "fetched": len(platform_orders),
                    "saved": saved_count,
                    "failed": failed_count,
                    "success": True
                }
            )

            # 记录汇总日志
            logging.info(
                f"[管理员拉取订单] 同步完成 - "
                f"拉取: {len(platform_orders)}, 保存: {saved_count}, 失败: {failed_count}"
            )

            # ========== 第5步：返回同步结果 ==========

            return jsonify({
                "success": True,
                "fetched": len(platform_orders),      # 拉取的订单数
                "saved": saved_count,                 # 成功保存的订单数
                "failed": failed_count,               # 保存失败的订单数
                "orders": order_summaries,            # 订单简要信息列表
                "message": f"成功同步 {saved_count} 个订单"
            })

        except Exception as e:
            # 捕获所有异常
            logging.error(f"[管理员拉取订单] 处理失败: {str(e)}")
            logging.error(traceback.format_exc())
            return jsonify({
                "success": False,
                "message": f"拉取失败：{str(e)}"
            }), 500

    # ==============================================================================
    # 欠费检查接口
    # ==============================================================================

    @app.route("/api/check_overdue", methods=["POST"])
    @login_required
    def check_overdue():
        """
        检查学校账号是否有欠费
        """
        try:
            # ========== 步骤1：检查付费控制配置 ==========
            # 从配置文件中读取付费相关配置
            # 如果系统运行在免费模式下，直接返回无欠费状态，无需继续检查
            config = configparser.ConfigParser()
            config.read("config.ini", encoding="utf-8")
            # 读取 require_payment 配置项，默认值为 true（需要付费）
            require_payment = config.getboolean(
                "Payment_Settings", "require_payment", fallback=True)
            # 读取 single_run_cost 配置项，默认值为 1.0元
            single_run_cost = config.getfloat(
                "Payment_Settings", "single_run_cost", fallback=1.0)

            # 判断是否为免费模式
            # 满足以下任一条件时，系统运行在免费模式下：
            # 1. require_payment 为 false（明确配置为免费模式）
            # 2. single_run_cost <= 0（价格为0或负数，等同于免费）
            if not require_payment or single_run_cost <= 0:
                # 免费模式下，不存在欠费概念，直接返回无欠费
                return jsonify({
                    "success": True,
                    "has_overdue": False,
                    "message": "当前系统运行在免费模式，所有用户均可无限次使用",
                    "overdue_accounts": []
                })

            # ========== 步骤2：检查学校账号欠费情况 ==========
            # 从请求体中获取参数
            data = request.get_json() or {}
            logging.info(f"[欠费检查] 请求数据: {data}")

            # 可选参数：要检查的特定学校账号用户名（支持字符串或数组）
            logging.info(f"[欠费检查] 得到的请求数据: {data}")
            school_username_input_before1 = data.get("school_username")
            school_username_input_before2 = data.get("school_usernames")
            logging.info(
                f"[欠费检查] 得到的 school_username 参数: {school_username_input_before1}")
            logging.info(
                f"[欠费检查] 得到的 school_usernames 参数: {school_username_input_before2}")

            # 统一处理输入，确保最终是列表
            def normalize_input(input_val):
                if input_val is None:
                    return []
                if isinstance(input_val, list):
                    return [str(u).strip() for u in input_val if u and str(u).strip()]
                if isinstance(input_val, str):
                    input_str = input_val.strip()
                    if input_str in ['null', 'None', 'undefined', 'NULL', '']:
                        return []
                    # 尝试按逗号分隔，支持 "a,b,c" 格式
                    return [s.strip() for s in input_str.split(',') if s.strip()]
                # 其他类型（如数字）直接转为字符串
                return [str(input_val).strip()]

            # 获取输入
            school_username_input = None
            if school_username_input_before1:
                school_username_input = normalize_input(
                    school_username_input_before1)
            elif school_username_input_before2:
                school_username_input = normalize_input(
                    school_username_input_before2)

            # 处理筛选逻辑：将输入统一转换为集合（若未指定则为空集合，表示不过滤）
            target_usernames = set(school_username_input) if school_username_input is not None else set()

            # 获取当前认证用户名
            auth_username = g.user

            if auth_system.get_user_group(auth_username) not in ['admin', 'super_admin']:
                user_school_accounts = g.api_instance._load_user_school_accounts(
                    g.user)
                missing_school_acount = [
                    u for u in (school_username_input or []) if u not in user_school_accounts]
                if missing_school_acount:
                    return jsonify({
                        "success": False,
                        "message": f"以下学校账号不存在或不属于当前用户：{', '.join(missing_school_acount)}"
                    }), 404

            # 获取该认证用户的所有学校账号配置
            # 返回格式：{school_username: {"password": "xxx", "ua": "xxx", "overdue_count": 0}, ...}
            school_accounts = g.api_instance._load_user_school_accounts(
                auth_username)

            # 如果没有学校账号，直接返回无欠费
            if not school_accounts:
                return jsonify({
                    "success": True,
                    "has_overdue": False,
                    "overdue_accounts": []
                })

            # 存储欠费账号的列表
            overdue_accounts = []

            # 遍历所有学校账号，检查欠费情况
            for acc_username, account_info in school_accounts.items():
                # 如果指定了目标账号（集合非空），且当前账号不在集合中，则跳过
                if target_usernames and acc_username not in target_usernames:
                    continue

                # 兼容旧格式：如果 account_info 是字符串（密码），跳过

                if isinstance(account_info, str):
                    continue

                # 获取欠费次数，默认为 0
                overdue_count = account_info.get("overdue_count", 0)

                # 如果欠费次数大于 0，记录该账号
                if overdue_count > 0:
                    # 尝试从备份文件中读取账号的真实姓名
                    # 备份文件路径：school_accounts/{acc_username}/{acc_username}_backup.json
                    name = None
                    try:
                        # 构造备份文件路径
                        backup_dir = os.path.join(
                            SCHOOL_ACCOUNTS_DIR, acc_username)
                        backup_file = os.path.join(
                            backup_dir, f"{acc_username}_backup.json")

                        # 如果备份文件存在，读取姓名
                        if os.path.exists(backup_file):
                            with open(backup_file, "r", encoding="utf-8") as f:
                                backup_data = json.load(f)
                                # 从 userInfo 中获取姓名
                                user_info = backup_data.get("userInfo", {})
                                name = user_info.get("name")
                    except Exception as e:
                        # 读取备份文件失败，记录警告但不影响主流程
                        logging.warning(
                            f"[欠费检查] 读取账号 {acc_username} 的备份文件失败: {e}"
                        )

                    # 将欠费账号信息添加到列表
                    overdue_accounts.append({
                        "username": acc_username,
                        "overdue_count": overdue_count,
                        "name": name or acc_username  # 如果没有姓名，使用用户名
                    })

            # 返回检查结果
            return jsonify({
                "success": True,
                "has_overdue": len(overdue_accounts) > 0,  # 是否存在欠费
                "overdue_accounts": overdue_accounts
            })

        except Exception as e:
            # 捕获所有异常，记录日志并返回错误
            logging.error(f"[欠费检查] 检查欠费状态失败: {e}", exc_info=True)
            return jsonify({
                "success": False,
                "message": f"检查欠费状态失败：{str(e)}"
            }), 500

    @app.route("/api/school_account/stats", methods=["POST"])
    @login_required
    def get_school_account_stats():
        """
        获取指定学校账号的统计信息（欠费信息）
        读取 school_accounts/{school_account}.ini 的 [stats] 节
        """
        try:
            # 获取请求参数
            data = request.get_json() or {}
            school_username = data.get("school_username", "").strip()

            if not school_username:
                return jsonify({"success": False, "message": "缺少 school_username 参数"}), 400

            # 获取当前登录用户
            auth_username = g.user

            # 验证该学校账号是否属于当前用户
            # 使用 g.api_instance._load_user_school_accounts 加载用户的所有学校账号
            school_accounts = g.api_instance._load_user_school_accounts(
                auth_username)

            if school_username not in school_accounts and auth_system.get_user_group(auth_username) not in ['admin', 'super_admin']:
                return jsonify({"success": False, "message": "账号不存在或不属于当前用户"}), 404

            # 读取统计信息 (使用现有的辅助函数读取ini中的stats节)
            # 返回格式: {"overdue_count": int, "completed_count": int}
            stats = g.api_instance._load_school_account_stats_from_ini(
                school_username)

            return jsonify({
                "success": True,
                "data": stats
            })

        except Exception as e:
            logging.error(f"[获取统计] 获取账号统计信息失败: {e}", exc_info=True)
            return jsonify({"success": False, "message": f"获取失败: {str(e)}"}), 500

