    @app.route("/api/admin/clear_overdue", methods=["POST"])
    @login_required
    @admin_required
    def admin_clear_overdue():
        """
        管理员清除/修改/添加学校账号欠费次数

        功能说明：
        此接口允许管理员直接修改指定用户的指定学校账号的欠费次数。
        支持两种模式：覆盖模式（直接设置为指定值）和叠加模式（在现有次数上累加）。
        主要用于帮助用户结清欠费、纠正错误的欠费记录，或手动添加欠费记录。

        权限要求：管理员（admin或super_admin）
        请求方法：POST

        请求参数（JSON格式）：
        {
            "auth_username": "user123",        // 用户名（账号所属用户，可为空）
            "school_username": "2021001",      // 学校账号用户名（必填）
            "new_overdue_count": 0,            // 欠费次数
            "add_mode": false                  // 叠加模式（true=累加，false=覆盖，默认false）
        }

        返回数据（JSON格式）：
        成功时：
        {
            "success": true,
            "message": "欠费次数已更新为 X"
        }

        失败时：
        {
            "success": false,
            "message": "错误信息描述"
        }

        使用场景：
        1. 用户完成线下支付后，管理员手动清零欠费（add_mode=false, new_overdue_count=0）
        2. 系统误判导致欠费次数错误，管理员纠正数据（add_mode=false）
        3. 管理员手动添加欠费次数（add_mode=true，叠加到已有次数上）

        安全机制：
        1. 必须有管理员权限（@admin_required装饰器）
        2. 参数验证：学校账号不能为空
        3. 参数验证：覆盖模式下欠费次数必须是非负整数；叠加模式下必须大于0
        4. 记录详细的管理员操作日志，便于审计追溯
        """
        try:
            # ========== 步骤1：获取并验证请求参数 ==========

            # 从请求体中获取JSON数据
            # 如果请求体为空或不是JSON格式，使用空字典作为默认值
            data = request.get_json() or {}

            # 从请求数据中提取参数，并去除首尾空白字符
            # auth_username: 目标用户的用户名（认证系统中的用户）

            auth_username = str(data.get("auth_username", "")).strip()

            # school_username: 要操作的学校账号用户名
            school_username = str(data.get("school_username", "")).strip()

            # new_overdue_count: 新的欠费次数，默认为0（清零）
            new_overdue_count = data.get("new_overdue_count", 0)

            # add_mode: 叠加模式。True 表示将 new_overdue_count 累加到现有欠费次数；
            # False（默认）表示直接覆盖为 new_overdue_count。
            add_mode = bool(data.get("add_mode", False))

            # ========== 步骤2：基本参数验证 ==========

            # 验证学校账号不能为空（这是必须的）
            if not school_username:
                return jsonify({
                    "success": False,
                    "message": "学校账号不能为空"
                }), 400

            # 如果auth_username为空，尝试自动查找
            # 这种情况通常发生在管理员只知道school_username的情况下

            # ========== 步骤3：验证欠费次数参数 ==========
            try:
                new_overdue_count = int(new_overdue_count)
                # 叠加模式要求次数大于0；覆盖模式允许0（用于清零）
                if add_mode and new_overdue_count < 1:
                    return jsonify({"success": False, "message": "添加的欠费次数必须大于0"}), 400
                elif not add_mode and new_overdue_count < 0:
                    return jsonify({"success": False, "message": "欠费次数不能为负数"}), 400
            except (ValueError, TypeError):
                # 如果转换失败，返回400错误
                return jsonify({"success": False, "message": "欠费次数必须是整数"}), 400

            # ========== 步骤4：直接修改INI文件 (不查找用户) ==========
            try:
                # 构造INI文件路径 (全局变量 SCHOOL_ACCOUNTS_DIR 指向 school_accounts 目录)
                ini_file = os.path.join(
                    SCHOOL_ACCOUNTS_DIR, f"{school_username}.ini")

                # 检查文件是否存在
                if not os.path.exists(ini_file):
                    return jsonify({
                        "success": False,
                        "message": f"学校账号配置文件不存在: {school_username}"
                    }), 404

                # 读取配置文件
                config = configparser.RawConfigParser()
                config.optionxform = str
                config.read(ini_file, encoding='utf-8')

                # 确保 [stats] 节存在
                if not config.has_section('stats'):
                    config.add_section('stats')

                # 计算最终欠费次数：叠加模式则累加，否则直接覆盖
                if add_mode:
                    current_overdue = config.getint('stats', 'overdue_count', fallback=0)
                    final_overdue_count = current_overdue + new_overdue_count
                else:
                    final_overdue_count = new_overdue_count

                # 更新欠费次数
                config.set('stats', 'overdue_count', str(final_overdue_count))

                # 保存文件
                with open(ini_file, 'w', encoding='utf-8') as f:
                    config.write(f)

                # 获取当前登录管理员（用于日志）
                admin_username = g.user if hasattr(g, 'user') else "unknown"
                # 兼容处理 g.user 可能是字典的情况
                if isinstance(admin_username, dict):
                    admin_username = admin_username.get(
                        "auth_username", "unknown")

                if add_mode:
                    logging.info(
                        f"[管理员操作] {admin_username} 手动添加欠费（叠加模式）- "
                        f"学校账号: {school_username}, 增加: {new_overdue_count}, "
                        f"最终欠费次数: {final_overdue_count}"
                    )
                else:
                    logging.info(
                        f"[管理员操作] {admin_username} 已直接修改INI文件 - "
                        f"学校账号: {school_username}, 新欠费次数: {final_overdue_count}"
                    )

                _write_payment_log(
                    user_id=admin_username,
                    order_id="",
                    action="admin_clear_overdue",
                    log_data={
                        "target_user": auth_username,
                        "school_username": school_username,
                        "new_overdue_count": final_overdue_count,
                        "add_mode": add_mode
                    }
                )

                return jsonify({
                    "success": True,
                    "message": f"已将学校账号 {school_username} 的欠费次数更新为 {final_overdue_count}"
                })

            except Exception as e:
                logging.error(f"[管理员操作] 修改INI文件失败: {str(e)}", exc_info=True)
                return jsonify({
                    "success": False,
                    "message": f"操作失败: {str(e)}"
                }), 500

        except Exception as e:
            # ========== 异常处理 ==========

            # 捕获所有未预期的异常
            # 记录ERROR级别日志，包含异常信息
            logging.error(f"[管理员操作] 清除欠费异常: {str(e)}")

            # 记录完整的异常堆栈信息，便于调试
            logging.error(traceback.format_exc())

            # 返回500错误，告知前端服务器内部错误
            return jsonify({
                "success": False,
                "message": f"操作失败: {str(e)}"
            }), 500

    # ==============================================================================

    @app.route("/api/config/pricing", methods=["GET"])
    @login_required
    def get_pricing_config():
        """
        获取付费相关配置

        功能说明：
        - 返回系统的付费相关配置信息
        - 包括是否需要付费、单次跑步费用、界面显示配置等
        - 前端用于显示价格信息和管理付费相关功能
        - 普通用户可以读取配置，但只有管理员可以修改

        请求方法：GET
        权限要求：需要登录（login_required装饰器）

        查询参数：无

        返回数据（JSON格式）：
        {
            "success": true,
            "config": {
                "require_payment": true,                      // 是否需要付费
                "single_run_cost": 1.0,                       // 单次跑步任务费用（元）
                "show_available_runs": true,                  // 是否在个人资料页显示剩余次数
                "available_runs_format": "剩余免费次数：{available_runs} 次",  // 剩余次数显示格式
                "show_available_runs_on_register": true,      // 是否在注册页显示免费次数提示
                "register_available_runs_hint": "注册即可得 {available_runs} 次校园跑"  // 注册页提示文本
            }
        }

        使用场景：
        - 前端初始化：加载配置以决定是否显示付费相关功能
        - 价格展示：在前端页面显示当前的收费标准
        - 管理后台：为管理员提供当前配置的查看和编辑界面

        注意事项：
        - 如果配置文件中不存在某项配置，使用默认值
        - 配置修改需要调用其他接口（如 /api/admin/config/save）
        """
        try:
            # ========== 步骤1：读取配置文件 ==========
            # 使用 _get_config() 函数获取配置对象
            # 该函数会自动处理配置文件不存在的情况，返回默认配置
            config = configparser.ConfigParser()
            config.read("config.ini", encoding="utf-8")

            # ========== 步骤2：提取付费相关配置项 ==========
            # 使用 fallback 参数指定默认值，确保即使配置文件中缺少某项也能正常返回

            # 是否需要付费（布尔值）
            # true: 启用付费模式，用户需要支付才能使用
            # false: 免费模式，所有用户可无限次使用
            require_payment = config.getboolean(
                "Payment_Settings", "require_payment", fallback=True)

            # 单次跑步任务费用（浮点数，单位：元）
            # 用于计算用户欠费金额 = 欠费次数 × single_run_cost
            # 设置为0或负数时，相当于关闭付费功能
            single_run_cost = config.getfloat(
                "Payment_Settings", "single_run_cost", fallback=1.0)

            # 是否在个人资料页面显示剩余免费次数（布尔值）
            # true: 显示 available_runs 字段
            # false: 不显示该字段
            show_available_runs = config.getboolean(
                "Profile_Display", "show_available_runs", fallback=True)

            # 剩余免费次数的显示格式（字符串模板）
            # {available_runs} 会被替换为实际的剩余次数数值
            # 例如："剩余免费次数：5 次"
            available_runs_format = config.get(
                "Profile_Display",
                "available_runs_format",
                fallback="剩余免费次数：{available_runs} 次"
            )

            # 是否在注册页面显示免费次数提示（布尔值）
            # true: 在注册表单中显示初始免费次数的提示信息
            # false: 不显示提示信息
            show_available_runs_on_register = config.getboolean(
                "Registration_Display",
                "show_available_runs_on_register",
                fallback=True
            )

            # 注册页面的免费次数提示文本（字符串模板）
            # {available_runs} 会被替换为新用户注册时获得的初始免费次数
            # 例如："注册即可得 10 次校园跑"
            register_available_runs_hint = config.get(
                "Registration_Display",
                "register_available_runs_hint",
                fallback="注册即可得 {available_runs} 次校园跑"
            )

            # ========== 步骤3：构造返回数据 ==========
            # 将所有配置项打包成一个字典，返回给前端
            return jsonify({
                "success": True,
                "config": {
                    "require_payment": require_payment,
                    "single_run_cost": single_run_cost,
                    "show_available_runs": show_available_runs,
                    "available_runs_format": available_runs_format,
                    "show_available_runs_on_register": show_available_runs_on_register,
                    "register_available_runs_hint": register_available_runs_hint
                }
            })

        except Exception as e:
            # ========== 异常处理 ==========
            # 捕获所有可能的异常（如配置文件损坏、类型转换错误等）
            # 记录详细的错误日志，包含完整的异常堆栈信息
            logging.error(f"[配置读取] 获取付费配置失败: {e}", exc_info=True)

            # 返回错误响应给前端
            # HTTP 状态码 500 表示服务器内部错误
            return jsonify({
                "success": False,
                "message": f"获取配置失败：{str(e)}"
            }), 500

    @app.route("/api/admin/overdue-accounts", methods=["GET"])
    @login_required  # 只需要登录即可，细粒度权限在函数内部检查
    def admin_get_overdue_accounts():
        """
        获取所有有欠费的学校账号列表（仅管理员可访问）
        """
        try:
            # ========== 权限检查：确认当前用户具有用户管理权限 ==========
            current_user = g.user
            # 细粒度权限检查：需要 'manage_users' 权限
            # manage_users 权限允许查看欠费账号列表
            # 欠费信息涉及用户的财务状况，需要严格的权限控制
            if not auth_system.check_permission(current_user, "manage_users"):
                return jsonify({
                    "success": False,
                    "message": "权限不足，需要用户管理权限（manage_users）"
                }), 403

            # ========== 初始化欠费账号列表 ==========
            # 用于存储所有找到的欠费账号信息
            overdue_accounts = []

            # ========== 获取所有系统用户列表 ==========
            # 遍历所有用户，检查他们的学校账号是否有欠费
            # 从权限配置中获取所有用户
            user_groups = auth_system.permissions.get("user_groups", {})
            all_usernames = set(user_groups.keys())
            # 添加超级管理员账号（超级管理员可能不在 user_groups 中）
            super_admin = auth_system.config.get(
                "Admin", "super_admin", fallback="admin")
            all_usernames.add(super_admin)

            # ========== 遍历所有用户，查找欠费账号 ==========
            for auth_username in all_usernames:
                try:
                    # 读取该用户的所有学校账号配置
                    # 文件路径：school_accounts/{auth_username}.json
                    # 返回格式：{school_username: {"password": "xxx", "ua": "xxx", "overdue_count": 0}, ...}
                    # [修正] 使用 g.api_instance 替代 background_task_manager
                    # Api 类包含 _load_user_school_accounts 方法，可以正确处理 INI 文件中的统计数据
                    school_accounts = g.api_instance._load_user_school_accounts(
                        auth_username)

                    # 遍历该用户的所有学校账号
                    for school_username, account_info in school_accounts.items():
                        # 兼容旧格式：如果 account_info 是字符串（密码），跳过
                        if isinstance(account_info, str):
                            continue

                        # 获取欠费次数，默认为 0
                        overdue_count = account_info.get('overdue_count', 0)

                        # 只处理有欠费的账号（overdue_count > 0）
                        if overdue_count > 0:
                            # ========== 从备份文件中读取账号详细信息 ==========
                            # 备份文件路径：school_accounts/{school_username}_backup.json
                            # [修正] 使用 g.api_instance.user_dir 替代 background_task_manager.user_dir
                            backup_file = os.path.join(
                                g.api_instance.user_dir, f"{school_username}_backup.json"
                            )

                            # 初始化默认值
                            name = "未知"  # 如果读取失败，显示"未知"
                            student_id = school_username  # 默认使用学校用户名作为学号
                            has_backup = False  # 标记是否存在备份文件

                            # 尝试读取备份文件
                            if os.path.exists(backup_file):
                                try:
                                    # 打开并解析 JSON 备份文件
                                    with open(backup_file, 'r', encoding='utf-8') as f:
                                        backup_data = json.load(f)

                                    # 从 userInfo 字段中提取信息
                                    user_info = backup_data.get('userInfo', {})
                                    name = user_info.get('name', '未知')  # 姓名
                                    student_id = user_info.get(
                                        'account', school_username)  # 学号
                                    has_backup = True  # 标记备份文件存在
                                except Exception as e:
                                    # 备份文件读取失败，使用默认值
                                    logging.warning(
                                        f"[欠费查询] 读取备份文件失败 {backup_file}: {e}"
                                    )

                            # 判断该 auth_username 是否为管理员（具有 auto_fill_password 权限）
                            is_admin = auth_system.check_permission(
                                auth_username, "auto_fill_password"
                            )

                            # ========== 将欠费账号信息添加到结果列表 ==========
                            overdue_accounts.append({
                                "auth_username": auth_username,  # 认证系统用户名
                                "school_username": school_username,  # 学校账号用户名
                                "overdue_count": overdue_count,  # 欠费次数
                                "name": name,  # 姓名
                                "student_id": student_id,  # 学号
                                "has_backup": has_backup,  # 是否有备份文件
                                "is_admin": is_admin  # 是否为管理员账号
                            })

                except Exception as e:
                    # 某个用户的账号读取失败，记录警告并继续处理其他用户
                    logging.warning(
                        f"[欠费查询] 读取用户 {auth_username} 的学校账号失败: {e}"
                    )
                    continue

            # ========== 按欠费次数从高到低排序 ==========
            # 欠费次数越多，排在越前面
            overdue_accounts.sort(
                key=lambda x: x['overdue_count'], reverse=True)

            # ========== 返回结果 ==========
            return jsonify({
                "success": True,
                "accounts": overdue_accounts,  # 欠费账号列表
                "total": len(overdue_accounts)  # 欠费账号总数
            })

        except Exception as e:
            # ========== 异常处理 ==========
            # 记录详细的错误日志，包括堆栈信息
            logging.error(f"[欠费查询] 获取欠费账号失败: {e}", exc_info=True)
            # 返回错误响应
            return jsonify({
                "success": False,
                "message": "获取欠费账号失败"
            }), 500

